-- V12: Seed ID translations juz11_15

INSERT INTO mst_translation (ayah_id, language_id, translator_name, text,
                             created_at, updated_at)
VALUES
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 93), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya jalan (untuk menyalahkan) hanyalah terhadap orang-orang yang meminta izin kepadamu, padahal mereka itu orang-orang kaya. Mereka rela berada bersama orang-orang yang tidak ikut berperang dan Allah telah mengunci mati hati mereka, maka mereka tidak mengetahui (akibat perbuatan mereka).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 94), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mereka (orang-orang munafik) mengemukakan ''uzurnya kepadamu, apabila kamu telah kembali kepada mereka (dari medan perang). Katakanlah: "Janganlah kamu mengemukakan ''uzur; kami tidak percaya lagi kepadamu, (karena) sesungguhnya Allah telah memberitahukan kepada kami beritamu yang sebenarnya. Dan Allah serta Rasul-Nya akan melihat pekerjaanmu, kemudian kamu dikembalikan kepada Yang mengetahui yang ghaib dan yang nyata, lalu Dia memberitahukan kepadamu apa yang telah kamu kerjakan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 95), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Kelak mereka akan bersumpah kepadamu dengan nama Allah, apabila kamu kembali kepada mereka, supaya kamu berpaling dari mereka. Maka berpalinglah dari mereka; karena sesungguhnya mereka itu adalah najis dan tempat mereka jahannam; sebagai balasan atas apa yang telah mereka kerjakan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 96), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mereka akan bersumpah kepadamu, agar kamu ridha kepada mereka. Tetapi jika sekiranya kamu ridha kepada mereka, sesungguhnya Allah tidak ridha kepada orang-orang yang fasik itu.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 97), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Orang-orang Arab Badwi itu, lebih sangat kekafiran dan kemunafikannya, dan lebih wajar tidak mengetahui hukum-hukum yang diturunkan Allah kepada Rasul-Nya. Dan Allah Maha mengetahui lagi Maha Bijaksana.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 98), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Di antara orang-orang Arab Badwi itu ada orang yang memandang apa yang dinafkahkannya (di jalan Allah), sebagi suatu kerugian, dan dia menanti-nanti marabahaya menimpamu, merekalah yang akan ditimpa marabahaya. Dan Allah Maha Mendengar lagi Maha Mengetahui.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 99), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Di antara orang-orang Arab Badwi itu ada orang yang beriman kepada Allah dan hari kemudian, dan memandang apa yang dinafkahkannya (di jalan Allah) itu, sebagai jalan untuk mendekatkannya kepada Allah dan sebagai jalan untuk memperoleh doa Rasul. Ketahuilah, sesungguhnya nafkah itu adalah suatu jalan bagi mereka untuk mendekatkan diri (kepada Allah). Kelak Allah akan memasukan mereka kedalam rahmat (surga)Nya; Sesungguhnya Allah Maha Pengampun lagi Maha Penyayang.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 100), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Orang-orang yang terdahulu lagi yang pertama-tama (masuk Islam) dari golongan muhajirin dan anshar dan orang-orang yang mengikuti mereka dengan baik, Allah ridha kepada mereka dan merekapun ridha kepada Allah dan Allah menyediakan bagi mereka surga-surga yang mengalir sungai-sungai di dalamnya selama-lamanya. Mereka kekal di dalamnya. Itulah kemenangan yang besar.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 101), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Di antara orang-orang Arab Badwi yang di sekelilingmu itu, ada orang-orang munafik; dan (juga) di antara penduduk Madinah. Mereka keterlaluan dalam kemunafikannya. Kamu (Muhammad) tidak mengetahui mereka, (tetapi) Kamilah yang mengetahui mereka. Nanti mereka akan Kami siksa dua kali kemudian mereka akan dikembalikan kepada azab yang besar.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 102), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan (ada pula) orang-orang lain yang mengakui dosa-dosa mereka, mereka mencampurbaurkan pekerjaan yang baik dengan pekerjaan lain yang buruk. Mudah-mudahan Allah menerima taubat mereka. Sesungguhnya Allah Maha Pengampun lagi maha Penyayang.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 103), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Ambillah zakat dari sebagian harta mereka, dengan zakat itu kamu membersihkan dan mensucikan mereka dan mendoalah untuk mereka. Sesungguhnya doa kamu itu (menjadi) ketenteraman jiwa bagi mereka. Dan Allah Maha Mendengar lagi Maha Mengetahui.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 104), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Tidaklah mereka mengetahui, bahwasanya Allah menerima taubat dari hamba-hamba-Nya dan menerima zakat dan bahwasanya Allah Maha Penerima taubat lagi Maha Penyayang?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 105), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Katakanlah: "Bekerjalah kamu, maka Allah dan Rasul-Nya serta orang-orang mukmin akan melihat pekerjaanmu itu, dan kamu akan dikembalikan kepada (Allah) Yang Mengetahui akan yang ghaib dan yang nyata, lalu diberitakan-Nya kepada kamu apa yang telah kamu kerjakan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 106), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan ada (pula) orang-orang lain yang ditangguhkan sampai ada keputusan Allah; adakalanya Allah akan mengazab mereka dan adakalanya Allah akan menerima taubat mereka. Dan Allah Maha Mengetahui lagi Maha Bijaksana.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 107), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan (di antara orang-orang munafik itu) ada orang-orang yang mendirikan masjid untuk menimbulkan kemudharatan (pada orang-orang mukmin), untuk kekafiran dan untuk memecah belah antara orang-orang mukmin serta menunggu kedatangan orang-orang yang telah memerangi Allah dan Rasul-Nya sejak dahulu. Mereka Sesungguhnya bersumpah: "Kami tidak menghendaki selain kebaikan". Dan Allah menjadi saksi bahwa sesungguhnya mereka itu adalah pendusta (dalam sumpahnya).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 108), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Janganlah kamu bersembahyang dalam mesjid itu selama-lamanya. Sesungguhnya mesjid yang didirikan atas dasar takwa (mesjid Quba), sejak hari pertama adalah lebih patut kamu sholat di dalamnya. Di dalamnya mesjid itu ada orang-orang yang ingin membersihkan diri. Dan sesungguhnya Allah menyukai orang-orang yang bersih.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 109), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka apakah orang-orang yang mendirikan mesjidnya di atas dasar takwa kepada Allah dan keridhaan-(Nya) itu yang baik, ataukah orang-orang yang mendirikan bangunannya di tepi jurang yang runtuh, lalu bangunannya itu jatuh bersama-sama dengan dia ke dalam neraka Jahannam. Dan Allah tidak memberikan petunjuk kepada orang-orang yang zalim.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 110), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Bangunan-bangunan yang mereka dirikan itu senantiasa menjadi pangkal keraguan dalam hati mereka, kecuali bila hati mereka itu telah hancur. Dan Allah Maha Mengetahui lagi Maha Bijaksana.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 111), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya Allah telah membeli dari orang-orang mukmin diri dan harta mereka dengan memberikan surga untuk mereka. Mereka berperang pada jalan Allah; lalu mereka membunuh atau terbunuh. (Itu telah menjadi) janji yang benar dari Allah di dalam Taurat, Injil dan Al Quran. Dan siapakah yang lebih menepati janjinya (selain) daripada Allah? Maka bergembiralah dengan jual beli yang telah kamu lakukan itu, dan itulah kemenangan yang besar.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 112), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mereka itu adalah orang-orang yang bertaubat, yang beribadat, yang memuji, yang melawat, yang ruku'', yang sujud, yang menyuruh berbuat ma''ruf dan mencegah berbuat munkar dan yang memelihara hukum-hukum Allah. Dan gembirakanlah orang-orang mukmin itu.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 113), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Tiadalah sepatutnya bagi Nabi dan orang-orang yang beriman memintakan ampun (kepada Allah) bagi orang-orang musyrik, walaupun orang-orang musyrik itu adalah kaum kerabat(nya), sesudah jelas bagi mereka, bahwasanya orang-orang musyrik itu adalah penghuni neraka jahanam.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 114), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan permintaan ampun dari Ibrahim (kepada Allah) untuk bapaknya tidak lain hanyalah karena suatu janji yang telah diikrarkannya kepada bapaknya itu. Maka, tatkala jelas bagi Ibrahim bahwa bapaknya itu adalah musuh Allah, maka Ibrahim berlepas diri dari padanya. Sesungguhnya Ibrahim adalah seorang yang sangat lembut hatinya lagi penyantun.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 115), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Allah sekali-kali tidak akan menyesatkan suatu kaum, sesudah Allah memberi petunjuk kepada mereka sehingga dijelaskan-Nya kepada mereka apa yang harus mereka jauhi. Sesungguhnya Allah Maha Mengetahui segala sesuatu.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 116), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya kepunyaan Allah-lah kerajaan langit dan bumi. Dia menghidupkan dan mematikan. Dan sekali-kali tidak ada pelindung dan penolong bagimu selain Allah.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 117), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya Allah telah menerima taubat Nabi, orang-orang muhajirin dan orang-orang anshar yang mengikuti Nabi dalam masa kesulitan, setelah hati segolongan dari mereka hampir berpaling, kemudian Allah menerima taubat mereka itu. Sesungguhnya Allah Maha Pengasih lagi Maha Penyayang kepada mereka,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 118), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'dan terhadap tiga orang yang ditangguhkan (penerimaan taubat) mereka, hingga apabila bumi telah menjadi sempit bagi mereka, padahal bumi itu luas dan jiwa merekapun telah sempit (pula terasa) oleh mereka, serta mereka telah mengetahui bahwa tidak ada tempat lari dari (siksa) Allah, melainkan kepada-Nya saja. Kemudian Allah menerima taubat mereka agar mereka tetap dalam taubatnya. Sesungguhnya Allah-lah Yang maha Penerima taubat lagi Maha Penyayang.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 119), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Hai orang-orang yang beriman bertakwalah kepada Allah, dan hendaklah kamu bersama orang-orang yang benar.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 120), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Tidaklah sepatutnya bagi penduduk Madinah dan orang-orang Arab Badwi yang berdiam di sekitar mereka, tidak turut menyertai Rasulullah (berperang) dan tidak patut (pula) bagi mereka lebih mencintai diri mereka daripada mencintai diri Rasul. Yang demikian itu ialah karena mereka tidak ditimpa kehausan, kepayahan dan kelaparan pada jalan Allah, dan tidak (pula) menginjak suatu tempat yang membangkitkan amarah orang-orang kafir, dan tidak menimpakan sesuatu bencana kepada musuh, melainkan dituliskanlah bagi mereka dengan yang demikian itu suatu amal saleh. Sesungguhnya Allah tidak menyia-nyiakan pahala orang-orang yang berbuat baik,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 121), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'dan mereka tiada menafkahkan suatu nafkah yang kecil dan tidak (pula) yang besar dan tidak melintasi suatu lembah, melainkan dituliskan bagi mereka (amal saleh pula) karena Allah akan memberi balasan kepada mereka yang lebih baik dari apa yang telah mereka kerjakan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 122), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Tidak sepatutnya bagi mukminin itu pergi semuanya (ke medan perang). Mengapa tidak pergi dari tiap-tiap golongan di antara mereka beberapa orang untuk memperdalam pengetahuan mereka tentang agama dan untuk memberi peringatan kepada kaumnya apabila mereka telah kembali kepadanya, supaya mereka itu dapat menjaga dirinya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 123), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Hai orang-orang yang beriman, perangilah orang-orang kafir yang di sekitar kamu itu, dan hendaklah mereka menemui kekerasan daripadamu, dan ketahuilah, bahwasanya Allah bersama orang-orang yang bertakwa.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 124), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan apabila diturunkan suatu surat, maka di antara mereka (orang-orang munafik) ada yang berkata: "Siapakah di antara kamu yang bertambah imannya dengan (turannya) surat ini?" Adapun orang-orang yang beriman, maka surat ini menambah imannya, dan mereka merasa gembira.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 125), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan adapun orang-orang yang di dalam hati mereka ada penyakit, maka dengan surat itu bertambah kekafiran mereka, disamping kekafirannya (yang telah ada) dan mereka mati dalam keadaan kafir.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 126), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan tidaklah mereka (orang-orang munafik) memperhatikan bahwa mereka diuji sekali atau dua kali setiap tahun, dan mereka tidak (juga) bertaubat dan tidak (pula) mengambil pelajaran?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 127), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan apabila diturunkan satu surat, sebagian mereka memandang kepada yang lain (sambil berkata): "Adakah seorang dari (orang-orang muslimin) yang melihat kamu?" Sesudah itu merekapun pergi. Allah telah memalingkan hati mereka disebabkan mereka adalah kaum yang tidak mengerti.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 128), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sungguh telah datang kepadamu seorang Rasul dari kaummu sendiri, berat terasa olehnya penderitaanmu, sangat menginginkan (keimanan dan keselamatan) bagimu, amat belas kasihan lagi penyayang terhadap orang-orang mukmin.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 129), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Jika mereka berpaling (dari keimanan), maka katakanlah: "Cukuplah Allah bagiku; tidak ada Tuhan selain Dia. Hanya kepada-Nya aku bertawakkal dan Dia adalah Tuhan yang memiliki ''Arsy yang agung".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Alif laam raa. Inilah ayat-ayat Al Quran yang mengandung hikmah.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Patutkah menjadi keheranan bagi manusia bahwa Kami mewahyukan kepada seorang laki-laki di antara mereka: "Berilah peringatan kepada manusia dan gembirakanlah orang-orang beriman bahwa mereka mempunyai kedudukan yang tinggi di sisi Tuhan mereka". Orang-orang kafir berkata: "Sesungguhnya orang ini (Muhammad) benar-benar adalah tukang sihir yang nyata".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya Tuhan kamu ialah Allah Yang menciptakan langit dan bumi dalam enam masa, kemudian Dia bersemayam di atas ''Arsy untuk mengatur segala urusan. Tiada seorangpun yang akan memberi syafa''at kecuali sesudah ada izin-Nya. (Dzat) yang demikian itulah Allah, Tuhan kamu, maka sembahlah Dia. Maka apakah kamu tidak mengambil pelajaran?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Hanya kepada-Nya-lah kamu semuanya akan kembali; sebagai janji yang benar daripada Allah, sesungguhnya Allah menciptakan makhluk pada permulaannya kemudian mengulanginya (menghidupkannya) kembali (sesudah berbangkit), agar Dia memberi pembalasan kepada orang-orang yang beriman dan yang mengerjakan amal saleh dengan adil. Dan untuk orang-orang kafir disediakan minuman air yang panas dan azab yang pedih disebabkan kekafiran mereka.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dialah yang menjadikan matahari bersinar dan bulan bercahaya dan ditetapkan-Nya manzilah-manzilah (tempat-tempat) bagi perjalanan bulan itu, supaya kamu mengetahui bilangan tahun dan perhitungan (waktu). Allah tidak menciptakan yang demikian itu melainkan dengan hak. Dia menjelaskan tanda-tanda (kebesaran-Nya) kepada orang-orang yang mengetahui.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya pada pertukaran malam dan siang itu dan pada apa yang diciptakan Allah di langit dan di bumi, benar-benar terdapat tanda-tanda (kekuasaan-Nya) bagi orang-orang yang bertakwa.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya orang-orang yang tidak mengharapkan (tidak percaya akan) pertemuan dengan Kami, dan merasa puas dengan kehidupan dunia serta merasa tenteram dengan kehidupan itu dan orang-orang yang melalaikan ayat-ayat Kami,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'mereka itu tempatnya ialah neraka, disebabkan apa yang selalu mereka kerjakan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya orang-orang yang beriman dan mengerjakan amal-amal saleh, mereka diberi petunjuk oleh Tuhan mereka karena keimanannya, di bawah mereka mengalir sungai-sungai di dalam surga yang penuh kenikmatan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Do''a mereka di dalamnya ialah: "Subhanakallahumma", dan salam penghormatan mereka ialah: "Salam". Dan penutup doa mereka ialah: "Alhamdulilaahi Rabbil ''aalamin".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan kalau sekiranya Allah menyegerakan kejahatan bagi manusia seperti permintaan mereka untuk menyegerakan kebaikan, pastilah diakhiri umur mereka. Maka Kami biarkan orang-orang yang tidak mengharapkan pertemuan dengan Kami, bergelimangan di dalam kesesatan mereka.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 12), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan apabila manusia ditimpa bahaya dia berdoa kepada Kami dalam keadaan berbaring, duduk atau berdiri, tetapi setelah Kami hilangkan bahaya itu daripadanya, dia (kembali) melalui (jalannya yang sesat), seolah-olah dia tidak pernah berdoa kepada Kami untuk (menghilangkan) bahaya yang telah menimpanya. Begitulah orang-orang yang melampaui batas itu memandang baik apa yang selalu mereka kerjakan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 13), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan sesungguhnya Kami telah membinasakan umat-umat sebelum kamu, ketika mereka berbuat kezaliman, padahal rasul-rasul mereka telah datang kepada mereka dengan membawa keterangan-keterangan yang nyata, tetapi mereka sekali-kali tidak hendak beriman. Demikianlah Kami memberi pembalasan kepada orang-orang yang berbuat dosa.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 14), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Kemudian Kami jadikan kamu pengganti-pengganti (mereka) di muka bumi sesudah mereka, supaya Kami memperhatikan bagaimana kamu berbuat.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 15), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan apabila dibacakan kepada mereka ayat-ayat Kami yang nyata, orang-orang yang tidak mengharapkan pertemuan dengan Kami berkata: "Datangkanlah Al Quran yang lain dari ini atau gantilah dia". Katakanlah: "Tidaklah patut bagiku menggantinya dari pihak diriku sendiri. Aku tidak mengikut kecuali apa yang diwahyukan kepadaku. Sesungguhnya aku takut jika mendurhakai Tuhanku kepada siksa hari yang besar (kiamat)".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 16), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Katakanlah: "Jikalau Allah menghendaki, niscaya aku tidak membacakannya kepadamu dan Allah tidak (pula) memberitahukannya kepadamu". Sesungguhnya aku telah tinggal bersamamu beberapa lama sebelumnya. Maka apakah kamu tidak memikirkannya?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 17), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka siapakah yang lebih zalim daripada orang yang mengada-adakan kedustaan terhadap Allah atau mendustakan ayat-ayat-Nya? Sesungguhnya, tiadalah beruntung orang-orang yang berbuat dosa.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 18), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan mereka menyembah selain daripada Allah apa yang tidak dapat mendatangkan kemudharatan kepada mereka dan tidak (pula) kemanfaatan, dan mereka berkata: "Mereka itu adalah pemberi syafa''at kepada kami di sisi Allah". Katakanlah: "Apakah kamu mengabarkan kepada Allah apa yang tidak diketahui-Nya baik di langit dan tidak (pula) dibumi?" Maha Suci Allah dan Maha Tinggi dan apa yang mereka mempersekutukan (itu).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 19), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Manusia dahulunya hanyalah satu umat, kemudian mereka berselisih. Kalau tidaklah karena suatu ketetapan yang telah ada dari Tuhanmu dahulu, pastilah telah diberi keputusan di antara mereka, tentang apa yang mereka perselisihkan itu.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 20), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan mereka berkata: "Mepada tidak diturunkan kepadanya (Muhammad) suatu keterangan (mukjizat) dari Tuhannya?" Maka katakanlah: "Sesungguhnya yang ghaib itu kepunyaan Allah, sebab itu tunggu (sajalah) olehmu, sesungguhnya aku bersama kamu termasuk orang-orang yang manunggu.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 21), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan apabila Kami merasakan kepada manusia suatu rahmat, sesudah (datangnya) bahaya menimpa mereka, tiba-tiba mereka mempunyai tipu daya dalam (menentang) tanda-tanda kekuasaan Kami. Katakanlah: "Allah lebih cepat pembalasannya (atas tipu daya itu)". Sesungguhnya malaikat-malaikat Kami menuliskan tipu dayamu.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 22), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dialah Tuhan yang menjadikan kamu dapat berjalan di daratan, (berlayar) di lautan. Sehingga apabila kamu berada di dalam bahtera, dan meluncurlah bahtera itu membawa orang-orang yang ada di dalamnya dengan tiupan angin yang baik, dan mereka bergembira karenanya, datanglah angin badai, dan (apabila) gelombang dari segenap penjuru menimpanya, dan mereka yakin bahwa mereka telah terkepung (bahaya), maka mereka berdoa kepada Allah dengan mengikhlaskan ketaatan kepada-Nya semata-mata. (Mereka berkata): "Sesungguhnya jika Engkau menyelamatkan kami dari bahaya ini, pastilah kami akan termasuk orang-orang yang bersyukur".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 23), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka tatkala Allah menyelamatkan mereka, tiba-tiba mereka membuat kezaliman di muka bumi tanpa (alasan) yang benar. Hai manusia, sesungguhnya (bencana) kezalimanmu akan menimpa dirimu sendiri; (hasil kezalimanmu) itu hanyalah kenikmatan hidup duniawi, kemudian kepada Kami-lah kembalimu, lalu Kami kabarkan kepadamu apa yang telah kamu kerjakan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 24), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya perumpamaan kehidupan duniawi itu, adalah seperti air (hujan) yang Kami turunkan dan langit, lalu tumbuhlah dengan suburnya karena air itu tanam-tanaman bumi, di antaranya ada yang dimakan manusia dan binatang ternak. Hingga apabila bumi itu telah sempurna keindahannya, dan memakai (pula) perhiasannya, dan pemilik-permliknya mengira bahwa mereka pasti menguasasinya, tiba-tiba datanglah kepadanya azab Kami di waktu malam atau siang, lalu Kami jadikan (tanam-tanamannya) laksana tanam-tanaman yang sudah disabit, seakan-akan belum pernah tumbuh kemarin. Demikianlah Kami menjelaskan tanda-tanda kekuasaan (Kami) kepada orang-orang berfikir.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 25), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Allah menyeru (manusia) ke Darussalam (surga), dan menunjuki orang yang dikehendaki-Nya kepada jalan yang lurus (Islam).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 26), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Bagi orang-orang yang berbuat baik, ada pahala yang terbaik (surga) dan tambahannya. Dan muka mereka tidak ditutupi debu hitam dan tidak (pula) kehinaan. Mereka itulah penghuni surga, mereka kekal di dalamnya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 27), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan orang-orang yang mengerjakan kejahatan (mendapat) balasan yang setimpal dan mereka ditutupi kehinaan. Tidak ada bagi mereka seorang pelindungpun dari (azab) Allah, seakan-akan muka mereka ditutupi dengan kepingan-kepingan malam yang gelap gelita. Mereka itulah penghuni neraka; mereka kekal di dalamnya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 28), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '(Ingatlah) suatu hari (ketika itu). Kami mengumpulkan mereka semuanya, kemudian Kami berkata kepada orang-orang yang mempersekutukan (Tuhan): "Tetaplah kamu dan sekutu-sekutumu di tempatmu itu". Lalu Kami pisahkan mereka dan berkatalah sekutu-sekutu mereka: "Kamu sekali-kali tidak pernah menyembah kami.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 29), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan cukuplah Allah menjadi saksi antara kami dengan kamu, bahwa kami tidak tahu-menahu tentang penyembahan kamu (kepada kami).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 30), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Di tempat itu (padang Mahsyar), tiap-tiap diri merasakan pembalasan dari apa yang telah dikerjakannya dahulu dan mereka dikembalikan kepada Allah Pelindung mereka yang sebenarnya dan lenyaplah dari mereka apa yang mereka ada-adakan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 31), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Katakanlah: "Siapakah yang memberi rezeki kepadamu dari langit dan bumi, atau siapakah yang kuasa (menciptakan) pendengaran dan penglihatan, dan siapakah yang mengeluarkan yang hidup dari yang mati dan mengeluarkan yang mati dari yang hidup dan siapakah yang mengatur segala urusan?" Maka mereka akan menjawab: "Allah". Maka katakanlah "Mangapa kamu tidak bertakwa kepada-Nya)?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 32), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka (Zat yang demikian) itulah Allah Tuhan kamu yang sebenarnya; maka tidak ada sesudah kebenaran itu, melainkan kesesatan. Maka bagaimanakah kamu dipalingkan (dari kebenaran)?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 33), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Demikianlah telah tetap hukuman Tuhanmu terhadap orang-orang yang fasik, karena sesungguhnya mereka tidak beriman.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 34), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Katakanlah: "Apakah di antara sekutu-sekutumu ada yang dapat memulai penciptaan makhluk, kemudian mengulanginya (menghidupkannya) kembali?" katakanlah: "Allah-lah yang memulai penciptaan makhluk, kemudian mengulanginya (menghidupkannya) kembali; maka bagaimanakah kamu dipalingkan (kepada menyembah yang selain Allah)?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 35), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Katakanlah: "Apakah di antara sekutu-sekuturmu ada yang menunjuki kepada kebenaran?" Katakanlah "Allah-lah yang menunjuki kepada kebenaran". Maka apakah orang-orang yang menunjuki kepada kebenaran itu lebih berhak diikuti ataukah orang yang tidak dapat memberi petunjuk kecuali (bila) diberi petunjuk? Mengapa kamu (berbuat demikian)? Bagaimanakah kamu mengambil keputusan?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 36), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan kebanyakan mereka tidak mengikuti kecuali persangkaan saja. Sesungguhnya persangkaan itu tidak sedikitpun berguna untuk mencapai kebenaran. Sesungguhnya Allah Maha Mengetahui apa yang mereka kerjakan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 37), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Tidaklah mungkin Al Quran ini dibuat oleh selain Allah; akan tetapi (Al Quran itu) membenarkan kitab-kitab yang sebelumnya dan menjelaskan hukum-hukum yang telah ditetapkannya, tidak ada keraguan di dalamnya, (diturunkan) dari Tuhan semesta alam.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 38), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Atau (patutkah) mereka mengatakan "Muhammad membuat-buatnya". Katakanlah: "(Kalau benar yang kamu katakan itu), maka cobalah datangkan sebuah surat seumpamanya dan panggillah siapa-siapa yang dapat kamu panggil (untuk membuatnya) selain Allah, jika kamu orang yang benar".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 39), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Bahkan yang sebenarnya, mereka mendustakan apa yang mereka belum mengetahuinya dengan sempurna padahal belum datang kepada mereka penjelasannya. Demikianlah orang-orang yang sebelum mereka telah mendustakan (rasul). Maka perhatikanlah bagaimana akibat orang-orang yang zalim itu.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 40), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Di antara mereka ada orang-orang yang beriman kepada Al Quran, dan di antaranya ada (pula) orang-orang yang tidak beriman kepadanya. Tuhanmu lebih mengetahui tentang orang-orang yang berbuat kerusakan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 41), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Jika mereka mendustakan kamu, maka katakanlah: "Bagiku pekerjaanku dan bagimu pekerjaanmu. Kamu berlepas diri terhadap apa yang aku kerjakan dan akupun berlepas diri terhadap apa yang kamu kerjakan".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 42), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan di antara mereka ada orang yang mendengarkanmu. Apakah kamu dapat menjadikan orang-orang tuli itu mendengar walaupun mereka tidak mengerti.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 43), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan di antara mereka ada orang yang melihat kepadamu, apakah dapat kamu memberi petunjuk kepada orang-orang yang buta, walaupun mereka tidak dapat memperhatikan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 44), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya Allah tidak berbuat zalim kepada manusia sedikitpun, akan tetapi manusia itulah yang berbuat zalim kepada diri mereka sendiri.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 45), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan (ingatlah) akan hari (yang di waktu itu) Allah mengumpulkan mereka, (mereka merasa di hari itu) seakan-akan mereka tidak pernah berdiam (di dunia) hanya sesaat di siang hari, (di waktu itu) mereka saling berkenalan. Sesungguhnya rugilah orang-orang yang mendustakan pertemuan mereka dengan Allah dan mereka tidak mendapat petunjuk', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 46), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan jika Kami perlihatkan kepadamu sebahagian dari (siksa) yang Kami ancamkan kepada mereka, (tentulah kamu akan melihatnya) atau (jika) Kami wafatkan kamu (sebelum itu), maka kepada Kami jualah mereka kembali, dan Allah menjadi saksi atas apa yang mereka kerjakan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 47), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Tiap-tiap umat mempunyai rasul; maka apabila telah datang rasul mereka, diberikanlah keputusan antara mereka dengan adil dan mereka (sedikitpun) tidak dianiaya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 48), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mereka mengatakan: "Bilakah (datangnya) ancaman itu, jika memang kamu orang-orang yang benar?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 49), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Katakanlah: "Aku tidak berkuasa mendatangkan kemudharatan dan tidak (pula) kemanfaatan kepada diriku, melainkan apa yang dikehendaki Allah". Tiap-tiap umat mempunyai ajal. Apabila telah datang ajal mereka, maka mereka tidak dapat mengundurkannya barang sesaatpun dan tidak (pula) mendahulukan(nya).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 50), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Katakanlah: "Terangkan kepadaku, jika datang kepada kamu sekalian sikaaan-Nya di waktu malam atau di siang hari, apakah orang-orang yang berdosa itu meminta disegerakan juga?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 51), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Kemudian apakah setelah terjadinya (azab itu), kemudian itu kamu baru mempercayainya? Apakah sekarang (baru kamu mempercayai), padahal sebelumnya kamu selalu meminta supaya disegerakan?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 52), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Kemudian dikatakan kepada orang-orang yang zalim (musyrik) itu: "Rasakanlah olehmu siksaan yang kekal; kamu tidak diberi balasan melainkan dengan apa yang telah kamu kerjakan".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 53), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan mereka menanyakan kepadamu: "Benarkah (azab yang dijanjikan) itu? Katakanlah: "Ya, demi Tuhanku, sesungguhnya azab itu adalah benar dan kamu sekali-kali tidak bisa luput (daripadanya)".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 54), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan kalau setiap diri yang zalim (muayrik) itu mempunyai segala apa yang ada di bumi ini, tentu dia menebus dirinya dengan itu, dan mereka membunyikan penyesalannya ketika mereka telah menyaksikan azab itu. Dan telah diberi keputusan di antara mereka dengan adil, sedang mereka tidak dianiaya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 55), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Ingatlah, sesungguhnya kepunyaan Allah apa yang ada di langit dan di bumi. Ingatlah, sesungguhnya janji Allah itu benar, tetapi kebanyakan mereka tidak mengetahui(nya).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 56), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dialah yang menghidupkan dan mematikan dan hanya kepada-Nya-lah kamu dikembalikan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 57), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Hai manusia, sesungguhnya telah datang kepadamu pelajaran dari Tuhanmu dan penyembuh bagi penyakit-penyakit (yang berada) dalam dada dan petunjuk serta rahmat bagi orang-orang yang beriman.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 58), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Katakanlah: "Dengan kurnia Allah dan rahmat-Nya, hendaklah dengan itu mereka bergembira. Kurnia Allah dan rahmat-Nya itu adalah lebih baik dari apa yang mereka kumpulkan".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 59), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Katakanlah: "Terangkanlah kepadaku tentang rezeki yang diturunkan Allah kepadamu, lalu kamu jadikan sebagiannya haram dan (sebagiannya) halal". Katakanlah: "Apakah Allah telah memberikan izin kepadamu (tentang ini) atau kamu mengada-adakan saja terhadap Allah?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 60), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Apakah dugaan orang-orang yang mengada-adakan kebohongan terhadap Allah pada hari kiamat? Sesungguhnya Allah benar-benar mempunyai karunia (yang dilimpahkan) atas manusia, tetapi kebanyakan mereka tidak mensyukuri(nya).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 61), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Kamu tidak berada dalam suatu keadaan dan tidak membaca suatu ayat dari Al Quran dan kamu tidak mengerjakan suatu pekerjaan, melainkan Kami menjadi saksi atasmu di waktu kamu melakukannya. Tidak luput dari pengetahuan Tuhanmu biarpun sebesar zarrah (atom) di bumi ataupun di langit. Tidak ada yang lebih kecil dan tidak (pula) yang lebih besar dari itu, melainkan (semua tercatat) dalam kitab yang nyata (Lauh Mahfuzh).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 62), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Ingatlah, sesungguhnya wali-wali Allah itu, tidak ada kekhawatiran terhadap mereka dan tidak (pula) mereka bersedih hati.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 63), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '(Yaitu) orang-orang yang beriman dan mereka selalu bertakwa.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 64), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Bagi mereka berita gembira di dalam kehidupan di dunia dan (dalam kehidupan} di akhirat. Tidak ada perubahan bagi kalimat-kalimat (janji-janji) Allah. Yang demikian itu adalah kemenangan yang besar.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 65), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Janganlah kamu sedih oleh perkataan mereka. Sesungguhnya kekuasaan itu seluruhnya adalah kepunyaan Allah. Dialah Yang Maha Mendengar lagi Maha Mengetahui.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 66), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Ingatlah, sesungguhnya kepunyaan Allah semua yang ada di langit dan semua yang ada di bumi. Dan orang-orang yang menyeru sekutu-sekutu selain Allah, tidaklah mengikuti (suatu keyakinan). Mereka tidak mengikuti kecuali prasangka belaka, dan mereka hanyalah menduga-duga.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 67), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dialah yang menjadikan malam bagi kamu supaya kamu beristirahat padanya dan (menjadikan) siang terang benderang (supaya kamu mencari karunia Allah). Sesungguhnya pada yang demikian itu terdapat tanda-tanda (kekuasaan Allah) bagi orang-orang yang mendengar.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 68), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mereka (orang-orang Yahudi dan Nasrani) berkata: "Allah mempuyai anak". Maha Suci Allah; Dialah Yang Maha Kaya; kepunyaan-Nya apa yang ada di langit dan apa yang di bumi. Kamu tidak mempunyai hujjah tentang ini. Pantaskah kamu mengatakan terhadap Allah apa yang tidak kamu ketahui?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 69), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Katakanlah: "Sesungguhnya orang-orang yang mengada-adakan kebohongan terhadap Allah tidak beruntung".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 70), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '(Bagi mereka) kesenangan (sementara) di dunia, kemudian kepada Kami-lah mereka kembali, kemudian Kami rasakan kepada mereka siksa yang berat, disebabkan kekafiran mereka.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 71), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan bacakanIah kepada mereka berita penting tentang Nuh di waktu dia berkata kepada kaumnya: "Hai kaumku, jika terasa berat bagimu tinggal (bersamaku) dan peringatanku (kepadamu) dengan ayat-ayat Allah, maka kepada Allah-lah aku bertawakal, karena itu bulatkanlah keputusanmu dan (kumpulkanlah) sekutu-sekutumu (untuk membinasakanku). Kemudian janganlah keputusanmu itu dirahasiakan, lalu lakukanlah terhadap diriku, dan janganlah kamu memberi tangguh kepadaku.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 72), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Jika kamu berpaling (dari peringatanku), aku tidak meminta upah sedikitpun dari padamu. Upahku tidak lain hanyalah dari Allah belaka, dan aku disuruh supaya aku termasuk golongan orang-orang yang berserah diri (kepada-Nya)".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 73), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Lalu mereka mendustakan Nuh, maka Kami selamatkan dia dan orang-orang yang bersamanya di dalam bahtera, dan Kami jadikan mereka itu pemegang kekuasaan dan Kami tenggelamkan orang-orang yang mendustakan ayat-ayat Kami. Maka perhatikanlah bagaimana kesesudahan orang-orang yang diberi peringatan itu.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 74), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Kemudian sesudah Nuh, Kami utus beberapa rasul kepada kaum mereka (masing-masing), maka rasul-rasul itu datang kepada mereka dengan membawa keterangan-keterangan yang nyata, tetapi mereka tidak hendak beriman karena mereka dahulu telah (biasa) mendustakannya. Demikianlah Kami mengunci mati hati orang-orang yang melampaui batas.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 75), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Kemudian sesudah rasul-rasul itu, Kami utus Musa dan Harun kepada Fir''aun dan pemuka-pemuka kaumnya, dengan (membawa) tanda-tanda (mukjizat-mukjizat) Kami, maka mereka menyombongkan diri dan mereka adalah orang-orang yang berdosa.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 76), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan tatkala telah datang kepada mereka kebenaran dari sisi Kami, mereka berkata: "Sesungguhnya ini adalah sihir yang nyata".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 77), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Musa berkata: "Apakah kamu mengatakan terhadap kebenaran waktu ia datang kepadamu, sihirkah ini?" padahal ahli-ahli sihir itu tidaklah mendapat kemenangan".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 78), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mereka berkata: "Apakah kamu datang kepada kami untuk memalingkan kami dari apa yang kami dapati nenek moyang kami mengerjakannya, dan supaya kamu berdua mempunyai kekuasaan di muka bumi? Kami tidak akan mempercayai kamu berdua".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 79), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Fir''aun berkata (kepada pemuka kaumnya): "Datangkanlah kepadaku semua ahli-ahli sihir yang pandai!"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 80), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka tatkala ahli-ahli sihir itu datang, Musa berkata kepada mereka: "Lemparkanlah apa yang hendak kamu lemparkan".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 81), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka setelah mereka lemparkan, Musa berkata: "Apa yang kamu lakukan itu, itulah yang sihir, sesungguhnya Allah akan menampakkan ketidak benarannya" Sesungguhnya Allah tidak akan membiarkan terus berlangsungnya pekerjaan orang-yang membuat kerusakan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 82), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Allah akan mengokohkan yang benar dengan ketetapan-Nya, walaupun orang-orang yang berbuat dosa tidak menyukai(nya).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 83), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka tidak ada yang beriman kepada Musa, melainkan pemuda-pemuda dari kaumnya (Musa) dalam keadaan takut bahwa Fir''aun dan pemuka-pemuka kaumnya akan menyiksa mereka. Sesungguhnya Fir''aun itu berbuat sewenang-wenang di muka bumi. Dan sesungguhnya dia termasuk orang-orang yang melampaui batas.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 84), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Berkata Musa: "Hai kaumku, jika kamu beriman kepada Allah, maka bertawakkallah kepada-Nya saja, jika kamu benar-benar orang yang berserah diri".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 85), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Lalu mereka berkata: "Kepada Allahlah kami bertawakkal! Ya Tuhan kami; janganlah Engkau jadikan kami sasaran fitnah bagi kaum yang''zalim,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 86), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'dan selamatkanlah kami dengan rahmat Engkau dari (tipu daya) orang-orang yang kafir".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 87), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Kami wahyukan kepada Musa dan saudaranya: "Ambillah olehmu berdua beberapa buah rumah di Mesir untuk tempat tinggal bagi kaummu dan jadikanlah olehmu rumah-rumahmu itu tempat shalat dan dirikanlah olehmu sembahyang serta gembirakanlah orang-orang yang beriman".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 88), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Musa berkata: "Ya Tuhan kami, sesungguhnya Engkau telah memberi kepada Fir''aun dan pemuka-pemuka kaumnya perhiasan dan harta kekayaan dalam kehidupan dunia, ya Tuhan Kami -- akibatnya mereka menyesatkan (manusia) dari jalan Engkau. Ya Tuhan kami, binasakanlah harta benda mereka, dan kunci matilah hati mereka, maka mereka tidak beriman hingga mereka melihat siksaan yang pedih".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 89), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'AlIah berfirman: "Sesungguhnya telah diperkenankan permohonan kamu berdua, sebab itu tetaplah kamu berdua pada jalan yang lurus dan janganlah sekali-kali kamu mengikuti jalan orang-orang yang tidak mengetahui".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 90), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Kami memungkinkan Bani Israil melintasi laut, lalu mereka diikuti oleh Fir''aun dan bala tentaranya, karena hendak menganiaya dan menindas (mereka); hingga bila Fir''aun itu telah hampir tenggelam berkatalah dia: "Saya percaya bahwa tidak ada Tuhan melainkan Tuhan yang dipercayai oleh Bani Israil, dan saya termasuk orang-orang yang berserah diri (kepada Allah)".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 91), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Apakah sekarang (baru kamu percaya), padahal sesungguhnya kamu telah durhaka sejak dahulu, dan kamu termasuk orang-orang yang berbuat kerusakan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 92), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka pada hari ini Kami selamatkan badanmu supaya kamu dapat menjadi pelajaran bagi orang-orang yang datang sesudahmu dan sesungguhnya kebanyakan dari manusia lengah dari tanda-tanda kekuasaan Kami.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 93), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan sesungguhnya Kami telah menempatkan Bani Israil di ternpat kediaman yang bagus dan Kami beri mereka rezeki dari yang baik-baik. Maka mereka tidak berselisih, kecuali setelah datang kepada mereka pengetahuan (yang tersebut dalam Taurat). Sesungguhnya Tuhan kamu akan memutuskan antara mereka di hari kiamat tentang apa yang mereka perselisihkan itu.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 94), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka jika kamu (Muhammad) berada dalam keragu-raguan tentang apa yang Kami turunkan kepadamu, maka tanyakanlah kepada orang-orang yang membaca kitab sebelum kamu. Sesungguhnya telah datang kebenaran kepadamu dari Tuhanmu, sebab itu janganlah sekali-kali kamu temasuk orang-orang yang ragu-ragu.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 95), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan sekali-kali janganlah kamu termasuk orang-orang yang mendustakan ayat-ayat Allah yang menyebabkan kamu termasuk orang-orang yang rugi.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 96), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya orang-orang yang telah pasti terhadap mereka kalimat Tuhanmu, tidaklah akan beriman,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 97), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'meskipun datang kepada mereka segala macam keterangan, hingga mereka menyaksikan azab yang pedih.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 98), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan mengapa tidak ada (penduduk) suatu kota yang beriman, lalu imannya itu bermanfaat kepadanya selain kaum Yunus? Tatkala mereka (kaum Yunus itu), beriman, Kami hilangkan dari mereka azab yang menghinakan dalam kehidupan dunia, dan Kami beri kesenangan kepada mereka sampai kepada waktu yang tertentu.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 99), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan jikalau Tuhanmu menghendaki, tentulah beriman semua orang yang di muka bumi seluruhnya. Maka apakah kamu (hendak) memaksa manusia supaya mereka menjadi orang-orang yang beriman semuanya?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 100), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan tidak ada seorangpun akan beriman kecuali dengan izin Allah; dan Allah menimpakan kemurkaan kepada orang-orang yang tidak mempergunakan akalnya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 101), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Katakanlah: "Perhatikanlah apa yaag ada di langit dan di bumi. Tidaklah bermanfaat tanda kekuasaan Allah dan rasul-rasul yang memberi peringatan bagi orang-orang yang tidak beriman".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 102), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mereka tidak menunggu-nunggu kecuali (kejadian-kejadian) yang sama dengan kejadian-kejadian (yang menimpa) orang-orang yang telah terdahulu sebelum mereka. Katakanlah: "Maka tunggulah, sesungguhnya akupun termasuk orang-orang yang menunggu bersama kamu".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 103), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Kemudian Kami selamatkan rasul-rasul Kami dan orang-orang yang beriman, demikianlah menjadi kewajiban atas Kami menyelamatkan orang-orang yang beriman.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 104), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Katakanlah: "Hai manusia, jika kamu masih dalam keragu-raguan tentang agamaku, maka (ketahuilah) aku tidak menyembah yang kamu sembah selain Allah, tetapi aku menyembah Allah yang akan mematikan kamu dan aku telah diperintah supaya termasuk orang-orang yang beriman",', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 105), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'dan (aku telah diperintah): "Hadapkanlah mukamu kepada agama dengan tulus dan ikhlas dan janganlah kamu termasuk orang-orang yang musyrik.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 106), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan janganlah kamu menyembah apa-apa yang tidak memberi manfaat dan tidak (pula) memberi mudharat kepadamu selain Allah; sebab jika kamu berbuat (yang demikian), itu, maka sesungguhnya kamu kalau begitu termasuk orang-orang yang zalim".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 107), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Jika Allah menimpakan sesuatu kemudharatan kepadamu, maka tidak ada yang dapat menghilangkannya kecuali Dia. Dan jika Allah menghendaki kebaikan bagi kamu, maka tak ada yang dapat menolak kurnia-Nya. Dia memberikan kebaikan itu kepada siapa yang dikehendaki-Nya di antara hamba-hamba-Nya dan Dialah Yang Maha Pengampun lagi Maha Penyayang.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 108), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Katakanlah: "Hai manusia, sesungguhnya teIah datang kepadamu kebenaran (Al Quran) dari Tuhanmu, sebab itu barangsiapa yang mendapat petunjuk maka sesungguhnya (petunjuk itu) untuk kebaikan dirinya sendiri. Dan barangsiapa yang sesat, maka sesungguhnya kesesatannya itu mencelakakan dirinya sendiri. Dan aku bukanlah seorang penjaga terhadap dirimu".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 109), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan ikutilah apa yang diwahyukan kepadamu, dan bersabarlah hingga Allah memberi keputusan dan Dia adalah Hakim yang sebaik-baiknya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Alif laam raa, (inilah) suatu kitab yang ayat-ayatnya disusun dengan rapi serta dijelaskan secara terperinci, yang diturunkan dari sisi (Allah) Yang Maha Bijaksana lagi Maha Tahu,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'agar kamu tidak menyembah selain Allah. Sesungguhnya aku (Muhammad) adalah pemberi peringatan dan pembawa khabar gembira kepadamu daripada-Nya,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'dan hendaklah kamu meminta ampun kepada Tuhanmu dan bertaubat kepada-Nya. (Jika kamu mengerjakan yang demikian), niscaya Dia akan memberi kenikmatan yang baik (terus menerus) kepadamu sampai kepada waktu yang telah ditentukan dan Dia akan memberikan kepada tiap-tiap orang yang mempunyai keutamaan (balasan) keutamaannya. Jika kamu berpaling, maka sesungguhnya aku takut kamu akan ditimpa siksa hari kiamat.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Kepada Allah-lah kembalimu, dan Dia Maha Kuasa atas segala sesuatu.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Ingatlah, sesungguhnya (orang munafik itu) memalingkan dada mereka untuk menyembunyikan diri daripadanya (Muhammad). Ingatlah, di waktu mereka menyelimuti dirinya dengan kain, Allah mengetahui apa yang mereka sembunyikan dan apa yang mereka lahirkan, sesungguhnya Allah Maha Mengetahui segala isi hati.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan tidak ada suatu binatang melata pun di bumi melainkan Allah-lah yang memberi rezekinya, dan Dia mengetahui tempat berdiam binatang itu dan tempat penyimpanannya. Semuanya tertulis dalam Kitab yang nyata (Lauh mahfuzh).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Dialah yang menciptakan langit dan bumi dalam enam masa, dan adalah singgasana-Nya (sebelum itu) di atas air, agar Dia menguji siapakah di antara kamu yang lebih baik amalnya, dan jika kamu berkata (kepada penduduk Mekah): "Sesungguhnya kamu akan dibangkitkan sesudah mati", niscaya orang-orang yang kafir itu akan berkata: "Ini tidak lain hanyalah sihir yang nyata".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan sesungguhnya jika Kami undurkan azab dari mereka sampai kepada suatu waktu yang ditentukan. niscaya mereka akan berkata: "Apakah yang menghalanginya?" lngatlah, diwaktu azab itu datang kepada mereka tidaklah dapat dipalingkan dari mereka dan mereka diliputi oleh azab yang dahulunya mereka selalu memperolok-olokkannya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan jika Kami rasakan kepada manusia suatu rahmat (nikmat) dari Kami, kemudian rahmat itu Kami cabut daripadanya, pastilah dia menjadi putus asa lagi tidak berterima kasih.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan jika Kami rasakan kepadanya kebahagiaan sesudah bencana yang menimpanya, niscaya dia akan berkata: "Telah hilang bencana-bencana itu daripadaku"; sesungguhnya dia sangat gembira lagi bangga,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'kecuali orang-orang yang sabar (terhadap bencana), dan mengerjakan amal-amal saleh; mereka itu beroleh ampunan dan pahala yang besar.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 12), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka boleh jadi kamu hendak meninggalkan sebahagian dari apa yang diwahyukan kepadamu dan sempit karenanya dadamu, karena khawatir bahwa mereka akan mengatakan: "Mengapa tidak diturunkan kepadanya perbendaharaan (kekayaan) atau datang bersama-sama dengan dia seorang malaikat?" Sesungguhnya kamu hanyalah seorang pemberi peringatan dan Allah Pemelihara segala sesuatu.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 13), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Bahkan mereka mengatakan: "Muhammad telah membuat-buat Al Quran itu", Katakanlah: "(Kalau demikian), maka datangkanlah sepuluh surat-surat yang dibuat-buat yang menyamainya, dan panggillah orang-orang yang kamu sanggup (memanggilnya) selain Allah, jika kamu memang orang-orang yang benar".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 14), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Jika mereka yang kamu seru itu tidak menerima seruanmu (ajakanmu) itu maka ketahuilah, sesungguhnya Al Quran itu diturunkan dengan ilmu Allah, dan bahwasanya tidak ada Tuhan selain Dia, maka maukah kamu berserah diri (kepada Allah)?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 15), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Barangsiapa yang menghendaki kehidupan dunia dan perhiasannya, niscaya Kami berikan kepada mereka balasan pekerjaan mereka di dunia dengan sempurna dan mereka di dunia itu tidak akan dirugikan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 16), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Itulah orang-orang yang tidak memperoleh di akhirat, kecuali neraka dan lenyaplah di akhirat itu apa yang telah mereka usahakan di dunia dan sia-sialah apa yang telah mereka kerjakan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 17), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Apakah (orang-orang kafir itu sama dengan) orang-orang yang ada mempunyai bukti yang nyata (Al Quran) dari Tuhannya, dan diikuti pula oleh seorang saksi (Muhammad) dari Allah dan sebelum Al Quran itu telah ada Kitab Musa yang menjadi pedoman dan rahmat? Mereka itu beriman kepada Al Quran. Dan barangsiapa di antara mereka (orang-orang Quraisy) dan sekutu-sekutunya yang kafir kepada Al Quran, maka nerakalah tempat yang diancamkan baginya, karena itu janganlah kamu ragu-ragu terhadap Al Quran itu. Sesungguhnya (Al Quran) itu benar-benar dari Tuhanmu, tetapi kebanyakan manusia tidak beriman.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 18), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan siapakah yang lebih zalim daripada orang yang membuat-buat dusta terhadap Allah? Mereka itu akan dihadapkan kepada Tuhan mereka, dan para saksi akan berkata: "Orang-orang inilah yang telah berdusta terhadap Tuhan mereka". Ingatlah, kutukan Allah (ditimpakan) atas orang-orang yang zalim,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 19), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '(yaitu) orang-orang yang menghalangi (manusia) dari jalan Allah dan menghendaki (supaya) jalan itu bengkok. Dan mereka itulah orang-orang yang tidak percaya akan adanya hari akhirat.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 20), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Orang-orang itu tidak mampu menghalang-halangi Allah untuk (mengazab mereka) di bumi ini, dan sekali-kali tidak adalah bagi mereka penolong selain Allah. Siksaan itu dilipat gandakan kepada mereka. Mereka selalu tidak dapat mendengar (kebenaran) dan mereka selalu tidak dapat melihat(nya).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 21), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mereka itulah orang-orang yang merugikan dirinya sendiri, dan lenyaplah dari mereka apa yang selalu mereka ada-adakan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 22), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Pasti mereka itu di akhirat menjadi orang-orang yang paling merugi.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 23), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya orang-orang yang beriman dan mengerjakan amal-amal saleh dan merendahkan diri kepada Tuhan mereka, mereka itu adalah penghuni-penghuni surga; mereka kekal di dalamnya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 24), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Perbandingan kedua golongan itu (orang-orang kafir dan orang-orang mukmin), seperti orang buta dan tuli dengan orang yang dapat melihat dan dapat mendengar. Adakah kedua golongan itu sama keadaan dan sifatnya? Maka tidakkah kamu mengambil pelajaran (daripada perbandingan itu)?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 25), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan sesungguhnya Kami telah mengutus Nuh kepada kaumnya, (dia berkata): "Sesungguhnya aku adalah pemberi peringatan yang nyata bagi kamu,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 26), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'agar kamu tidak menyembah selain Allah. Sesungguhnya aku takut kamu akan ditimpa azab (pada) hari yang sangat menyedihkan".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 27), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka berkatalah pemimpin-pemimpin yang kafir dari kaumnya: "Kami tidak melihat kamu, melainkan (sebagai) seorang manusia (biasa) seperti kami, dan kami tidak melihat orang-orang yang mengikuti kamu, melainkan orang-orang yang hina dina di antara kami yang lekas percaya saja, dan kami tidak melihat kamu memiliki sesuatu kelebihan apapun atas kami, bahkan kami yakin bahwa kamu adalah orang-orang yang dusta".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 28), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Berkata Nuh: "Hai kaumku, bagaimana pikiranmu, jika aku ada mempunyai bukti yang nyata dari Tuhanku, dan diberinya aku rahmat dari sisi-Nya, tetapi rahmat itu disamarkan bagimu. Apa akan kami paksakankah kamu menerimanya, padahal kamu tiada menyukainya?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 29), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan (dia berkata): "Hai kaumku, aku tiada meminta harta benda kepada kamu (sebagai upah) bagi seruanku. Upahku hanyalah dari Allah dan aku sekali-kali tidak akan mengusir orang-orang yang telah beriman. Sesungguhnya mereka akan bertemu dengan Tuhannya, akan tetapi aku memandangmu suatu kaum yang tidak mengetahui".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 30), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan (dia berkata): "Hai kaumku, siapakah yang akan menolongku dari (azab) Allah jika aku mengusir mereka. Maka tidakkah kamu mengambil pelajaran?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 31), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan aku tidak mengatakan kepada kamu (bahwa): "Aku mempunyai gudang-gudang rezeki dan kekayaan dari Allah, dan aku tiada mengetahui yang ghaib", dan tidak (pula) aku mengatakan: "Bahwa sesungguhnya aku adalah malaikat", dan tidak juga aku mengatakan kepada orang-orang yang dipandang hina oleh penglihatanmu: "Sekali-kali Allah tidak akan mendatangkan kebaikan kepada mereka". Allah lebih mengetahui apa yang ada pada diri mereka; sesungguhnya aku, kalau begitu benar-benar termasuk orang-orang yang zalim.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 32), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mereka berkata "Hai Nuh, sesungguhnya kamu telah berbantah dengan kami, dan kamu telah memperpanjang bantahanmu terhadap kami, maka datangkanlah kepada kami azab yang kamu ancamkan kepada kami, jika kamu termasuk orang-orang yang benar".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 33), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Nuh menjawab: "Hanyalah Allah yang akan mendatangkan azab itu kepadamu jika Dia menghendaki, dan kamu sekali-kali tidak dapat melepaskan diri.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 34), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan tidaklah bermanfaat kepadamu nasehatku jika aku hendak memberi nasehat kepada kamu, sekiranya Allah hendak menyesatkan kamu, Dia adalah Tuhanmu, dan kepada-Nya-lah kamu dikembalikan".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 35), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Malahan kaum Nuh itu berkata: "Dia cuma membuat-buat nasihatnya saja". Katakanlah: "Jika aku membuat-buat nasihat itu, maka hanya akulah yang memikul dosaku, dan aku berlepas diri dari dosa yang kamu perbuat".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 36), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan diwahyukan kepada Nuh, bahwasanya sekali-kali tidak akan beriman di antara kaummu, kecuali orang yang telah beriman (saja), karena itu janganlah kamu bersedih hati tentang apa yang selalu mereka kerjakan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 37), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan buatlah bahtera itu dengan pengawasan dan petunjuk wahyu Kami, dan janganlah kamu bicarakan dengan Aku tentang orang-orang yang zalim itu; sesungguhnya mereka itu akan ditenggelamkan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 38), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan mulailah Nuh membuat bahtera. Dan setiap kali pemimpin kaumnya berjalan meliwati Nuh, mereka mengejeknya. Berkatalah Nuh: "Jika kamu mengejek kami, maka sesungguhnya kami (pun) mengejekmu sebagaimana kamu sekalian mengejek (kami).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 39), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Kelak kamu akan mengetahui siapa yang akan ditimpa oleh azab yang menghinakannya dan yang akan ditimpa azab yang kekal".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 40), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Hingga apabila perintah Kami datang dan dapur telah memancarkan air, Kami berfirman: "Muatkanlah ke dalam bahtera itu dari masing-masing binatang sepasang (jantan dan betina), dan keluargamu kecuali orang yang telah terdahulu ketetapan terhadapnya dan (muatkan pula) orang-orang yang beriman". Dan tidak beriman bersama dengan Nuh itu kecuali sedikit.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 41), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Nuh berkata: "Naiklah kamu sekalian ke dalamnya dengan menyebut nama Allah di waktu berlayar dan berlabuhnya". Sesungguhnya Tuhanku benar-benar Maha Pengampun lagi Maha Penyayang.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 42), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan bahtera itu berlayar membawa mereka dalam gelombang laksana gunung. Dan Nuh memanggil anaknya, sedang anak itu berada di tempat yang jauh terpencil: "Hai anakku, naiklah (ke kapal) bersama kami dan janganlah kamu berada bersama orang-orang yang kafir".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 43), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Anaknya menjawab: "Aku akan mencari perlindungan ke gunung yang dapat memeliharaku dari air bah!" Nuh berkata: "Tidak ada yang melindungi hari ini dari azab Allah selain Allah (saja) Yang Maha Penyayang". Dan gelombang menjadi penghalang antara keduanya; maka jadilah anak itu termasuk orang-orang yang ditenggelamkan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 44), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan difirmankan: "Hai bumi telanlah airmu, dan hai langit (hujan) berhentilah," dan airpun disurutkan, perintahpun diselesaikan dan bahtera itupun berlabuh di atas bukit Judi, dan dikatakan: "Binasalah orang-orang yang zalim".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 45), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Nuh berseru kepada Tuhannya sambil berkata: "Ya Tuhanku, sesungguhnya anakku termasuk keluargaku, dan sesungguhnya janji Engkau itulah yang benar. Dan Engkau adalah Hakim yang seadil-adilnya".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 46), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Allah berfirman: "Hai Nuh, sesungguhnya dia bukanlah termasuk keluargamu (yang dijanjikan akan diselamatkan), sesungguhnya (perbuatan)nya perbuatan yang tidak baik. Sebab itu janganlah kamu memohon kepada-Ku sesuatu yang kamu tidak mengetahui (hakekat)nya. Sesungguhnya Aku memperingatkan kepadamu supaya kamu jangan termasuk orang-orang yang tidak berpengetahuan".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 47), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Nuh berkata: Ya Tuhanku, sesungguhnya aku berlindung kepada Engkau dari memohon kepada Engkau sesuatu yang aku tiada mengetahui (hakekat)nya. Dan sekiranya Engkau tidak memberi ampun kepadaku, dan (tidak) menaruh belas kasihan kepadaku, niscaya aku akan termasuk orang-orang yang merugi".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 48), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Difirmankan: "Hai Nuh, turunlah dengan selamat sejahtera dan penuh keberkatan dari Kami atasmu dan atas umat-umat (yang mukmin) dari orang-orang yang bersamamu. Dan ada (pula) umat-umat yang Kami beri kesenangan pada mereka (dalam kehidupan dunia), kemudian mereka akan ditimpa azab yang pedih dari Kami".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 49), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Itu adalah di antara berita-berita penting tentang yang ghaib yang Kami wahyukan kepadamu (Muhammad); tidak pernah kamu mengetahuinya dan tidak (pula) kaummu sebelum ini. Maka bersabarlah; sesungguhnya kesudahan yang baik adalah bagi orang-orang yang bertakwa.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 50), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan kepada kaum ''Ad (Kami utus) saudara mereka, Huud. Ia berkata: "Hai kaumku, sembahlah Allah, sekali-kali tidak ada bagimu Tuhan selain Dia. Kamu hanyalah mengada-adakan saja.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 51), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Hai kaumku, aku tidak meminta upah kepadamu bagi seruanku ini. Upahku tidak lain hanyalah dari Allah yang telah menciptakanku. Maka tidakkah kamu memikirkan(nya)?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 52), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan (dia berkata): "Hai kaumku, mohonlah ampun kepada Tuhanmu lalu bertobatlah kepada-Nya, niscaya Dia menurunkan hujan yang sangat deras atasmu, dan Dia akan menambahkan kekuatan kepada kekuatanmu, dan janganlah kamu berpaling dengan berbuat dosa".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 53), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Kaum ''Ad berkata: "Hai Huud, kamu tidak mendatangkan kepada kami suatu bukti yang nyata, dan kami sekali-kali tidak akan meninggalkan sembahan-sembahan kami karena perkataanmu, dan kami sekali-kali tidak akan mempercayai kamu.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 54), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Kami tidak mengatakan melainkan bahwa sebagian sembahan kami telah menimpakan penyakit gila atas dirimu". Huud menjawab: "Sesungguhnya aku bersaksi kepada Allah dan saksikanlah olehmu sekalian bahwa sesungguhnya aku berlepas diri dari apa yang kamu persekutukan,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 55), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'dari selain-Nya, sebab itu jalankanlah tipu dayamu semuanya terhadapku dan janganlah kamu memberi tangguh kepadaku.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 56), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya aku bertawakkal kepada Allah Tuhanku dan Tuhanmu. Tidak ada suatu binatang melatapun melainkan Dialah yang memegang ubun-ubunnya. Sesungguhnya Tuhanku di atas jalan yang lurus".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 57), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Jika kamu berpaling, maka sesungguhnya aku telah menyampaikan kepadamu apa (amanat) yang aku diutus (untuk menyampaikan)nya kepadamu. Dan Tuhanku akan mengganti (kamu) dengan kaum yang lain (dari) kamu; dan kamu tidak dapat membuat mudharat kepada-Nya sedikitpun. Sesungguhnya Tuhanku adalah Maha Pemelihara segala sesuatu.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 58), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan tatkala datang azab Kami, Kami selamatkan Huud dan orang-orang yang beriman bersama dia dengan rahmat dari Kami; dan Kami selamatkan (pula) mereka (di akhirat) dari azab yang berat.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 59), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan itulah (kisah) kaum ''Ad yang mengingkari tanda-tanda kekuasaan Tuhan mereka, dan mendurhakai rasul-rasul Allah dan mereka menuruti perintah semua penguasa yang sewenang-wenang lagi menentang (kebenaran).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 60), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan mereka selalu diikuti dengan kutukan di dunia ini dan (begitu pula) di hari kiamat. Ingatlah, sesungguhnya kaum ''Ad itu kafir kepada Tuhan mereka. Ingatlah kebinasaanlah bagi kaum ''Ad (yaitu) kaum Huud itu.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 61), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan kepada Tsamud (Kami utus) saudara mereka Shaleh. Shaleh berkata: "Hai kaumku, sembahlah Allah, sekali-kali tidak ada bagimu Tuhan selain Dia. Dia telah menciptakan kamu dari bumi (tanah) dan menjadikan kamu pemakmurnya, karena itu mohonlah ampunan-Nya, kemudian bertobatlah kepada-Nya, Sesungguhnya Tuhanku amat dekat (rahmat-Nya) lagi memperkenankan (doa hamba-Nya)".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 62), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Kaum Tsamud berkata: "Hai Shaleh, sesungguhnya kamu sebelum ini adalah seorang di antara kami yang kami harapkan, apakah kamu melarang kami untuk menyembah apa yang disembah oleh bapak-bapak kami? dan sesungguhnya kami betul-betul dalam keraguan yang menggelisahkan terhadap agama yang kamu serukan kepada kami".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 63), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Shaleh berkata: "Hai kaumku, bagaimana pikiranmu jika aku mempunyai bukti yang nyata dari Tuhanku dan diberi-Nya aku rahmat (kenabian) dari-Nya, maka siapakah yang akan menolong aku dari (azab) Allah jika aku mendurhakai-Nya. Sebab itu kamu tidak menambah apapun kepadaku selain daripada kerugian.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 64), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Hai kaumku, inilah unta betina dari Allah, sebagai mukjizat (yang menunjukkan kebenaran) untukmu, sebab itu biarkanlah dia makan di bumi Allah, dan janganlah kamu mengganggunya dengan gangguan apapun yang akan menyebabkan kamu ditimpa azab yang dekat".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 65), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mereka membunuh unta itu, maka berkata Shaleh: "Bersukarialah kamu sekalian di rumahmu selama tiga hari, itu adalah janji yang tidak dapat didustakan".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 66), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka tatkala datang azab Kami, Kami selamatkan Shaleh beserta orang-orang yang beriman bersama dia dengan rahmat dari Kami dan dari kehinaan di hari itu. Sesungguhnya Tuhanmu Dia-Lah yang Maha Kuat lagi Maha Perkasa.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 67), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan satu suara keras yang mengguntur menimpa orang-orang yang zalim itu, lalu mereka mati bergelimpangan di rumahnya,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 68), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'seolah-olah mereka belum pernah berdiam di tempat itu. Ingatlah, sesungguhnya kaum Tsamud mengingkari Tuhan mereka. Ingatlah, kebinasaanlah bagi kaum Tsamud.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 69), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan sesungguhnya utusan-utusan Kami (malaikat-malaikat) telah datang kepada lbrahim dengan membawa kabar gembira, mereka mengucapkan: "Selamat". Ibrahim menjawab: "Selamatlah," maka tidak lama kemudian Ibrahim menyuguhkan daging anak sapi yang dipanggang.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 70), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka tatkala dilihatnya tangan mereka tidak menjamahnya, Ibrahim memandang aneh perbuatan mereka, dan merasa takut kepada mereka. Malaikat itu berkata: "Jangan kamu takut, sesungguhnya kami adalah (malaikat-ma]aikat) yang diutus kepada kaum Luth".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 71), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan isterinya berdiri (dibalik tirai) lalu dia tersenyum, maka Kami sampaikan kepadanya berita gembira tentang (kelahiran) Ishak dan dari Ishak (akan lahir puteranya) Ya''qub.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 72), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Isterinya berkata: "Sungguh mengherankan, apakah aku akan melahirkan anak padahal aku adalah seorang perempuan tua, dan ini suamikupun dalam keadaan yang sudah tua pula?. Sesungguhnya ini benar-benar suatu yang sangat aneh".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 73), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Para malaikat itu berkata: "Apakah kamu merasa heran tentang ketetapan Allah? (Itu adalah) rahmat Allah dan keberkatan-Nya, dicurahkan atas kamu, hai ahlulbait! Sesungguhnya Allah Maha Terpuji lagi Maha Pemurah".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 74), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka tatkala rasa takut hilang dari Ibrahim dan berita gembira telah datang kepadanya, diapun bersoal jawab dengan (malaikat-malaikat) Kami tentang kaum Luth.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 75), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya Ibrahim itu benar-benar seorang yang penyantun lagi penghiba dan suka kembali kepada Allah.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 76), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Hai Ibrahim, tinggalkanlah soal jawab ini, sesungguhnya telah datang ketetapan Tuhanmu, dan sesungguhnya mereka itu akan didatangi azab yang tidak dapat ditolak.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 77), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan tatkala datang utusan-utusan Kami (para malaikat) itu kepada Luth, dia merasa susah dan merasa sempit dadanya karena kedatangan mereka, dan dia berkata: "Ini adalah hari yang amat sulit".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 78), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan datanglah kepadanya kaumnya dengan bergegas-gegas. Dan sejak dahulu mereka selalu melakukan perbuatan-perbuatan yang keji. Luth berkata: "Hai kaumku, inilah puteri-puteriku, mereka lebih suci bagimu, maka bertakwalah kepada Allah dan janganlah kamu mencemarkan (nama)ku terhadap tamuku ini. Tidak adakah di antaramu seorang yang berakal?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 79), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mereka menjawab: "Sesungguhnya kamu telah tahu bahwa kami tidak mempunyai keinginan terhadap puteri-puterimu; dan sesungguhnya kamu tentu mengetahui apa yang sebenarnya kami kehendaki".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 80), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Luth berkata: "Seandainya aku ada mempunyai kekuatan (untuk menolakmu) atau kalau aku dapat berlindung kepada keluarga yang kuat (tentu aku lakukan)".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 81), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Para utusan (malaikat) berkata: "Hai Luth, sesungguhnya kami adalah utusan-utusan Tuhanmu, sekali-kali mereka tidak akan dapat mengganggu kamu, sebab itu pergilah dengan membawa keluarga dan pengikut-pengikut kamu di akhir malam dan janganlah ada seorangpun di antara kamu yang tertinggal, kecuali isterimu. Sesungguhnya dia akan ditimpa azab yang menimpa mereka karena sesungguhnya saat jatuhnya azab kepada mereka ialah di waktu subuh; bukankah subuh itu sudah dekat?".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 82), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka tatkala datang azab Kami, Kami jadikan negeri kaum Luth itu yang di atas ke bawah (Kami balikkan), dan Kami hujani mereka dengan batu dari tanah yang terbakar dengan bertubi-tubi,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 83), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Yang diberi tanda oleh Tuhanmu, dan siksaan itu tiadalah jauh dari orang-orang yang zalim.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 84), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan kepada (penduduk) Mad-yan (Kami utus) saudara mereka, Syu''aib. Ia berkata: "Hai kaumku, sembahlah Allah, sekali-kali tiada Tuhan bagimu selain Dia. Dan janganlah kamu kurangi takaran dan timbangan, sesungguhnya aku melihat kamu dalam keadaan yang baik (mampu) dan sesungguhnya aku khawatir terhadapmu akan azab hari yang membinasakan (kiamat)".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 85), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Syu''aib berkata: "Hai kaumku, cukupkanlah takaran dan timbangan dengan adil, dan janganlah kamu merugikan manusia terhadap hak-hak mereka dan janganlah kamu membuat kejahatan di muka bumi dengan membuat kerusakan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 86), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sisa (keuntungan) dari Allah adalah lebih baik bagimu jika kamu orang-orang yang beriman. Dan aku bukanlah seorang penjaga atas dirimu"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 87), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mereka berkata: "Hai Syu''aib, apakah sembahyangmu menyuruh kamu agar kami meninggalkan apa yang disembah oleh bapak-bapak kami atau melarang kami memperbuat apa yang kami kehendaki tentang harta kami. Sesungguhnya kamu adalah orang yang sangat penyantun lagi berakal".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 88), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Syu''aib berkata: "Hai kaumku, bagaimana pikiranmu jika aku mempunyai bukti yang nyata dari Tuhanku dan dianugerahi-Nya aku dari pada-Nya rezeki yang baik (patutkah aku menyalahi perintah-Nya)? Dan aku tidak berkehendak menyalahi kamu (dengan mengerjakan) apa yang aku larang. Aku tidak bermaksud kecuali (mendatangkan) perbaikan selama aku masih berkesanggupan. Dan tidak ada taufik bagiku melainkan dengan (pertolongan) Allah. Hanya kepada Allah aku bertawakkal dan hanya kepada-Nya-lah aku kembali.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 89), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Hai kaumku, janganlah hendaknya pertentangan antara aku (dengan kamu) menyebabkan kamu menjadi jahat hingga kamu ditimpa azab seperti yang menimpa kaum Nuh atau kaum Hud atau kaum Shaleh, sedang kaum Luth tidak (pula) jauh (tempatnya) dari kamu.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 90), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan mohonlah ampun kepada Tuhanmu kemudian bertaubatlah kepada-Nya. Sesungguhnya Tuhanku Maha Penyayang lagi Maha Pengasih.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 91), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mereka berkata: "Hai Syu''aib, kami tidak banyak mengerti tentang apa yang kamu katakan itu dan sesungguhnya kami benar-benar melihat kamu seorang yang lemah di antara kami; kalau tidaklah karena keluargamu tentulah kami telah merajam kamu, sedang kamupun bukanlah seorang yang berwibawa di sisi kami".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 92), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Syu''aib menjawab: "Hai kaumku, apakah keluargaku lebih terhormat menurut pandanganmu daripada Allah, sedang Allah kamu jadikan sesuatu yang terbuang di belakangmu?. Sesungguhnya (pengetahuan) Tuhanku meliputi apa yang kamu kerjakan".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 93), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan (dia berkata): "Hai kaumku, berbuatlah menurut kemampuanmu, sesungguhnya akupun berbuat (pula). Kelak kamu akan mengetahui siapa yang akan ditimpa azab yang menghinakannya dan siapa yang berdusta. Dan tunggulah azab (Tuhan), sesungguhnya akupun menunggu bersama kamu".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 94), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan tatkala datang azab Kami, Kami selamatkan Syu''aib dan orang-orang yang beriman bersama-sama dengan dia dengan rahmat dari Kami, dan orang-orang yang zalim dibinasakan oleh satu suara yang mengguntur, lalu jadilah mereka mati bergelimpangan di rumahnya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 95), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Seolah-olah mereka belum pernah berdiam di tempat itu. Ingatlah, kebinasaanlah bagi penduduk Mad-yan sebagaimana kaum Tsamud telah binasa.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 96), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan sesungguhnya Kami telah mengutus Musa dengan tanda-tanda (kekuasaan) Kami dan mukjizat yang nyata,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 97), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'kepada Fir''aun dan pemimpin-pemimpin kaumnya, tetapi mereka mengikut perintah Fir''aun, padahal perintah Fir''aun sekali-kali bukanlah (perintah) yang benar.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 98), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Ia berjalan di muka kaumnya di hari kiamat lalu memasukkan mereka ke dalam neraka. Neraka itu seburuk-buruk tempat yang didatangi.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 99), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan mereka selalu diikuti dengan kutukan di dunia ini dan (begitu pula) di hari kiamat. La''nat itu seburuk-buruk pemberian yang diberikan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 100), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Itu adalah sebahagian dan berita-berita negeri (yang telah dibinasakan) yang Kami ceritakan kepadamu (Muhammad); di antara negeri-negeri itu ada yang masih kedapatan bekas-bekasnya dan ada (pula) yang telah musnah.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 101), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Kami tidaklah menganiaya mereka tetapi merekalah yang menganiaya diri mereka sendiri, karena itu tiadalah bermanfaat sedikitpun kepada mereka sembahan-sembahan yang mereka seru selain Allah, di waktu azab Tuhanmu datang. Dan sembahan-sembahan itu tidaklah menambah kepada mereka kecuali kebinasaan belaka.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 102), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan begitulah azab Tuhanmu, apabila Dia mengazab penduduk negeri-negeri yang berbuat zalim. Sesungguhnya azab-Nya itu adalah sangat pedih lagi keras.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 103), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya pada yang demikian itu benar-benar terdapat pelajaran bagi orang-orang yang takut kepada azab akhirat. Hari kiamat itu adalah suatu hari yang semua manusia dikumpulkan untuk (menghadapi)nya, dan hari itu adalah suatu hari yang disaksikan (oleh segala makhluk).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 104), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Kami tiadalah mengundurkannya, melainkan sampai waktu yang tertentu.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 105), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Di kala datang hari itu, tidak ada seorangun yang berbicara, melainkan dengan izin-Nya; maka di antara mereka ada yang celaka dan ada yang berbahagia.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 106), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Adapun orang-orang yang celaka, maka (tempatnya) di dalam neraka, di dalamnya mereka mengeluarkan dan menarik nafas (dengan merintih),', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 107), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'mereka kekal di dalamnya selama ada langit dan bumi, kecuali jika Tuhanmu menghendaki (yang lain). Sesungguhnya Tuhanmu Maha Pelaksana terhadap apa yang Dia kehendaki.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 108), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Adapun orang-orang yang berbahagia, maka tempatnya di dalam surga, mereka kekal di dalamnya selama ada langit dan bumi, kecuali jika Tuhanmu menghendaki (yang lain); sebagai karunia yang tiada putus-putusnya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 109), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka janganlah kamu berada dalam keragu-raguan tentang apa yang disembah oleh mereka. Mereka tidak menyembah melainkan sebagaimana nenek moyang mereka menyembah dahulu. Dan sesungguhnya Kami pasti akan menyempurnakan dengan secukup-cukupnya pembalasan (terhadap) mereka dengan tidak dikurangi sedikitpun.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 110), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan sesungguhnya Kami telah memberikan Kitab (Taurat) kepada Musa, lalu diperselisihkan tentang Kitab itu. Dan seandainya tidak ada ketetapan yang telah terdahulu dari Tuhanmu, niscaya telah ditetapkan hukuman di antara mereka. Dan sesungguhnya mereka (orang-orang kafir Mekah) dalam keraguan yang menggelisahkan terhadap Al Quran.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 111), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan sesungguhnya kepada masing-masing (mereka yang berselisih itu) pasti Tuhanmu akan menyempurnakan dengan cukup, (balasan) pekerjaan mereka. Sesungguhnya Dia Maha Mengetahui apa yang mereka kerjakan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 112), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka tetaplah kamu pada jalan yang benar, sebagaimana diperintahkan kepadamu dan (juga) orang yang telah taubat beserta kamu dan janganlah kamu melampaui batas. Sesungguhnya Dia Maha Melihat apa yang kamu kerjakan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 113), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan janganlah kamu cenderung kepada orang-orang yang zalim yang menyebabkan kamu disentuh api neraka, dan sekali-kali kamu tiada mempunyai seorang penolongpun selain daripada Allah, kemudian kamu tidak akan diberi pertolongan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 114), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan dirikanlah sembahyang itu pada kedua tepi siang (pagi dan petang) dan pada bahagian permulaan daripada malam. Sesungguhnya perbuatan-perbuatan yang baik itu menghapuskan (dosa) perbuatan-perbuatan yang buruk. Itulah peringatan bagi orang-orang yang ingat.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 115), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan bersabarlah, karena sesungguhnya Allah tiada menyia-nyiakan pahala orang-orang yang berbuat kebaikan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 116), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka mengapa tidak ada dari umat-umat yang sebelum kamu orang-orang yang mempunyai keutamaan yang melarang daripada (mengerjakan) kerusakan di muka bumi, kecuali sebahagian kecil di antara orang-orang yang telah Kami selamatkan di antara mereka, dan orang-orang yang zalim hanya mementingkan kenikmatan yang mewah yang ada pada mereka, dan mereka adalah orang-orang yang berdosa.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 117), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Tuhanmu sekali-kali tidak akan membinasakan negeri-negeri secara zalim, sedang penduduknya orang-orang yang berbuat kebaikan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 118), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Jikalau Tuhanmu menghendaki, tentu Dia menjadikan manusia umat yang satu, tetapi mereka senantiasa berselisih pendapat,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 119), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'kecuali orang-orang yang diberi rahmat oleh Tuhanmu. Dan untuk itulah Allah menciptakan mereka. Kalimat Tuhanmu (keputusan-Nya) telah ditetapkan: sesungguhnya Aku akan memenuhi neraka Jahannam dengan jin dan manusia (yang durhaka) semuanya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 120), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan semua kisah dari rasul-rasul Kami ceritakan kepadamu, ialah kisah-kisah yang dengannya Kami teguhkan hatimu; dan dalam surat ini telah datang kepadamu kebenaran serta pengajaran dan peringatan bagi orang-orang yang beriman.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 121), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan katakanlah kepada orang-orang yang tidak beriman: "Berbuatlah menurut kemampuanmu; sesungguhnya Kami-pun berbuat (pula)".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 122), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan tunggulah (akibat perbuatanmu); sesungguhnya kamipun menunggu (pula)".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 123), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan kepunyaan Allah-lah apa yang ghaib di langit dan di bumi dan kepada-Nya-lah dikembalikan urusan-urusan semuanya, maka sembahlah Dia, dan bertawakkallah kepada-Nya. Dan sekali-kali Tuhanmu tidak lalai dari apa yang kamu kerjakan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Alif, laam, raa. Ini adalah ayat-ayat Kitab (Al Quran) yang nyata (dari Allah).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya Kami menurunkannya berupa Al Quran dengan berbahasa Arab, agar kamu memahaminya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Kami menceritakan kepadamu kisah yang paling baik dengan mewahyukan Al Quran ini kepadamu, dan sesungguhnya kamu sebelum (Kami mewahyukan)nya adalah termasuk orang-orang yang belum mengetahui.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '(Ingatlah), ketika Yusuf berkata kepada ayahnya: "Wahai ayahku, sesungguhnya aku bermimpi melihat sebelas bintang, matahari dan bulan; kulihat semuanya sujud kepadaku".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Ayahnya berkata: "Hai anakku, janganlah kamu ceritakan mimpimu itu kepada saudara-saudaramu, maka mereka membuat makar (untuk membinasakan)mu. Sesungguhnya syaitan itu adalah musuh yang nyata bagi manusia".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan demikianlah Tuhanmu, memilih kamu (untuk menjadi Nabi) dan diajarkan-Nya kepadamu sebahagian dari ta''bir mimpi-mimpi dan disempurnakan-Nya nikmat-Nya kepadamu dan kepada keluarga Ya''qub, sebagaimana Dia telah menyempurnakan nikmat-Nya kepada dua orang bapakmu sebelum itu, (yaitu) Ibrahim dan Ishak. Sesungguhnya Tuhanmu Maha Mengetahui lagi Maha Bijaksana.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya ada beberapa tanda-tanda kekuasaan Allah pada (kisah) Yusuf dan saudara-saudaranya bagi orang-orang yang bertanya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '(Yaitu) ketika mereka berkata: "Sesungguhnya Yusuf dan saudara kandungnya (Bunyamin) lebih dicintai oleh ayah kita dari pada kita sendiri, padahal kita (ini) adalah satu golongan (yang kuat). Sesungguhnya ayah kita adalah dalam kekeliruan yang nyata.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Bunuhlah Yusuf atau buanglah dia kesuatu daerah (yang tak dikenal) supaya perhatian ayahmu tertumpah kepadamu saja, dan sesudah itu hendaklah kamu menjadi orang-orang yang baik".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Seorang diantara mereka berkata: "Janganlah kamu bunuh Yusuf, tetapi masukkanlah dia ke dasar sumur supaya dia dipungut oleh beberapa orang musafir, jika kamu hendak berbuat".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mereka berkata: "Wahai ayah kami, apa sebabnya kamu tidak mempercayai kami terhadap Yusuf, padahal sesungguhnya kami adalah orang-orang yang mengingini kebaikan baginya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 12), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Biarkanlah dia pergi bersama kami besok pagi, agar dia (dapat) bersenang-senang dan (dapat) bermain-main, dan sesungguhnya kami pasti menjaganya".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 13), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Berkata Ya''qub: "Sesungguhnya kepergian kamu bersama Yusuf amat menyedihkanku dan aku khawatir kalau-kalau dia dimakan serigala, sedang kamu lengah dari padanya".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 14), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mereka berkata: "Jika ia benar-benar dimakan serigala, sedang kami golongan (yang kuat), sesungguhnya kami kalau demikian adalah orang-orang yang merugi".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 15), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka tatkala mereka membawanya dan sepakat memasukkannya ke dasar sumur (lalu mereka masukkan dia), dan (di waktu dia sudah dalam sumur) Kami wahyukan kepada Yusuf: "Sesungguhnya kamu akan menceritakan kepada mereka perbuatan mereka ini, sedang mereka tiada ingat lagi".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 16), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Kemudian mereka datang kepada ayah mereka di sore hari sambil menangis.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 17), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mereka berkata: "Wahai ayah kami, sesungguhnya kami pergi berlomba-lomba dan kami tinggalkan Yusuf di dekat barang-barang kami, lalu dia dimakan serigala; dan kamu sekali-kali tidak akan percaya kepada kami, sekalipun kami adalah orang-orang yang benar".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 18), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mereka datang membawa baju gamisnya (yang berlumuran) dengan darah palsu. Ya''qub berkata: "Sebenarnya dirimu sendirilah yang memandang baik perbuatan (yang buruk) itu; maka kesabaran yang baik itulah (kesabaranku). Dan Allah sajalah yang dimohon pertolongan-Nya terhadap apa yang kamu ceritakan".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 19), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Kemudian datanglah kelompok orang-orang musafir, lalu mereka menyuruh seorang pengambil air, maka dia menurunkan timbanya, dia berkata: "Oh; kabar gembira, ini seorang anak muda!" Kemudian mereka menyembunyikan dia sebagai barang dagangan. Dan Allah Maha Mengetahui apa yang mereka kerjakan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 20), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan mereka menjual Yusuf dengan harga yang murah, yaitu beberapa dirham saja, dan mereka merasa tidak tertarik hatinya kepada Yusuf.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 21), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan orang Mesir yang membelinya berkata kepada isterinya: "Berikanlah kepadanya tempat (dan layanan) yang baik, boleh jadi dia bermanfaat kepada kita atau kita pungut dia sebagai anak". Dan demikian pulalah Kami memberikan kedudukan yang baik kepada Yusuf di muka bumi (Mesir), dan agar Kami ajarkan kepadanya ta''bir mimpi. Dan Allah berkuasa terhadap urusan-Nya, tetapi kebanyakan manusia tiada mengetahuinya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 22), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan tatkala dia cukup dewasa Kami berikan kepadanya hikmah dan ilmu. Demikianlah Kami memberi balasan kepada orang-orang yang berbuat baik.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 23), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan wanita (Zulaikha) yang Yusuf tinggal di rumahnya menggoda Yusuf untuk menundukkan dirinya (kepadanya) dan dia menutup pintu-pintu, seraya berkata: "Marilah ke sini". Yusuf berkata: "Aku berlindung kepada Allah, sungguh tuanku telah memperlakukan aku dengan baik". Sesungguhnya orang-orang yang zalim tiada akan beruntung.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 24), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya wanita itu telah bermaksud (melakukan perbuatan itu) dengan Yusuf, dan Yusufpun bermaksud (melakukan pula) dengan wanita itu andaikata dia tidak melihat tanda (dari) Tuhannya. Demikianlah, agar Kami memalingkan dari padanya kemungkaran dan kekejian. Sesungguhnya Yusuf itu termasuk hamba-hamba Kami yang terpilih.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 25), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan keduanya berlomba-lomba menuju pintu dan wanita itu menarik baju gamis Yusuf dari belakang hingga koyak dan kedua-duanya mendapati suami wanita itu di muka pintu. Wanita itu berkata: "Apakah pembalasan terhadap orang yang bermaksud berbuat serong dengan isterimu, selain dipenjarakan atau (dihukum) dengan azab yang pedih?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 26), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Yusuf berkata: "Dia menggodaku untuk menundukkan diriku (kepadanya)", dan seorang saksi dari keluarga wanita itu memberikan kesaksiannya: "Jika baju gamisnya koyak di muka, maka wanita itu benar dan Yusuf termasuk orang-orang yang dusta.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 27), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan jika baju gamisnya koyak di belakang, maka wanita itulah yang dusta, dan Yusuf termasuk orang-orang yang benar".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 28), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka tatkala suami wanita itu melihat baju gamis Yusuf koyak di belakang berkatalah dia: "Sesungguhnya (kejadian) itu adalah diantara tipu daya kamu, sesungguhnya tipu daya kamu adalah besar".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 29), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '(Hai) Yusuf: "Berpalinglah dari ini, dan (kamu hai isteriku) mohon ampunlah atas dosamu itu, karena kamu sesungguhnya termasuk orang-orang yang berbuat salah".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 30), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan wanita-wanita di kota berkata: "Isteri Al Aziz menggoda bujangnya untuk menundukkan dirinya (kepadanya), sesungguhnya cintanya kepada bujangnya itu adalah sangat mendalam. Sesungguhnya kami memandangnya dalam kesesatan yang nyata".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 31), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka tatkala wanita itu (Zulaikha) mendengar cercaan mereka, diundangnyalah wanita-wanita itu dan disediakannya bagi mereka tempat duduk, dan diberikannya kepada masing-masing mereka sebuah pisau (untuk memotong jamuan), kemudian dia berkata (kepada Yusuf): "Keluarlah (nampakkanlah dirimu) kepada mereka". Maka tatkala wanita-wanita itu melihatnya, mereka kagum kepada (keelokan rupa)nya, dan mereka melukai (jari) tangannya dan berkata: "Maha sempurna Allah, ini bukanlah manusia. Sesungguhnya ini tidak lain hanyalah malaikat yang mulia".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 32), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Wanita itu berkata: "Itulah dia orang yang kamu cela aku karena (tertarik) kepadanya, dan sesungguhnya aku telah menggoda dia untuk menundukkan dirinya (kepadaku) akan tetapi dia menolak. Dan sesungguhnya jika dia tidak mentaati apa yang aku perintahkan kepadanya, niscaya dia akan dipenjarakan dan dia akan termasuk golongan orang-orang yang hina".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 33), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Yusuf berkata: "Wahai Tuhanku, penjara lebih aku sukai daripada memenuhi ajakan mereka kepadaku. Dan jika tidak Engkau hindarkan dari padaku tipu daya mereka, tentu aku akan cenderung untuk (memenuhi keinginan mereka) dan tentulah aku termasuk orang-orang yang bodoh".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 34), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka Tuhannya memperkenankan doa Yusuf dan Dia menghindarkan Yusuf dari tipu daya mereka. Sesungguhnya Dialah Yang Maha Mendengar lagi Maha Mengetahui.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 35), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Kemudian timbul pikiran pada mereka setelah melihat tanda-tanda (kebenaran Yusuf) bahwa mereka harus memenjarakannya sampai sesuatu waktu.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 36), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan bersama dengan dia masuk pula ke dalam penjara dua orang pemuda. Berkatalah salah seorang diantara keduanya: "Sesungguhnya aku bermimpi, bahwa aku memeras anggur". Dan yang lainnya berkata: "Sesungguhnya aku bermimpi, bahwa aku membawa roti di atas kepalaku, sebahagiannya dimakan burung". Berikanlah kepada kami ta''birnya; sesungguhnya kami memandang kamu termasuk orang-orang yang pandai (mena''birkan mimpi).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 37), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Yusuf berkata: "Tidak disampaikan kepada kamu berdua makanan yang akan diberikan kepadamu melainkan aku telah dapat menerangkan jenis makanan itu, sebelum makanan itu sampai kepadamu. Yang demikian itu adalah sebagian dari apa yang diajarkan kepadaku oleh Tuhanku. Sesungguhnya aku telah meninggalkan agama orang-orang yang tidak beriman kepada Allah, sedang mereka ingkar kepada hari kemudian.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 38), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan aku pengikut agama bapak-bapakku yaitu Ibrahim, Ishak dan Ya''qub. Tiadalah patut bagi kami (para Nabi) mempersekutukan sesuatu apapun dengan Allah. Yang demikian itu adalah dari karunia Allah kepada kami dan kepada manusia (seluruhnya); tetapi kebanyakan manusia tidak mensyukuri (Nya).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 39), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Hai kedua penghuni penjara, manakah yang baik, tuhan-tuhan yang bermacam-macam itu ataukah Allah Yang Maha Esa lagi Maha Perkasa?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 40), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Kamu tidak menyembah yang selain Allah kecuali hanya (menyembah) nama-nama yang kamu dan nenek moyangmu membuat-buatnya. Allah tidak menurunkan suatu keteranganpun tentang nama-nama itu. Keputusan itu hanyalah kepunyaan Allah. Dia telah memerintahkan agar kamu tidak menyembah selain Dia. Itulah agama yang lurus, tetapi kebanyakan manusia tidak mengetahui".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 41), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Hai kedua penghuni penjara: "Adapun salah seorang diantara kamu berdua, akan memberi minuman tuannya dengan khamar; adapun yang seorang lagi maka ia akan disalib, lalu burung memakan sebagian dari kepalanya. Telah diputuskan perkara yang kamu berdua menanyakannya (kepadaku)".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 42), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Yusuf berkata kepada orang yang diketahuinya akan selamat diantara mereka berdua: "Terangkanlah keadaanku kepada tuanmu". Maka syaitan menjadikan dia lupa menerangkan (keadaan Yusuf) kepada tuannya. Karena itu tetaplah dia (Yusuf) dalam penjara beberapa tahun lamanya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 43), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Raja berkata (kepada orang-orang terkemuka dari kaumnya): "Sesungguhnya aku bermimpi melihat tujuh ekor sapi betina yang gemuk-gemuk dimakan oleh tujuh ekor sapi betina yang kurus-kurus dan tujuh bulir (gandum) yang hijau dan tujuh bulir lainnya yang kering". Hai orang-orang yang terkemuka: "Terangkanlah kepadaku tentang ta''bir mimpiku itu jika kamu dapat mena''birkan mimpi".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 44), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mereka menjawab: "(Itu) adalah mimpi-mimpi yang kosong dan kami sekali-kali tidak tahu menta''birkan mimpi itu".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 45), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan berkatalah orang yang selamat diantara mereka berdua dan teringat (kepada Yusuf) sesudah beberapa waktu lamanya: "Aku akan memberitakan kepadamu tentang (orang yang pandai) mena''birkan mimpi itu, maka utuslah aku (kepadanya)".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 46), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '(Setelah pelayan itu berjumpa dengan Yusuf dia berseru): "Yusuf, hai orang yang amat dipercaya, terangkanlah kepada kami tentang tujuh ekor sapi betina yang gemuk-gemuk yang dimakan oleh tujuh ekor sapi betina yang kurus-kurus dan tujuh bulir (gandum) yang hijau dan (tujuh) lainnya yang kering agar aku kembali kepada orang-orang itu, agar mereka mengetahuinya".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 47), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Yusuf berkata: "Supaya kamu bertanam tujuh tahun (lamanya) sebagaimana biasa; maka apa yang kamu tuai hendaklah kamu biarkan dibulirnya kecuali sedikit untuk kamu makan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 48), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Kemudian sesudah itu akan datang tujuh tahun yang amat sulit, yang menghabiskan apa yang kamu simpan untuk menghadapinya (tahun sulit), kecuali sedikit dari (bibit gandum) yang kamu simpan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 49), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Kemudian setelah itu akan datang tahun yang padanya manusia diberi hujan (dengan cukup) dan dimasa itu mereka memeras anggur".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 50), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Raja berkata: "Bawalah dia kepadaku". Maka tatkala utusan itu datang kepada Yusuf, berkatalah Yusuf: "Kembalilah kepada tuanmu dan tanyakanlah kepadanya bagaimana halnya wanita-wanita yang telah melukai tangannya. Sesungguhnya Tuhanku, Maha Mengetahui tipu daya mereka".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 51), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Raja berkata (kepada wanita-wanita itu): "Bagaimana keadaanmu ketika kamu menggoda Yusuf untuk menundukkan dirinya (kepadamu)?" Mereka berkata: "Maha Sempurna Allah, kami tiada mengetahui sesuatu keburukan dari padanya". Berkata isteri Al Aziz: "Sekarang jelaslah kebenaran itu, akulah yang menggodanya untuk menundukkan dirinya (kepadaku), dan sesungguhnya dia termasuk orang-orang yang benar".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 52), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '(Yusuf berkata): "Yang demikian itu agar dia (Al Aziz) mengetahui bahwa sesungguhnya aku tidak berkhianat kepadanya di belakangnya, dan bahwasanya Allah tidak meridhai tipu daya orang-orang yang berkhianat.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 53), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan aku tidak membebaskan diriku (dari kesalahan), karena sesungguhnya nafsu itu selalu menyuruh kepada kejahatan, kecuali nafsu yang diberi rahmat oleh Tuhanku. Sesungguhnya Tuhanku Maha Pengampun lagi Maha Penyanyang.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 54), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan raja berkata: "Bawalah Yusuf kepadaku, agar aku memilih dia sebagai orang yang rapat kepadaku". Maka tatkala raja telah bercakap-cakap dengan dia, dia berkata: "Sesungguhnya kamu (mulai) hari ini menjadi seorang yang berkedudukan tinggi lagi dipercayai pada sisi kami".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 55), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Berkata Yusuf: "Jadikanlah aku bendaharawan negara (Mesir); sesungguhnya aku adalah orang yang pandai menjaga, lagi berpengetahuan".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 56), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan demikianlah Kami memberi kedudukan kepada Yusuf di negeri Mesir; (dia berkuasa penuh) pergi menuju kemana saja ia kehendaki di bumi Mesir itu. Kami melimpahkan rahmat Kami kepada siapa yang Kami kehendaki dan Kami tidak menyia-nyiakan pahala orang-orang yang berbuat baik.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 57), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan sesungguhnya pahala di akhirat itu lebih baik, bagi orang-orang yang beriman dan selalu bertakwa.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 58), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan saudara-saudara Yusuf datang (ke Mesir} lalu mereka masuk ke (tempat)nya. Maka Yusuf mengenal mereka, sedang mereka tidak kenal (lagi) kepadanya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 59), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan tatkala Yusuf menyiapkan untuk mereka bahan makanannya, ia berkata: "Bawalah kepadaku saudaramu yang seayah dengan kamu (Bunyamin), tidakkah kamu melihat bahwa aku menyempurnakan sukatan dan aku adalah sebaik-baik penerima tamu?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 60), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Jika kamu tidak membawanya kepadaku, maka kamu tidak akan mendapat sukatan lagi dari padaku dan jangan kamu mendekatiku".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 61), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mereka berkata: "Kami akan membujuk ayahnya untuk membawanya (ke mari) dan sesungguhnya kami benar-benar akan melaksanakannya".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 62), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Yusuf berkata kepada bujang-bujangnya: "Masukkanlah barang-barang (penukar kepunyaan mereka) ke dalam karung-karung mereka, supaya mereka mengetahuinya apabila mereka telah kembali kepada keluarganya, mudah-mudahan mereka kembali lagi".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 63), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka tatkala mereka telah kembali kepada ayah mereka (Ya''qub) mereka berkata: "Wahai ayah kami, kami tidak akan mendapat sukatan (gandum) lagi, (jika tidak membawa saudara kami), sebab itu biarkanlah saudara kami pergi bersama-sama kami supaya kami mendapat sukatan, dan sesungguhnya kami benar benar akan menjaganya".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 64), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Berkata Ya''qub: "Bagaimana aku akan mempercayakannya (Bunyamin) kepadamu, kecuali seperti aku telah mempercayakan saudaranya (Yusuf) kepada kamu dahulu?". Maka Allah adalah sebaik-baik Penjaga dan Dia adalah Maha Penyanyang diantara para penyanyang.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 65), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Tatkala mereka membuka barang-barangnya, mereka menemukan kembali barang-barang (penukaran) mereka, dikembalikan kepada mereka. Mereka berkata: "Wahai ayah kami apa lagi yang kita inginkan. Ini barang-barang kita dikembalikan kepada kita, dan kami akan dapat memberi makan keluarga kami, dan kami akan dapat memelihara saudara kami, dan kami akan mendapat tambahan sukatan (gandum) seberat beban seekor unta. Itu adalah sukatan yang mudah (bagi raja Mesir)".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 66), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Ya''qub berkata: "Aku sekali-kali tidak akan melepaskannya (pergi) bersama-sama kamu, sebelum kamu memberikan kepadaku janji yang teguh atas nama Allah, bahwa kamu pasti akan membawanya kepadaku kembali, kecuali jika kamu dikepung musuh". Tatkala mereka memberikan janji mereka, maka Ya''qub berkata: "Allah adalah saksi terhadap apa yang kita ucapkan (ini)".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 67), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Ya''qub berkata: "Hai anak-anakku janganlah kamu (bersama-sama) masuk dari satu pintu gerbang, dan masuklah dari pintu-pintu gerbang yang berlain-lain; namun demikian aku tiada dapat melepaskan kamu barang sedikitpun dari pada (takdir) Allah. Keputusan menetapkan (sesuatu) hanyalah hak Allah; kepada-Nya-lah aku bertawakkal dan hendaklah kepada-Nya saja orang-orang yang bertawakkal berserah diri".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 68), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan tatkala mereka masuk menurut yang diperintahkan ayah mereka, maka (cara yang mereka lakukan itu) tiadalah melepaskan mereka sedikitpun dari takdir Allah, akan tetapi itu hanya suatu keinginan pada diri Ya''qub yang telah ditetapkannya. Dan sesungguhnya dia mempunyai pengetahuan, karena Kami telah mengajarkan kepadanya. Akan tetapi kebanyakan manusia tiada mengetahui.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 69), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan tatkala mereka masuk ke (tempat) Yusuf. Yusuf membawa saudaranya (Bunyamin) ke tempatnya, Yusuf berkata: "Sesungguhnya aku (ini) adalah saudaramu, maka janganlah kamu berdukacita terhadap apa yang telah mereka kerjakan".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 70), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka tatkala telah disiapkan untuk mereka bahan makanan mereka, Yusuf memasukkan piala (tempat minum) ke dalam karung saudaranya. Kemudian berteriaklah seseorang yang menyerukan: "Hai kafilah, sesungguhnya kamu adalah orang-orang yang mencuri".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 71), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mereka menjawab, sambil menghadap kepada penyeru-penyeru itu: "Barang apakah yang hilang dari pada kamu?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 72), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Penyeru-penyeru itu berkata: "Kami kehilangan piala raja, dan siapa yang dapat mengembalikannya akan memperoleh bahan makanan (seberat) beban unta, dan aku menjamin terhadapnya".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 73), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Saudara-saudara Yusuf menjawab "Demi Allah sesungguhnya kamu mengetahui bahwa kami datang bukan untuk membuat kerusakan di negeri (ini) dan kami bukanlah para pencuri".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 74), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mereka berkata: "Tetapi apa balasannya jikalau kamu betul-betul pendusta? "', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 75), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mereka menjawab: "Balasannya, ialah pada siapa diketemukan (barang yang hilang) dalam karungnya, maka dia sendirilah balasannya (tebusannya)". Demikianlah kami memberi pembalasan kepada orang-orang yang zalim.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 76), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka mulailah Yusuf (memeriksa) karung-karung mereka sebelum (memeriksa) karung saudaranya sendiri, kemudian dia mengeluarkan piala raja itu dari karung saudaranya. Demikianlah Kami atur untuk (mencapai maksud) Yusuf. Tiadalah patut Yusuf menghukum saudaranya menurut undang-undang raja, kecuali Allah menghendaki-Nya. Kami tinggikan derajat orang yang Kami kehendaki; dan di atas tiap-tiap orang yang berpengetahuan itu ada lagi Yang Maha Mengetahui.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 77), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mereka berkata: "Jika ia mencuri, maka sesungguhnya, telah pernah mencuri pula saudaranya sebelum itu". Maka Yusuf menyembunyikan kejengkelan itu pada dirinya dan tidak menampakkannya kepada mereka. Dia berkata (dalam hatinya): "Kamu lebih buruk kedudukanmu (sifat-sifatmu) dan Allah Maha Mengetahui apa yang kamu terangkan itu".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 78), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mereka berkata: "Wahai Al Aziz, sesungguhnya ia mempunyai ayah yang sudah lanjut usianya, lantaran itu ambillah salah seorang diantara kami sebagai gantinya, sesungguhnya kami melihat kamu termasuk oranng-orang yang berbuat baik".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 79), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Berkata Yusuf: "Aku mohon perlindungan kepada Allah daripada menahan seorang, kecuali orang yang kami ketemukan harta benda kami padanya, jika kami berbuat demikian, maka benar-benarlah kami orang-orang yang zalim".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 80), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka tatkala mereka berputus asa dari pada (putusan) Yusuf mereka menyendiri sambil berunding dengan berbisik-bisik. Berkatalah yang tertua diantara mereka: "Tidakkah kamu ketahui bahwa sesungguhnya ayahmu telah mengambil janji dari kamu dengan nama Allah dan sebelum itu kamu telah menyia-nyiakan Yusuf. Sebab itu aku tidak akan meninggalkan negeri Mesir, sampai ayahku mengizinkan kepadaku (untuk kembali), atau Allah memberi keputusan terhadapku. Dan Dia adalah Hakim yang sebaik-baiknya".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 81), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Kembalilah kepada ayahmu dan katakanlah: "Wahai ayah kami! Sesungguhnya anakmu telah mencuri, dan kami hanya menyaksikan apa yang kami ketahui, dan sekali-kali kami tidak dapat menjaga (mengetahui) barang yang ghaib.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 82), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan tanyalah (penduduk) negeri yang kami berada disitu, dan kafilah yang kami datang bersamanya, dan sesungguhnya kami adalah orang-orang yang benar".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 83), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Ya''qub berkata: "Hanya dirimu sendirilah yang memandang baik perbuatan (yang buruk) itu. Maka kesabaran yang baik itulah (kesabaranku). Mudah-mudahan Allah mendatangkan mereka semuanya kepadaku; sesungguhnya Dialah Yang Maha Mengetahui lagi Maha Bijaksana".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 84), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Ya''qub berpaling dari mereka (anak-anaknya) seraya berkata: "Aduhai duka citaku terhadap Yusuf", dan kedua matanya menjadi putih karena kesedihan dan dia adalah seorang yang menahan amarahnya (terhadap anak-anaknya).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 85), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mereka berkata: "Demi Allah, senantiasa kamu mengingati Yusuf, sehingga kamu mengidapkan penyakit yang berat atau termasuk orang-orang yang binasa".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 86), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Ya''qub menjawab: "Sesungguhnya hanyalah kepada Allah aku mengadukan kesusahan dan kesedihanku, dan aku mengetahui dari Allah apa yang kamu tiada mengetahuinya".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 87), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Hai anak-anakku, pergilah kamu, maka carilah berita tentang Yusuf dan saudaranya dan jangan kamu berputus asa dari rahmat Allah. Sesungguhnya tiada berputus asa dari rahmat Allah, melainkan kaum yang kafir".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 88), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka ketika mereka masuk ke (tempat) Yusuf, mereka berkata: "Hai Al Aziz, kami dan keluarga kami telah ditimpa kesengsaraan dan kami datang membawa barang-barang yang tak berharga, maka sempurnakanlah sukatan untuk kami, dan bersedekahlah kepada kami, sesungguhnya Allah memberi balasan kepada orang-orang yang bersedekah".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 89), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Yusuf berkata: "Apakah kamu mengetahui (kejelekan) apa yang telah kamu lakukan terhadap Yusuf dan saudaranya ketika kamu tidak mengetahui (akibat) perbuatanmu itu?".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 90), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mereka berkata: "Apakah kamu ini benar-benar Yusuf?". Yusuf menjawab: "Akulah Yusuf dan ini saudaraku. Sesungguhnya Allah telah melimpahkan karunia-Nya kepada kami". Sesungguhnya barang siapa yang bertakwa dan bersabar, maka sesungguhnya Allah tidak menyia-nyiakan pahala orang-orang yang berbuat baik"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 91), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mereka berkata: "Demi Allah, sesungguhnya Allah telah melebihkan kamu atas kami, dan sesungguhnya kami adalah orang-orang yang bersalah (berdosa)".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 92), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dia (Yusuf) berkata: "Pada hari ini tak ada cercaan terhadap kamu, mudah-mudahan Allah mengampuni (kamu), dan Dia adalah Maha Penyayang diantara para penyayang".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 93), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Pergilah kamu dengan membawa baju gamisku ini, lalu letakkanlah dia kewajah ayahku, nanti ia akan melihat kembali; dan bawalah keluargamu semuanya kepadaku".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 94), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Tatkala kafilah itu telah ke luar (dari negeri Mesir) berkata ayah mereka: "Sesungguhnya aku mencium bau Yusuf, sekiranya kamu tidak menuduhku lemah akal (tentu kamu membenarkan aku)".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 95), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Keluarganya berkata: "Demi Allah, sesungguhnya kamu masih dalam kekeliruanmu yang dahulu".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 96), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Tatkala telah tiba pembawa kabar gembira itu, maka diletakkannya baju gamis itu ke wajah Ya''qub, lalu kembalilah dia dapat melihat. Berkata Ya''qub: "Tidakkah aku katakan kepadamu, bahwa aku mengetahui dari Allah apa yang kamu tidak mengetahuinya".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 97), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mereka berkata: "Wahai ayah kami, mohonkanlah ampun bagi kami terhadap dosa-dosa kami, sesungguhnya kami adalah orang-orang yang bersalah (berdosa)".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 98), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Ya''qub berkata: "Aku akan memohonkan ampun bagimu kepada Tuhanku. Sesungguhnya Dialah Yang Maha Pengampun lagi Maha Penyayang".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 99), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka tatkala mereka masuk ke (tempat) Yusuf: Yusuf merangkul ibu bapanya dan dia berkata: "Masuklah kamu ke negeri Mesir, insya Allah dalam keadaan aman".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 100), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan ia menaikkan kedua ibu-bapanya ke atas singgasana. Dan mereka (semuanya) merebahkan diri seraya sujud kepada Yusuf. Dan berkata Yusuf: "Wahai ayahku inilah ta''bir mimpiku yang dahulu itu; sesungguhnya Tuhanku telah menjadikannya suatu kenyataan. Dan sesungguhnya Tuhanku telah berbuat baik kepadaku, ketika Dia membebaskan aku dari rumah penjara dan ketika membawa kamu dari dusun padang pasir, setelah syaitan merusakkan (hubungan) antaraku dan saudara-saudaraku. Sesungguhnya Tuhanku Maha Lembut terhadap apa yang Dia kehendaki. Sesungguhnya Dialah Yang Maha Mengetahui lagi Maha Bijaksana.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 101), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Ya Tuhanku, sesungguhnya Engkau telah menganugerahkan kepadaku sebahagian kerajaan dan telah mengajarkan kepadaku sebahagian ta''bir mimpi. (Ya Tuhan) Pencipta langit dan bumi. Engkaulah Pelindungku di dunia dan di akhirat, wafatkanlah aku dalam keadaan Islam dan gabungkanlah aku dengan orang-orang yang saleh.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 102), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Demikian itu (adalah) diantara berita-berita yang ghaib yang Kami wahyukan kepadamu (Muhammad); padahal kamu tidak berada pada sisi mereka, ketika mereka memutuskan rencananya (untuk memasukkan Yusuf ke dalam sumur) dan mereka sedang mengatur tipu daya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 103), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan sebahagian besar manusia tidak akan beriman -- walaupun kamu sangat menginginkannya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 104), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan kamu sekali-kali tidak meminta upah kepada mereka (terhadap seruanmu ini), itu tidak lain hanyalah pengajaran bagi semesta alam.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 105), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan banyak sekali tanda-tanda (kekuasaan Allah) di langit dan di bumi yang mereka melaluinya, sedang mereka berpaling dari padanya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 106), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan sebahagian besar dari mereka tidak beriman kepada Allah, melainkan dalam keadaan mempersekutukan Allah (dengan sembahan-sembahan lain).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 107), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Apakah mereka merasa aman dari kedatangan siksa Allah yang meliputi mereka, atau kedatangan kiamat kepada mereka secara mendadak, sedang mereka tidak menyadarinya?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 108), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Katakanlah: "Inilah jalan (agama)ku, aku dan orang-orang yang mengikutiku mengajak (kamu) kepada Allah dengan hujjah yang nyata, Maha Suci Allah, dan aku tiada termasuk orang-orang yang musyrik".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 109), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Kami tidak mengutus sebelum kamu, melainkan orang laki-laki yang Kami berikan wahyu kepadanya diantara penduduk negeri. Maka tidakkah mereka bepergian di muka bumi lalu melihat bagaimana kesudahan orang-orang sebelum mereka (yang mendustakan rasul) dan sesungguhnya kampung akhirat adalah lebih baik bagi orang-orang yang bertakwa. Maka tidakkah kamu memikirkannya?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 110), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sehingga apabila para rasul tidak mempunyai harapan lagi (tentang keimanan mereka) dan telah meyakini bahwa mereka telah didustakan, datanglah kepada para rasul itu pertolongan Kami, lalu diselamatkan orang-orang yang Kami kehendaki. Dan tidak dapat ditolak siksa Kami dari pada orang-orang yang berdosa.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 111), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya pada kisah-kisah mereka itu terdapat pengajaran bagi orang-orang yang mempunyai akal. Al Quran itu bukanlah cerita yang dibuat-buat, akan tetapi membenarkan (kitab-kitab) yang sebelumnya dan menjelaskan segala sesuatu, dan sebagai petunjuk dan rahmat bagi kaum yang beriman.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Alif laam miim raa. Ini adalah ayat-ayat Al Kitab (Al Quran). Dan Kitab yang diturunkan kepadamu daripada Tuhanmu itu adalah benar: akan tetapi kebanyakan manusia tidak beriman (kepadanya).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Allah-lah Yang meninggikan langit tanpa tiang (sebagaimana) yang kamu lihat, kemudian Dia bersemayam di atas ''Arasy, dan menundukkan matahari dan bulan. Masing-masing beredar hingga waktu yang ditentukan. Allah mengatur urusan (makhluk-Nya), menjelaskan tanda-tanda (kebesaran-Nya), supaya kamu meyakini pertemuan(mu) dengan Tuhanmu.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Dialah Tuhan yang membentangkan bumi dan menjadikan gunung-gunung dan sungai-sungai padanya. Dan menjadikan padanya semua buah-buahan berpasang-pasangan, Allah menutupkan malam kepada siang. Sesungguhnya pada yang demikian itu terdapat tanda-tanda (kebesaran Allah) bagi kaum yang memikirkan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan di bumi ini terdapat bagian-bagian yang berdampingan, dan kebun-kebun anggur, tanaman-tanaman dan pohon korma yang bercabang dan yang tidak bercabang, disirami dengan air yang sama. Kami melebihkan sebahagian tanam-tanaman itu atas sebahagian yang lain tentang rasanya. Sesungguhnya pada yang demikian itu terdapat tanda-tanda (kebesaran Allah) bagi kaum yang berfikir.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan jika (ada sesuatu) yang kamu herankan, maka yang patut mengherankan adalah ucapan mereka: "Apabila kami telah menjadi tanah, apakah kami sesungguhnya akan (dikembalikan) menjadi makhluk yang baru?" Orang-orang itulah yang kafir kepada Tuhannya; dan orang-orang itulah (yang dilekatkan) belenggu di lehernya; mereka itulah penghuni neraka, mereka kekal di dalamnya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mereka meminta kepadamu supaya disegerakan (datangnya) siksa, sebelum (mereka meminta) kebaikan, padahal telah terjadi bermacam-macam contoh siksa sebelum mereka. Sesungguhnya Tuhanmu benar-benar mempunyai ampunan (yang luas) bagi manusia sekalipun mereka zalim, dan sesungguhnya Tuhanmu benar-benar sangat keras siksanya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Orang-orang yang kafir berkata: "Mengapa tidak diturunkan kepadanya (Muhammad) suatu tanda (kebesaran) dari Tuhannya?" Sesungguhnya kamu hanyalah seorang pemberi peringatan; dan bagi tiap-tiap kaum ada orang yang memberi petunjuk.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Allah mengetahui apa yang dikandung oleh setiap perempuan, dan kandungan rahim yang kurang sempurna dan yang bertambah. Dan segala sesuatu pada sisi-Nya ada ukurannya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Yang mengetahui semua yang ghaib dan yang nampak; Yang Maha Besar lagi Maha Tinggi.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sama saja (bagi Tuhan), siapa diantaramu yang merahasiakan ucapannya, dan siapa yang berterus-terang dengan ucapan itu, dan siapa yang bersembunyi di malam hari dan yang berjalan (menampakkan diri) di siang hari.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Bagi manusia ada malaikat-malaikat yang selalu mengikutinya bergiliran, di muka dan di belakangnya, mereka menjaganya atas perintah Allah. Sesungguhnya Allah tidak merubah keadaan sesuatu kaum sehingga mereka merubah keadaan yang ada pada diri mereka sendiri. Dan apabila Allah menghendaki keburukan terhadap sesuatu kaum, maka tak ada yang dapat menolaknya; dan sekali-kali tak ada pelindung bagi mereka selain Dia.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 12), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dialah Tuhan yang memperlihatkan kilat kepadamu untuk menimbulkan ketakutan dan harapan, dan Dia mengadakan awan mendung.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 13), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan guruh itu bertasbih dengan memuji Allah, (demikian pula) para malaikat karena takut kepada-Nya, dan Allah melepaskan halilintar, lalu menimpakannya kepada siapa yang Dia kehendaki, dan mereka berbantah-bantahan tentang Allah, dan Dialah Tuhan Yang Maha keras siksa-Nya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 14), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Hanya bagi Allah-lah (hak mengabulkan) doa yang benar. Dan berhala-berhala yang mereka sembah selain Allah tidak dapat memperkenankan sesuatupun bagi mereka, melainkan seperti orang yang membukakan kedua telapak tangannya ke dalam air supaya sampai air ke mulutnya, padahal air itu tidak dapat sampai ke mulutnya. Dan doa (ibadat) orang-orang kafir itu, hanyalah sia-sia belaka.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 15), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Hanya kepada Allah-lah sujud (patuh) segala apa yang di langit dan di bumi, baik dengan kemauan sendiri ataupun terpaksa (dan sujud pula) bayang-bayangnya di waktu pagi dan petang hari.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 16), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Katakanlah: "Siapakah Tuhan langit dan bumi?" Jawabnya: "Allah". Katakanlah: "Maka patutkah kamu mengambil pelindung-pelindungmu dari selain Allah, padahal mereka tidak menguasai kemanfaatan dan tidak (pula) kemudharatan bagi diri mereka sendiri?". Katakanlah: "Adakah sama orang buta dan yang dapat melihat, atau samakah gelap gulita dan terang benderang; apakah mereka menjadikan beberapa sekutu bagi Allah yang dapat menciptakan seperti ciptaan-Nya sehingga kedua ciptaan itu serupa menurut pandangan mereka?" Katakanlah: "Allah adalah Pencipta segala sesuatu dan Dialah Tuhan Yang Maha Esa lagi Maha Perkasa".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 17), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Allah telah menurunkan air (hujan) dari langit, maka mengalirlah air di lembah-lembah menurut ukurannya, maka arus itu membawa buih yang mengambang. Dan dari apa (logam) yang mereka lebur dalam api untuk membuat perhiasan atau alat-alat, ada (pula) buihnya seperti buih arus itu. Demikianlah Allah membuat perumpamaan (bagi) yang benar dan yang bathil. Adapun buih itu, akan hilang sebagai sesuatu yang tak ada harganya; adapun yang memberi manfaat kepada manusia, maka ia tetap di bumi. Demikianlah Allah membuat perumpamaan-perumpamaan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 18), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Bagi orang-orang yang memenuhi seruan Tuhannya, (disediakan) pembalasan yang baik. Dan orang-orang yang tidak memenuhi seruan Tuhan, sekiranya mereka mempunyai semua (kekayaan) yang ada di bumi dan (ditambah) sebanyak isi bumi itu lagi besertanya, niscaya mereka akan menebus dirinya dengan kekayaan itu. Orang-orang itu disediakan baginya hisab yang buruk dan tempat kediaman mereka ialah Jahanam dan itulah seburuk-buruk tempat kediaman.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 19), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Adakah orang yang mengetahui bahwasanya apa yang diturunkan kepadamu dari Tuhanmu itu benar sama dengan orang yang buta? Hanyalah orang-orang yang berakal saja yang dapat mengambil pelajaran,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 20), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '(yaitu) orang-orang yang memenuhi janji Allah dan tidak merusak perjanjian,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 21), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'dan orang-orang yang menghubungkan apa-apa yang Allah perintahkan supaya dihubungkan, dan mereka takut kepada Tuhannya dan takut kepada hisab yang buruk.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 22), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan orang-orang yang sabar karena mencari keridhaan Tuhannya, mendirikan shalat, dan menafkahkan sebagian rezeki yang Kami berikan kepada mereka, secara sembunyi atau terang-terangan serta menolak kejahatan dengan kebaikan; orang-orang itulah yang mendapat tempat kesudahan (yang baik),', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 23), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '(yaitu) surga ''Adn yang mereka masuk ke dalamnya bersama-sama dengan orang-orang yang saleh dari bapak-bapaknya, isteri-isterinya dan anak cucunya, sedang malaikat-malaikat masuk ke tempat-tempat mereka dari semua pintu;', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 24), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '(sambil mengucapkan): "Salamun ''alaikum bima shabartum". Maka alangkah baiknya tempat kesudahan itu.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 25), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Orang-orang yang merusak janji Allah setelah diikrarkan dengan teguh dan memutuskan apa-apa yang Allah perintahkan supaya dihubungkan dan mengadakan kerusakan di bumi, orang-orang itulah yang memperoleh kutukan dan bagi mereka tempat kediaman yang buruk (Jahannam).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 26), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Allah meluaskan rezeki dan menyempitkannya bagi siapa yang Dia kehendaki. Mereka bergembira dengan kehidupan di dunia, padahal kehidupan dunia itu (dibanding dengan) kehidupan akhirat, hanyalah kesenangan (yang sedikit).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 27), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Orang-orang kafir berkata: "Mengapa tidak diturunkan kepadanya (Muhammad) tanda (mukjizat) dari Tuhannya?" Katakanlah: "Sesungguhnya Allah menyesatkan siapa yang Dia kehendaki dan menunjuki orang-orang yang bertaubat kepada-Nya",', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 28), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '(yaitu) orang-orang yang beriman dan hati mereka manjadi tenteram dengan mengingat Allah. Ingatlah, hanya dengan mengingati Allah-lah hati menjadi tenteram.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 29), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Orang-orang yang beriman dan beramal saleh, bagi mereka kebahagiaan dan tempat kembali yang baik.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 30), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Demikianlah, Kami telah mengutus kamu pada suatu umat yang sungguh telah berlalu beberapa umat sebelumnya, supaya kamu membacakan kepada mereka (Al Quran) yang Kami wahyukan kepadamu, padahal mereka kafir kepada Tuhan Yang Maha Pemurah. Katakanlah: "Dialah Tuhanku tidak ada Tuhan selain Dia; hanya kepada-Nya aku bertawakkal dan hanya kepada-Nya aku bertaubat".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 31), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan sekiranya ada suatu bacaan (kitab suci) yang dengan bacaan itu gunung-gunung dapat digoncangkan atau bumi jadi terbelah atau oleh karenanya orang-orang yang sudah mati dapat berbicara, (tentulah Al Quran itulah dia). Sebenarnya segala urusan itu adalah kepunyaan Allah. Maka tidakkah orang-orang yang beriman itu mengetahui bahwa seandainya Allah menghendaki (semua manusia beriman), tentu Allah memberi petunjuk kepada manusia semuanya. Dan orang-orang yang kafir senantiasa ditimpa bencana disebabkan perbuatan mereka sendiri atau bencana itu terjadi dekat tempat kediaman mereka, sehingga datanglah janji Allah. Sesungguhnya Allah tidak menyalahi janji.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 32), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan sesungguhnya telah diperolok-olokkan beberapa rasul sebelum kamu, maka Aku beri tangguh kepada orang-orang kafir itu kemudian Aku binasakan mereka. Alangkah hebatnya siksaan-Ku itu!', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 33), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka apakah Tuhan yang menjaga setiap diri terhadap apa yang diperbuatnya (sama dengan yang tidak demikian sifatnya)? Mereka menjadikan beberapa sekutu bagi Allah. Katakanlah: "Sebutkanlah sifat-sifat mereka itu". Atau apakah kamu hendak memberitakan kepada Allah apa yang tidak diketahui-Nya di bumi, atau kamu mengatakan (tentang hal itu) sekadar perkataan pada lahirnya saja. Sebenarnya orang-orang kafir itu dijadikan (oleh syaitan) memandang baik tipu daya mereka dan dihalanginya dari jalan (yang benar). Dan barangsiapa yang disesatkan Allah, maka baginya tak ada seorangpun yang akan memberi petunjuk.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 34), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Bagi mereka azab dalam kehidupan dunia dan sesungguhnya azab akhirat adalah lebih keras dan tak ada bagi mereka seorang pelindungpun dari (azab) Allah.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 35), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Perumpamaan surga yang dijanjikan kepada orang-orang yang takwa ialah (seperti taman); mengalir sungai-sungai di dalamnya; buahnya tak henti-henti sedang naungannya (demikian pula). Itulah tempat kesudahan bagi orang-orang yang bertakwa, sedang tempat kesudahan bagi orang-orang kafir ialah neraka.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 36), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Orang-orang yang telah Kami berikan kitab kepada mereka bergembira dengan kitab yang diturunkan kepadamu, dan di antara golongan-golongan (Yahudi dan Nasrani) yang bersekutu, ada yang mengingkari sebahagiannya. Katakanlah "Sesungguhnya aku hanya diperintah untuk menyembah Allah dan tidak mempersekutukan sesuatupun dengan Dia. Hanya kepada-Nya aku seru (manusia) dan hanya kepada-Nya aku kembali".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 37), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan demikianlah, Kami telah menurunkan Al Quran itu sebagai peraturan (yang benar) dalam bahasa Arab. Dan seandainya kamu mengikuti hawa nafsu mereka setelah datang pengetahuan kepadamu, maka sekali-kali tidak ada pelindung dan pemelihara bagimu terhadap (siksa) Allah.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 38), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan sesungguhnya Kami telah mengutus beberapa Rasul sebelum kamu dan Kami memberikan kepada mereka isteri-isteri dan keturunan. Dan tidak ada hak bagi seorang Rasul mendatangkan sesuatu ayat (mukjizat) melainkan dengan izin Allah. Bagi tiap-tiap masa ada Kitab (yang tertentu).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 39), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Allah menghapuskan apa yang Dia kehendaki dan menetapkan (apa yang Dia kehendaki), dan di sisi-Nya-lah terdapat Ummul-Kitab (Lauh mahfuzh).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 40), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan jika Kami perlihatkan kepadamu sebahagian (siksa) yang Kami ancamkan kepada mereka atau Kami wafatkan kamu (hal itu tidak penting bagimu) karena sesungguhnya tugasmu hanya menyampaikan saja, sedang Kami-lah yang menghisab amalan mereka.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 41), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan apakah mereka tidak melihat bahwa sesungguhnya Kami mendatangi daerah-daerah (orang-orang kafir), lalu Kami kurangi daerah-daerah itu (sedikit demi sedikit) dari tepi-tepinya? Dan Allah menetapkan hukum (menurut kehendak-Nya), tidak ada yang dapat menolak ketetapan-Nya; dan Dialah Yang Maha cepat hisab-Nya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 42), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan sungguh orang-orang kafir yang sebelum mereka (kafir Mekah) telah mengadakan tipu daya, tetapi semua tipu daya itu adalah dalam kekuasaan Allah. Dia mengetahui apa yang diusahakan oleh setiap diri, dan orang-orang kafir akan mengetahui untuk siapa tempat kesudahan (yang baik) itu.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 43), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Berkatalah orang-orang kafir: "Kamu bukan seorang yang dijadikan Rasul". Katakanlah: "Cukuplah Allah menjadi saksi antaraku dan kamu, dan antara orang yang mempunyai ilmu Al Kitab".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Alif, laam raa. (Ini adalah) Kitab yang Kami turunkan kepadamu supaya kamu mengeluarkan manusia dari gelap gulita kepada cahaya terang benderang dengan izin Tuhan mereka, (yaitu) menuju jalan Tuhan Yang Maha Perkasa lagi Maha Terpuji.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Allah-lah yang memiliki segala apa yang di langit dan di bumi. Dan kecelakaanlah bagi orang-orang kafir karena siksaan yang sangat pedih,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '(yaitu) orang-orang yang lebih menyukai kehidupan dunia dari pada kehidupan akhirat, dan menghalang-halangi (manusia) dari jalan Allah dan menginginkan agar jalan Allah itu bengkok. Mereka itu berada dalam kesesatan yang jauh.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Kami tidak mengutus seorang rasulpun, melainkan dengan bahasa kaumnya, supaya ia dapat memberi penjelasan dengan terang kepada mereka. Maka Allah menyesatkan siapa yang Dia kehendaki, dan memberi petunjuk kepada siapa yang Dia kehendaki. Dan Dialah Tuhan Yang Maha Kuasa lagi Maha Bijaksana.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan sesungguhnya Kami telah mengutus Musa dengan membawa ayat-ayat Kami, (dan Kami perintahkan kepadanya): "Keluarkanlah kaummu dari gelap gulita kepada cahaya terang benderang dan ingatkanlah mereka kepada hari-hari Allah". Sesunguhnya pada yang demikian itu terdapat tanda-tanda (kekuasaan Allah) bagi setiap orang penyabar dan banyak bersyukur.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan (ingatlah), ketika Musa berkata kepada kaumnya: "Ingatlah nikmat Allah atasmu ketika Dia menyelamatkan kamu dari (Fir''aun dan) pengikut-pengikutnya, mereka menyiksa kamu dengan siksa yang pedih, mereka menyembelih anak-anak laki-lakimu, membiarkan hidup anak-anak perempuanmu; dan pada yang demikian itu ada cobaan yang besar dari Tuhanmu".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan (ingatlah juga), tatkala Tuhanmu memaklumkan; "Sesungguhnya jika kamu bersyukur, pasti Kami akan menambah (nikmat) kepadamu, dan jika kamu mengingkari (nikmat-Ku), maka sesungguhnya azab-Ku sangat pedih".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Musa berkata: "Jika kamu dan orang-orang yang ada di muka bumi semuanya mengingkari (nikmat Allah) maka sesungguhnya Allah Maha Kaya lagi Maha Terpuji".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Belumkah sampai kepadamu berita orang-orang sebelum kamu (yaitu) kaum Nuh, ''Ad, Tsamud dan orang-orang sesudah mereka. Tidak ada yang mengetahui mereka selain Allah. Telah datang rasul-rasul kepada mereka (membawa) bukti-bukti yang nyata lalu mereka menutupkan tangannya ke mulutnya (karena kebencian), dan berkata: "Sesungguhnya kami mengingkari apa yang kamu disuruh menyampaikannya (kepada kami), dan sesungguhnya kami benar-benar dalam keragu-raguan yang menggelisahkan terhadap apa yang kamu ajak kami kepadanya".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Berkata rasul-rasul mereka: "Apakah ada keragu-raguan terhadap Allah, Pencipta langit dan bumi? Dia menyeru kamu untuk memberi ampunan kepadamu dari dosa-dosamu dan menangguhkan (siksaan)mu sampai masa yang ditentukan?" Mereka berkata: "Kamu tidak lain hanyalah manusia seperti kami juga. Kamu menghendaki untuk menghalang-halangi (membelokkan) kami dari apa yang selalu disembah nenek moyang kami, karena itu datangkanlah kepada kami, bukti yang nyata".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Rasul-rasul mereka berkata kepada mereka: "Kami tidak lain hanyalah manusia seperti kamu, akan tetapi Allah memberi karunia kepada siapa yang Dia kehendaki di antara hamba-hamba-Nya. Dan tidak patut bagi kami mendatangkan suatu bukti kepada kamu melainkan dengan izin Allah. Dan hanya kepada Allah sajalah hendaknya orang-orang mukmin bertawakkal.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 12), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mengapa kami tidak akan bertawakkal kepada Allah padahal Dia telah menunjukkan jalan kepada kami, dan kami sungguh-sungguh akan bersabar terhadap gangguan-gangguan yang kamu lakukan kepada kami. Dan hanya kepada Allah saja orang-orang yang bertawakkal itu, berserah diri".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 13), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Orang-orang kafir berkata kepada Rasul-rasul mereka: "Kami sungguh-sungguh akan mengusir kamu dari negeri kami atau kamu kembali kepada agama kami". Maka Tuhan mewahyukan kepada mereka: "Kami pasti akan membinasakan orang-orang yang zalim itu,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 14), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'dan Kami pasti akan menempatkan kamu di negeri-negeri itu sesudah mereka. Yang demikian itu (adalah untuk) orang-orang yang takut (akan menghadap) kehadirat-Ku dan yang takut kepada ancaman-Ku".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 15), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan mereka memohon kemenangan (atas musuh-musuh mereka) dan binasalah semua orang yang berlaku sewenang-wenang lagi keras kepala,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 16), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'di hadapannya ada Jahannam dan dia akan diberi minuman dengan air nanah,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 17), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'diminumnnya air nanah itu dan hampir dia tidak bisa menelannya dan datanglah (bahaya) maut kepadanya dari segenap penjuru, tetapi dia tidak juga mati, dan dihadapannya masih ada azab yang berat.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 18), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Orang-orang yang kafir kepada Tuhannya, amalan-amalan mereka adalah seperti abu yang ditiup angin dengan keras pada suatu hari yang berangin kencang. Mereka tidak dapat mengambil manfaat sedikitpun dari apa yang telah mereka usahakan (di dunia). Yang demikian itu adalah kesesatan yang jauh.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 19), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Tidakkah kamu perhatikan, bahwa sesungguhnya Allah telah menciptakan langit dan bumi dengan hak? Jika Dia menghendaki, niscaya Dia membinasakan kamu dan mengganti(mu) dengan makhluk yang baru,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 20), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'dan yang demikian itu sekali-kali tidak sukar bagi Allah.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 21), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan mereka semuanya (di padang Mahsyar) akan berkumpul menghadap ke hadirat Allah, lalu berkatalah orang-orang yang lemah kepada orang-orang yang sombong: "Sesungguhnya kami dahulu adalah pengikut-pengikutmu, maka dapatkah kamu menghindarkan daripada kami azab Allah (walaupun) sedikit saja? Mereka menjawab: "Seandainya Allah memberi petunjuk kepada kami, niscaya kami dapat memberi petunjuk kepadamu. Sama saja bagi kita, apakah kita mengeluh ataukah bersabar. Sekali-kali kita tidak mempunyai tempat untuk melarikan diri".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 22), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan berkatalah syaitan tatkala perkara (hisab) telah diselesaikan: "Sesungguhnya Allah telah menjanjikan kepadamu janji yang benar, dan akupun telah menjanjikan kepadamu tetapi aku menyalahinya. Sekali-kali tidak ada kekuasaan bagiku terhadapmu, melainkan (sekedar) aku menyeru kamu lalu kamu mematuhi seruanku, oleh sebab itu janganlah kamu mencerca aku akan tetapi cercalah dirimu sendiri. Aku sekali-kali tidak dapat menolongmu dan kamupun sekali-kali tidak dapat menolongku. Sesungguhnya aku tidak membenarkan perbuatanmu mempersekutukan aku (dengan Allah) sejak dahulu". Sesungguhnya orang-orang yang zalim itu mendapat siksaan yang pedih.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 23), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan dimasukkanlah orang-orang yang beriman dan beramal saleh ke dalam surga yang mengalir di bawahnya sungai-sungai, mereka kekal di dalamnya dengan seizin Tuhan mereka. Ucapan penghormatan mereka dalam surga itu ialah "salaam".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 24), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Tidakkah kamu perhatikan bagaimana Allah telah membuat perumpamaan kalimat yang baik seperti pohon yang baik, akarnya teguh dan cabangnya (menjulang) ke langit,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 25), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'pohon itu memberikan buahnya pada setiap musim dengan seizin Tuhannya. Allah membuat perumpamaan-perumpamaan itu untuk manusia supaya mereka selalu ingat.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 26), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan perumpamaan kalimat yang buruk seperti pohon yang buruk, yang telah dicabut dengan akar-akarnya dari permukaan bumi; tidak dapat tetap (tegak) sedikitpun.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 27), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Allah meneguhkan (iman) orang-orang yang beriman dengan ucapan yang teguh itu dalam kehidupan di dunia dan di akhirat; dan Allah menyesatkan orang-orang yang zalim dan memperbuat apa yang Dia kehendaki.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 28), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Tidakkah kamu perhatikan orang-orang yang telah menukar nikmat Allah dengan kekafiran dan menjatuhkan kaumnya ke lembah kebinasaan?,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 29), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'yaitu neraka jahannam; mereka masuk kedalamnya; dan itulah seburuk-buruk tempat kediaman.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 30), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Orang-orang kafir itu telah menjadikan sekutu-sekutu bagi Allah supaya mereka menyesatkan (manusia) dari jalan-Nya. Katakanlah: "Bersenang-senanglah kamu, karena sesungguhnya tempat kembalimu ialah neraka".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 31), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Katakanlah kepada hamba-hamba-Ku yang telah beriman: "Hendaklah mereka mendirikan shalat, menafkahkan sebahagian rezeki yang Kami berikan kepada mereka secara sembunyi ataupun terang-terangan sebelum datang hari (kiamat) yang pada bari itu tidak ada jual beli dan persahabatan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 32), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Allah-lah yang telah menciptakan langit dan bumi dan menurunkan air hujan dari langit, kemudian Dia mengeluarkan dengan air hujan itu berbagai buah-buahan menjadi rezeki untukmu; dan Dia telah menundukkan bahtera bagimu supaya bahtera itu, berlayar di lautan dengan kehendak-Nya, dan Dia telah menundukkan (pula) bagimu sungai-sungai.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 33), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Dia telah menundukkan (pula) bagimu matahari dan bulan yang terus menerus beredar (dalam orbitnya); dan telah menundukkan bagimu malam dan siang.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 34), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Dia telah memberikan kepadamu (keperluanmu) dan segala apa yang kamu mohonkan kepadanya. Dan jika kamu menghitung nikmat Allah, tidaklah dapat kamu menghinggakannya. Sesungguhnya manusia itu, sangat zalim dan sangat mengingkari (nikmat Allah).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 35), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan (ingatlah), ketika Ibrahim berkata: "Ya Tuhanku, jadikanlah negeri ini (Mekah), negeri yang aman, dan jauhkanlah aku beserta anak cucuku daripada menyembah berhala-berhala.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 36), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Ya Tuhanku, sesungguhnya berhala-berhala itu telah menyesatkan kebanyakan daripada manusia, maka barangsiapa yang mengikutiku, maka sesungguhnya orang itu termasuk golonganku, dan barangsiapa yang mendurhakai aku, maka sesungguhnya Engkau, Maha Pengampun lagi Maha Penyayang.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 37), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Ya Tuhan kami, sesungguhnya aku telah menempatkan sebahagian keturunanku di lembah yang tidak mempunyai tanam-tanaman di dekat rumah Engkau (Baitullah) yang dihormati, ya Tuhan kami (yang demikian itu) agar mereka mendirikan shalat, maka jadikanlah hati sebagian manusia cenderung kepada mereka dan beri rezekilah mereka dari buah-buahan, mudah-mudahan mereka bersyukur.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 38), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Ya Tuhan kami, sesungguhnya Engkau mengetahui apa yang kami sembunyikan dan apa yang kami lahirkan; dan tidak ada sesuatupun yang tersembunyi bagi Allah, baik yang ada di bumi maupun yang ada di langit.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 39), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Segala puji bagi Allah yang telah menganugerahkan kepadaku di hari tua(ku) Ismail dan Ishaq. Sesungguhnya Tuhanku, benar-benar Maha Mendengar (memperkenankan) doa.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 40), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Ya Tuhanku, jadikanlah aku dan anak cucuku orang-orang yang tetap mendirikan shalat, ya Tuhan kami, perkenankanlah doaku.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 41), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Ya Tuhan kami, beri ampunlah aku dan kedua ibu bapaku dan sekalian orang-orang mukmin pada hari terjadinya hisab (hari kiamat)".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 42), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan janganlah sekali-kali kamu (Muhammad) mengira, bahwa Allah lalai dari apa yang diperbuat oleh orang-orang yang zalim. Sesungguhnya Allah memberi tangguh kepada mereka sampai hari yang pada waktu itu mata (mereka) terbelalak,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 43), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'mereka datang bergegas-gegas memenuhi panggilan dengan mangangkat kepalanya, sedang mata mereka tidak berkedip-kedip dan hati mereka kosong.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 44), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan berikanlah peringatan kepada manusia terhadap hari (yang pada waktu itu) datang azab kepada mereka, maka berkatalah orang-orang yang zalim: "Ya Tuhan kami, beri tangguhlah kami (kembalikanlah kami ke dunia) walaupun dalam waktu yang sedikit, niscaya kami akan mematuhi seruan Engkau dan akan mengikuti rasul-rasul". (Kepada mereka dikatakan): "Bukankah kamu telah bersumpah dahulu (di dunia) bahwa sekali-kali kamu tidak akan binasa?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 45), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'dan kamu telah berdiam di tempat-tempat kediaman orang-orang yang menganiaya diri mereka sendiri, dan telah nyata bagimu bagaimana Kami telah berbuat terhadap mereka dan telah Kami berikan kepadamu beberapa perumpamaan".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 46), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan sesungguhnya mereka telah membuat makar yang besar padahal di sisi Allah-lah (balasan) makar mereka itu. Dan sesungguhnya makar mereka itu (amat besar) sehingga gunung-gunung dapat lenyap karenanya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 47), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Karena itu janganlah sekali-kali kamu mengira Allah akan menyalahi janji-Nya kepada rasul-raaul-Nya; sesungguhnya Allah Maha Perkasa, lagi mempunyai pembalasan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 48), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '(Yaitu) pada hari (ketika) bumi diganti dengan bumi yang lain dan (demikian pula) langit, dan meraka semuanya (di padang Mahsyar) berkumpul menghadap ke hadirat Allah yang Maha Esa lagi Maha Perkasa.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 49), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan kamu akan melihat orang-orang yang berdosa pada hari itu diikat bersama-sama dengan belenggu.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 50), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Pakaian mereka adalah dari pelangkin (ter) dan muka mereka ditutup oleh api neraka,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 51), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'agar Allah memberi pembalasan kepada tiap-tiap orang terhadap apa yang ia usahakan. Sesungguhnya Allah Maha cepat hisab-Nya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 52), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '(Al Quran) ini adalah penjelasan yang sempurna bagi manusia, dan supaya mereka diberi peringatan dengan-Nya, dan supaya mereka mengetahui bahwasanya Dia adalah Tuhan Yang Maha Esa dan agar orang-orang yang berakal mengambil pelajaran.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Alif, laam, raa. (Surat) ini adalah (sebagian dari) ayat-ayat Al-Kitab (yang sempurna), yaitu (ayat-ayat) Al Quran yang memberi penjelasan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Orang-orang yang kafir itu seringkali (nanti di akhirat) menginginkan, kiranya mereka dahulu (di dunia) menjadi orang-orang muslim.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Biarkanlah mereka (di dunia ini) makan dan bersenang-senang dan dilalaikan oleh angan-angan (kosong), maka kelak mereka akan mengetahui (akibat perbuatan mereka).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Kami tiada membinasakan sesuatu negeripun, melainkan ada baginya ketentuan masa yang telah ditetapkan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Tidak ada suatu umatpun yang dapat mendahului ajalnya, dan tidak (pula) dapat mengundurkan(nya).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mereka berkata: "Hai orang yang diturunkan Al Quran kepadanya, sesungguhnya kamu benar-benar orang yang gila.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mengapa kamu tidak mendatangkan malaikat kepada kami, jika kamu termasuk orang-orang yang benar?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Kami tidak menurunkan malaikat melainkan dengan benar (untuk membawa azab) dan tiadalah mereka ketika itu diberi tangguh.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya Kami-lah yang menurunkan Al Quran, dan sesungguhnya Kami benar-benar memeliharanya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan sesungguhnya Kami telah mengutus (beberapa rasul) sebelum kamu kepada umat-umat yang terdahulu.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan tidak datang seorang rasulpun kepada mereka, melainkan mereka selalu memperolok-olokkannya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 12), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Demikianlah, Kami mamasukkan (rasa ingkar dan memperolok-olokkan itu) kedalam hati orang-orang yang berdosa (orang-orang kafir),', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 13), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'mereka tidak beriman kepadanya (Al Quran) dan sesungguhnya telah berlalu sunnatullah terhadap orang-orang dahulu.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 14), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan jika seandainya Kami membukakan kepada mereka salah satu dari (pintu-pintu) langit, lalu mereka terus menerus naik ke atasnya,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 15), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'tentulah mereka berkata: "Sesungguhnya pandangan kamilah yang dikaburkan, bahkan kami adalah orang orang yang kena sihir".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 16), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan sesungguhnya Kami telah menciptakan gugusan bintang-bintang (di langit) dan Kami telah menghiasi langit itu bagi orang-orang yang memandang(nya),', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 17), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'dan Kami menjaganya dari tiap-tiap syaitan yang terkutuk,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 18), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'kecuali syaitan yang mencuri-curi (berita) yang dapat didengar (dari malaikat) lalu dia dikejar oleh semburan api yang terang.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 19), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Kami telah menghamparkan bumi dan menjadikan padanya gunung-gunung dan Kami tumbuhkan padanya segala sesuatu menurut ukuran.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 20), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Kami telah menjadikan untukmu di bumi keperluan-keperluan hidup, dan (Kami menciptakan pula) makhluk-makhluk yang kamu sekali-kali bukan pemberi rezeki kepadanya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 21), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan tidak ada sesuatupun melainkan pada sisi Kami-lah khazanahnya; dan Kami tidak menurunkannya melainkan dengan ukuran yang tertentu.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 22), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Kami telah meniupkan angin untuk mengawinkan (tumbuh-tumbuhan) dan Kami turunkan hujan dari langit, lalu Kami beri minum kamu dengan air itu, dan sekali-kali bukanlah kamu yang menyimpannya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 23), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan sesungguhnya benar-benar Kami-lah yang menghidupkan dan mematikan dan Kami (pulalah) yang mewarisi.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 24), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan sesungguhnya Kami telah mengetahui orang-orang yang terdahulu daripada-mu dan sesungguhnya Kami mengetahui pula orang-orang yang terkemudian (daripadamu).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 25), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya Tuhanmu, Dialah yang akan menghimpunkan mereka. Sesungguhnya Dia adalah Maha Bijaksana lagi Maha Mengetahui.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 26), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan sesungguhnya Kami telah menciptakan manusia (Adam) dari tanah liat kering (yang berasal) dari lumpur hitam yang diberi bentuk.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 27), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Kami telah menciptakan jin sebelum (Adam) dari api yang sangat panas.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 28), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan (ingatlah), ketika Tuhanmu berfirman kepada para malaikat: "Sesungguhnya Aku akan menciptakan seorang manusia dari tanah liat kering (yang berasal) dari lumpur hitam yang diberi bentuk,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 29), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka apabila Aku telah menyempurnakan kejadiannya, dan telah meniup kan kedalamnya ruh (ciptaan)-Ku, maka tunduklah kamu kepadanya dengan bersujud.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 30), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka bersujudlah para malaikat itu semuanya bersama-sama,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 31), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'kecuali iblis. Ia enggan ikut besama-sama (malaikat) yang sujud itu.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 32), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Allah berfirman: "Hai iblis, apa sebabnya kamu tidak (ikut sujud) bersama-sama mereka yang sujud itu?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 33), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Berkata Iblis: "Aku sekali-kali tidak akan sujud kepada manusia yang Engkau telah menciptakannya dari tanah liat kering (yang berasal) dari lumpur hitam yang diberi bentuk"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 34), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Allah berfirman: "Keluarlah dari surga, karena sesungguhnya kamu terkutuk,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 35), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'dan sesungguhnya kutukan itu tetap menimpamu sampai hari kiamat".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 36), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Berkata iblis: "Ya Tuhanku, (kalau begitu) maka beri tangguhlah kepadaku sampai hari (manusia) dibangkitkan,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 37), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Allah berfirman: "(Kalau begitu) maka sesungguhnya kamu termasuk orang-orang yang diberi tangguh,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 38), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'sampai hari (suatu) waktu yang telah ditentukan,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 39), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Iblis berkata: "Ya Tuhanku, oleh sebab Engkau telah memutuskan bahwa aku sesat, pasti aku akan menjadikan mereka memandang baik (perbuatan maksiat) di muka bumi, dan pasti aku akan menyesatkan mereka semuanya,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 40), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'kecuali hamba-hamba Engkau yang mukhlis di antara mereka".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 41), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Allah berfirman: "Ini adalah jalan yang lurus, kewajiban Aku-lah (menjaganya).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 42), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya hamba-hamba-Ku tidak ada kekuasaan bagimu terhadap mereka, kecuali orang-orang yang mengikut kamu, yaitu orang-orang yang sesat.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 43), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan sesungguhnya Jahannam itu benar-benar tempat yang telah diancamkan kepada mereka (pengikut-pengikut syaitan) semuanya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 44), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Jahannam itu mempunyai tujuh pintu. Tiap-tiap pintu (telah ditetapkan) untuk golongan yang tertentu dari mereka.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 45), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya orang-orang yang bertakwa itu berada dalam surga (taman-taman) dan (di dekat) mata air-mata air (yang mengalir).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 46), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '(Dikatakan kepada mereka): "Masuklah ke dalamnya dengan sejahtera lagi aman"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 47), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Kami lenyapkan segala rasa dendam yang berada dalam hati mereka, sedang mereka merasa bersaudara duduk berhadap-hadapan di atas dipan-dipan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 48), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mereka tidak merasa lelah di dalamnya dan mereka sekali-kali tidak akan dikeluarkan daripadanya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 49), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Kabarkanlah kepada hamba-hamba-Ku, bahwa sesungguhnya Aku-lah Yang Maha Pengampun lagi Maha Penyayang,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 50), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'dan bahwa sesungguhnya azab-Ku adalah azab yang sangat pedih.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 51), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan kabarkanlah kepada mereka tentang tamu-tamu Ibrahim.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 52), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Ketika mereka masuk ke tempatnya, lalu mereka mengucapkan: "Salaam". Berkata Ibrahim: "Sesungguhnya kami merasa takut kepadamu".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 53), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mereka berkata: "Janganlah kamu merasa takut, sesungguhnya kami memberi kabar gembira kepadamu dengan (kelahiran seorang) anak laki-laki (yang akan menjadi) orang yang alim".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 54), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Berkata Ibrahim: "Apakah kamu memberi kabar gembira kepadaku padahal usiaku telah lanjut, maka dengan cara bagaimanakah (terlaksananya) berita gembira yang kamu kabarkan ini?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 55), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mereka menjawab: "Kami menyampaikan kabar gembira kepadamu dengan benar, maka janganlah kamu termasuk orang-orang yang berputus asa".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 56), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Ibrahim berkata: "Tidak ada orang yang berputus asa dari rahmat Tuhan-nya, kecuali orang-orang yang sesat".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 57), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Berkata (pula) Ibrahim: "Apakah urusanmu yang penting (selain itu), hai para utusan?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 58), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mereka menjawab: "Kami sesungguhnya diutus kepada kaum yang berdosa,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 59), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'kecuali Luth beserta pengikut-pengikutnya. Sesungguhnya Kami akan menyelamatkan mereka semuanya,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 60), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'kecuali istrinya. Kami telah menentukan, bahwa sesungguhnya ia itu termasuk orang-orang yang tertinggal (bersama-sama dengan orang kafir lainnya)".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 61), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka tatkala para utusan itu datang kepada kaum Luth, beserta pengikut pengikutnya,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 62), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'ia berkata: "Sesungguhnya kamu adalah orang-orang yang tidak dikenal".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 63), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Para utusan menjawab: "Sebenarnya kami ini datang kepadamu dengan membawa azab yang selalu mereka dustakan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 64), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan kami datang kepadamu membawa kebenaran dan sesungguhnya kami betul-betul orang-orang benar.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 65), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka pergilah kamu di akhir malam dengan membawa keluargamu, dan ikutlah mereka dari belakang dan janganlah seorangpun di antara kamu menoleh kebelakang dan teruskanlah perjalanan ke tempat yang di perintahkan kepadamu".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 66), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan telah Kami wahyukan kepadanya (Luth) perkara itu, yaitu bahwa mereka akan ditumpas habis di waktu subuh.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 67), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan datanglah penduduk kota itu (ke rumah Luth) dengan gembira (karena) kedatangan tamu-tamu itu.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 68), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Luth berkata: "Sesungguhnya mereka adalah tamuku; maka janganlah kamu memberi malu (kepadaku),', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 69), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'dan bertakwalah kepada Allah dan janganlah kamu membuat aku terhina".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 70), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mereka berkata: "Dan bukankah kami telah melarangmu dari (melindungi) manusia?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 71), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Luth berkata: "Inilah puteri-puteriku (kawinlah dengan mereka), jika kamu hendak berbuat (secara yang halal)".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 72), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '(Allah berfirman): "Demi umurmu (Muhammad), sesungguhnya mereka terombang-ambing di dalam kemabukan (kesesatan)".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 73), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka mereka dibinasakan oleh suara keras yang mengguntur, ketika matahari akan terbit.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 74), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka Kami jadikan bahagian atas kota itu terbalik ke bawah dan Kami hujani mereka dengan batu dari tanah yang keras.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 75), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya pada yang demikian itu benar-benar terdapat tanda-tanda (kekuasaan Allah) bagi orang-orang yang memperhatikan tanda-tanda.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 76), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan sesungguhnya kota itu benar-benar terletak di jalan yang masih tetap (dilalui manusia).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 77), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya pada yang demikian itu benar-benar terdapat tanda-tanda (kekuasaan Allah) bagi orang-orang yang beriman.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 78), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan sesungguhnya adalah penduduk Aikah itu benar-benar kaum yang zalim,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 79), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'maka Kami membinasakan mereka. Dan sesungguhnya kedua kota itu benar-benar terletak di jalan umum yang terang.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 80), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan sesungguhnya penduduk-penduduk kota Al Hijr telah mendustakan rasul-rasul,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 81), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'dan Kami telah mendatangkan kepada mereka tanda-tanda (kekuasaan) Kami, tetapi mereka selalu berpaling daripadanya,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 82), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'dan mereka memahat rumah-rumah dari gunung-gunung batu (yang didiami) dengan aman.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 83), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka mereka dibinasakan oleh suara keras yang mengguntur di waktu pagi,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 84), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'maka tak dapat menolong mereka, apa yang telah mereka usahakan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 85), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan tidaklah Kami ciptakan langit dan bumi dan apa yang ada di antara keduanya, melainkan dengan benar. Dan sesungguhnya saat (kiamat) itu pasti akan datang, maka maafkanlah (mereka) dengan cara yang baik.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 86), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya Tuhanmu, Dialah Yang Maha Pencipta lagi Maha Mengetahui.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 87), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan sesungguhnya Kami telah berikan kepadamu tujuh ayat yang dibaca berulang-ulang dan Al Quran yang agung.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 88), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Janganlah sekali-kali kamu menunjukkan pandanganmu kepada kenikmatan hidup yang telah Kami berikan kepada beberapa golongan di antara mereka (orang-orang kafir itu), dan janganlah kamu bersedih hati terhadap mereka dan berendah dirilah kamu terhadap orang-orang yang beriman.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 89), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan katakanlah: "Sesungguhnya aku adalah pemberi peringatan yang menjelaskan".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 90), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sebagaimana (Kami telah memberi peringatan), Kami telah menurunkan (azab) kepada orang-orang yang membagi-bagi (Kitab Allah),', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 91), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '(yaitu) orang-orang yang telah menjadikan Al Quran itu terbagi-bagi.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 92), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka demi Tuhanmu, Kami pasti akan menanyai mereka semua,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 93), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'tentang apa yang telah mereka kerjakan dahulu.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 94), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka sampaikanlah olehmu secara terang-terangan segala apa yang diperintahkan (kepadamu) dan berpalinglah dari orang-orang yang musyrik.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 95), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya Kami memelihara kamu daripada (kejahatan) orang-orang yang memperolok-olokkan (kamu),', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 96), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '(Yaitu) orang-orang yang menganggap adanya tuhan yang lain di samping Allah; maka mereka kelak akan mengetahui (akibat-akibatnya).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 97), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Kami sungguh-sungguh mengetahui, bahwa dadamu menjadi sempit disebabkan apa yang mereka ucapkan,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 98), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'maka bertasbihlah dengan memuji Tuhanmu dan jadilah kamu di antara orang-orang yang bersujud (shalat),', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 99), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'dan sembahlah Tuhanmu sampai datang kepadamu yang diyakini (ajal).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Telah pasti datangnya ketetapan Allah maka janganlah kamu meminta agar disegerakan (datang)nya. Maha Suci Allah dan Maha Tinggi dari apa yang mereka persekutukan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dia menurunkan para malaikat dengan (membawa) wahyu dengan perintah-Nya kepada siapa yang Dia kehendaki di antara hamba-hamba-Nya, yaitu: "Peringatkanlah olehmu sekalian, bahwasanya tidak ada Tuhan (yang hak) melainkan Aku, maka hendaklah kamu bertakwa kepada-Ku".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dia menciptakan langit dan bumi dengan hak. Maha Tinggi Allah daripada apa yang mereka persekutukan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dia telah menciptakan manusia dari mani, tiba-tiba ia menjadi pembantah yang nyata.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Dia telah menciptakan binatang ternak untuk kamu; padanya ada (bulu) yang menghangatkan dan berbagai-bagai manfaat, dan sebahagiannya kamu makan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan kamu memperoleh pandangan yang indah padanya, ketika kamu membawanya kembali ke kandang dan ketika kamu melepaskannya ke tempat penggembalaan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan ia memikul beban-bebanmu ke suatu negeri yang kamu tidak sanggup sampai kepadanya, melainkan dengan kesukaran-kesukaran (yang memayahkan) diri. Sesungguhnya Tuhanmu benar-benar Maha Pengasih lagi Maha Penyayang,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'dan (Dia telah menciptakan) kuda, bagal dan keledai, agar kamu menungganginya dan (menjadikannya) perhiasan. Dan Allah menciptakan apa yang kamu tidak mengetahuinya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan hak bagi Allah (menerangkan) jalan yang lurus, dan di antara jalan-jalan ada yang bengkok. Dan jikalau Dia menghendaki, tentulah Dia memimpin kamu semuanya (kepada jalan yang benar).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dialah, Yang telah menurunkan air hujan dari langit untuk kamu, sebahagiannya menjadi minuman dan sebahagiannya (menyuburkan) tumbuh-tumbuhan, yang pada (tempat tumbuhnya) kamu menggembalakan ternakmu.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dia menumbuhkan bagi kamu dengan air hujan itu tanam-tanaman; zaitun, korma, anggur dan segala macam buah-buahan. Sesungguhnya pada yang demikian itu benar-benar ada tanda (kekuasaan Allah) bagi kaum yang memikirkan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 12), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Dia menundukkan malam dan siang, matahari dan bulan untukmu. Dan bintang-bintang itu ditundukkan (untukmu) dengan perintah-Nya. Sesungguhnya pada yang demikian itu benar-benar ada tanda-tanda (kekuasaan Allah) bagi kaum yang memahami(nya),', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 13), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'dan Dia (menundukkan pula) apa yang Dia ciptakan untuk kamu di bumi ini dengan berlain-lainan macamnya. Sesungguhnya pada yang demikian itu benar-benar terdapat tanda (kekuasaan Allah) bagi kaum yang mengambil pelajaran.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 14), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Dialah, Allah yang menundukkan lautan (untukmu), agar kamu dapat memakan daripadanya daging yang segar (ikan), dan kamu mengeluarkan dari lautan itu perhiasan yang kamu pakai; dan kamu melihat bahtera berlayar padanya, dan supaya kamu mencari (keuntungan) dari karunia-Nya, dan supaya kamu bersyukur.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 15), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Dia menancapkan gunung-gunung di bumi supaya bumi itu tidak goncang bersama kamu, (dan Dia menciptakan) sungai-sungai dan jalan-jalan agar kamu mendapat petunjuk,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 16), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'dan (Dia ciptakan) tanda-tanda (penunjuk jalan). Dan dengan bintang-bintang itulah mereka mendapat petunjuk.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 17), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka apakah (Allah) yang menciptakan itu sama dengan yang tidak dapat menciptakan (apa-apa)?. Maka mengapa kamu tidak mengambil pelajaran.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 18), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan jika kamu menghitung-hitung nikmat Allah, niscaya kamu tak dapat menentukan jumlahnya. Sesungguhnya Allah benar-benar Maha Pengampun lagi Maha Penyayang.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 19), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Allah mengetahui apa yang kamu rahasiakan dan apa yang kamu lahirkan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 20), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan berhala-berhala yang mereka seru selain Allah, tidak dapat membuat sesuatu apapun, sedang berhala-berhala itu (sendiri) dibuat orang.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 21), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '(Berhala-berhala itu) benda mati tidak hidup, dan berhala-berhala tidak mengetahui bilakah penyembah-penyembahnya akan dibangkitkan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 22), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Tuhan kamu adalah Tuhan Yang Maha Esa. Maka orang-orang yang tidak beriman kepada akhirat, hati mereka mengingkari (keesaaan Allah), sedangkan mereka sendiri adalah orang-orang yang sombong.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 23), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Tidak diragukan lagi bahwa sesungguhnya Allah mengetahui apa yang mereka rahasiakan dan apa yang mereka lahirkan. Sesungguhnya Allah tidak menyukai orang-orang yang sombong.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 24), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan apabila dikatakan kepada mereka "Apakah yang telah diturunkan Tuhanmu?" Mereka menjawab: "Dongeng-dongengan orang-orang dahulu",', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 25), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '(ucapan mereka) menyebabkan mereka memikul dosa-dosanya dengan sepenuh-penuhnya pada hari kiamat, dan sebahagian dosa-dosa orang yang mereka sesatkan yang tidak mengetahui sedikitpun (bahwa mereka disesatkan). Ingatlah, amat buruklah dosa yang mereka pikul itu.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 26), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya orang-orang yang sebelum mereka telah mengadakan makar, maka Allah menghancurkan rumah-rumah mereka dari fondasinya, lalu atap (rumah itu) jatuh menimpa mereka dari atas, dan datanglah azab itu kepada mereka dari tempat yang tidak mereka sadari.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 27), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Kemudian Allah menghinakan mereka di hari kiamat, dan berfirman: "Di manakah sekutu-sekutu-Ku itu (yang karena membelanya) kamu selalu memusuhi mereka (nabi-nabi dan orang-orang mukmin)?" Berkatalah orang-orang yang telah diberi ilmu: "Sesungguhnya kehinaan dan azab hari ini ditimpakan atas orang-orang yang kafir",', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 28), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '(yaitu) orang-orang yang dimatikan oleh para malaikat dalam keadaan berbuat zalim kepada diri mereka sendiri, lalu mereka menyerah diri (sambil berkata); "Kami sekali-kali tidak ada mengerjakan sesuatu kejahatanpun". (Malaikat menjawab): "Ada, sesungguhnya Allah Maha Mengetahui apa yang telah kamu kerjakan".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 29), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka masukilah pintu-pintu neraka Jahannam, kamu kekal di dalamnya. Maka amat buruklah tempat orang-orang yang menyombongkan diri itu.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 30), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan dikatakan kepada orang-orang yang bertakwa: "Apakah yang telah diturunkan oleh Tuhanmu?" Mereka menjawab: "(Allah telah menurunkan) kebaikan". Orang-orang yang berbuat baik di dunia ini mendapat (pembalasan) yang baik. Dan sesungguhnya kampung akhirat adalah lebih baik dan itulah sebaik-baik tempat bagi orang yang bertakwa,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 31), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '(yaitu) surga ''Adn yang mereka masuk ke dalamnya, mengalir di bawahnya sungai-sungai, di dalam surga itu mereka mendapat segala apa yang mereka kehendaki. Demikianlah Allah memberi balasan kepada orang-orang yang bertakwa,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 32), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '(yaitu) orang-orang yang diwafatkan dalam keadaan baik oleh para malaikat dengan mengatakan (kepada mereka): "Salaamun''alaikum, masuklah kamu ke dalam surga itu disebabkan apa yang telah kamu kerjakan".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 33), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Tidak ada yang ditunggu-tunggu orang kafir selain dari datangnya para malaikat kepada mereka atau datangnya perintah Tuhanmu. Demikianlah yang telah diperbuat oleh orang-orang (kafir) sebelum mereka. Dan Allah tidak menganiaya mereka, akan tetapi merekalah yang selalu menganiaya diri mereka sendiri,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 34), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka mereka ditimpa oleh (akibat) kejahatan perbuatan mereka dan mereka diliputi oleh azab yang selalu mereka perolok-olokan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 35), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan berkatalah orang-orang musyrik: "Jika Allah menghendaki, niscaya kami tidak akan menyembah sesuatu apapun selain Dia, baik kami maupun bapak-bapak kami, dan tidak pula kami mengharamkan sesuatupun tanpa (izin)-Nya". Demikianlah yang diperbuat orang-orang sebelum mereka; maka tidak ada kewajiban atas para rasul, selain dari menyampaikan (amanat Allah) dengan terang.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 36), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan sungguhnya Kami telah mengutus rasul pada tiap-tiap umat (untuk menyerukan): "Sembahlah Allah (saja), dan jauhilah Thaghut itu", maka di antara umat itu ada orang-orang yang diberi petunjuk oleh Allah dan ada pula di antaranya orang-orang yang telah pasti kesesatan baginya. Maka berjalanlah kamu dimuka bumi dan perhatikanlah bagaimana kesudahan orang-orang yang mendustakan (rasul-rasul).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 37), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Jika kamu sangat mengharapkan agar mereka dapat petunjuk, maka sesungguhnya Allah tiada memberi petunjuk kepada orang yang disesatkan-Nya, dan sekali-kali mereka tiada mempunyai penolong.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 38), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mereka bersumpah dengan nama Allah dengan sumpahnya yang sungguh-sungguh: "Allah tidak akan akan membangkitkan orang yang mati". (Tidak demikian), bahkan (pasti Allah akan membangkitnya), sebagai suatu janji yang benar dari Allah, akan tetapi kebanyakan manusia tiada mengetahui,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 39), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'agar Allah menjelaskan kepada mereka apa yang mereka perselisihkan itu, agar orang-orang kafir itu mengetahui bahwasanya mereka adalah orang-orang yang berdusta.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 40), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya perkataan Kami terhadap sesuatu apabila Kami menghendakinya, Kami hanya mengatakan kepadanya: "kun (jadilah)", maka jadilah ia.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 41), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan orang-orang yang berhijrah karena Allah sesudah mereka dianiaya, pasti Kami akan memberikan tempat yang bagus kepada mereka di dunia. Dan sesungguhnya pahala di akhirat adalah lebih besar, kalau mereka mengetahui,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 42), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '(yaitu) orang-orang yang sabar dan hanya kepada Tuhan saja mereka bertawakkal.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 43), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Kami tidak mengutus sebelum kamu, kecuali orang-orang lelaki yang Kami beri wahyu kepada mereka; maka bertanyalah kepada orang yang mempunyai pengetahuan jika kamu tidak mengetahui,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 44), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'keterangan-keterangan (mukjizat) dan kitab-kitab. Dan Kami turunkan kepadamu Al Quran, agar kamu menerangkan pada umat manusia apa yang telah diturunkan kepada mereka dan supaya mereka memikirkan,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 45), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'maka apakah orang-orang yang membuat makar yang jahat itu, merasa aman (dari bencana) ditenggelamkannya bumi oleh Allah bersama mereka, atau datangnya azab kepada mereka dari tempat yang tidak mereka sadari,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 46), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'atau Allah mengazab mereka diwaktu mereka dalam perjalanan, maka sekali-kali mereka tidak dapat menolak (azab itu),', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 47), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'atau Allah mengazab mereka dengan berangsur-angsur (sampai binasa). Maka sesungguhnya Tuhanmu adalah Maha Pengasih lagi Maha Penyayang.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 48), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan apakah mereka tidak memperhatikan segala sesuatu yang telah diciptakan Allah yang bayangannya berbolak-balik ke kanan dan ke kiri dalam keadaan sujud kepada Allah, sedang mereka berendah diri?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 49), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan kepada Allah sajalah bersujud segala apa yang berada di langit dan semua makhluk yang melata di bumi dan (juga) para ma]aikat, sedang mereka (malaikat) tidak menyombongkan diri.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 50), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mereka takut kepada Tuhan mereka yang di atas mereka dan melaksanakan apa yang diperintahkan (kepada mereka).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 51), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Allah berfirman: "Janganlah kamu menyembah dua tuhan; sesungguhnya Dialah Tuhan Yang Maha Esa, maka hendaklah kepada-Ku saja kamu takut".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 52), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan kepunyaan-Nya-lah segala apa yang ada di langit dan di bumi, dan untuk-Nya-lah ketaatan itu selama-lamanya. Maka mengapa kamu bertakwa kepada selain Allah?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 53), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan apa saja nikmat yang ada pada kamu, maka dari Allah-lah (datangnya), dan bila kamu ditimpa oleh kemudharatan, maka hanya kepada-Nya-lah kamu meminta pertolongan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 54), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Kemudian apabila Dia telah menghilangkan kemudharatan itu dari pada kamu, tiba-tiba sebahagian dari pada kamu mempersekutukan Tuhannya dengan (yang lain),', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 55), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Biarlah mereka mengingkari nikmat yang telah Kami berikan kepada mereka; maka bersenang-senanglah kamu. Kelak kamu akan mengetahui (akibatnya).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 56), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan mereka sediakan untuk berhala-berhala yang mereka tiada mengetahui (kekuasaannya), satu bahagian dari rezeki yang telah Kami berikan kepada mereka. Demi Allah, sesungguhnya kamu akan ditanyai tentang apa yang telah kamu ada-adakan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 57), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan mereka menetapkan bagi Allah anak-anak perempuan. Maha Suci Allah, sedang untuk mereka sendiri (mereka tetapkan) apa yang mereka sukai (yaitu anak-anak laki-laki).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 58), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan apabila seseorang dari mereka diberi kabar dengan (kelahiran) anak perempuan, hitamlah (merah padamlah) mukanya, dan dia sangat marah.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 59), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Ia menyembunyikan dirinya dari orang banyak, disebabkan buruknya berita yang disampaikan kepadanya. Apakah dia akan memeliharanya dengan menanggung kehinaan ataukah akan menguburkannya ke dalam tanah (hidup-hidup)?. Ketahuilah, alangkah buruknya apa yang mereka tetapkan itu.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 60), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Orang-orang yang tidak beriman kepada kehidupan akhirat, mempunyai sifat yang buruk; dan Allah mempunyai sifat yang Maha Tinggi; dan Dialah Yang Maha Perkasa lagi Maha Bijaksana.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 61), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Jikalau Allah menghukum manusia karena kezalimannya, niscaya tidak akan ditinggalkan-Nya di muka bumi sesuatupun dari makhluk yang melata, tetapi Allah menangguhkan mereka sampai kepada waktu yang ditentukan. Maka apabila telah tiba waktunya (yang ditentukan) bagi mereka, tidaklah mereka dapat mengundurkannya barang sesaatpun dan tidak (pula) mendahulukannya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 62), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan mereka menetapkan bagi Allah apa yang mereka sendiri membencinya, dan lidah mereka mengucapkan kedustaan, yaitu bahwa sesungguhnya merekalah yang akan mendapat kebaikan. Tiadalah diragukan bahwa nerakalah bagi mereka, dan sesungguhnya mereka segera dimasukkan (ke dalamnya).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 63), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Demi Allah, sesungguhnya Kami telah mengutus rasul-rasul Kami kepada umat-umat sebelum kamu, tetapi syaitan menjadikan umat-umat itu memandang baik perbuatan mereka (yang buruk), maka syaitan menjadi pemimpin mereka di hari itu dan bagi mereka azab yang sangat pedih.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 64), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Kami tidak menurunkan kepadamu Al-Kitab (Al Quran) ini, melainkan agar kamu dapat menjelaskan kepada mereka apa yang mereka perselisihkan itu dan menjadi petunjuk dan rahmat bagi kaum yang beriman.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 65), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Allah menurunkan dari langit air (hujan) dan dengan air itu dihidupkan-Nya bumi sesudah matinya. Sesungguhnya pada yang demikian itu benar-benar terdapat tanda-tanda (kebesaran Tuhan) bagi orang-orang yang mendengarkan (pelajaran).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 66), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan sesungguhnya pada binatang ternak itu benar-benar terdapat pelajaran bagi kamu. Kami memberimu minum dari pada apa yang berada dalam perutnya (berupa) susu yang bersih antara tahi dan darah, yang mudah ditelan bagi orang-orang yang meminumnya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 67), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan dari buah korma dan anggur, kamu buat minimuman yang memabukkan dan rezeki yang baik. Sesunggguhnya pada yang demikian itu benar-benar terdapat tanda (kebesaran Allah) bagi orang yang memikirkan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 68), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Tuhanmu mewahyukan kepada lebah: "Buatlah sarang-sarang di bukit-bukit, di pohon-pohon kayu, dan di tempat-tempat yang dibikin manusia",', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 69), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'kemudian makanlah dari tiap-tiap (macam) buah-buahan dan tempuhlah jalan Tuhanmu yang telah dimudahkan (bagimu). Dari perut lebah itu ke luar minuman (madu) yang bermacam-macam warnanya, di dalamnya terdapat obat yang menyembuhkan bagi manusia. Sesungguhnya pada yang demikian itu benar-benar terdapat tanda (kebesaran Tuhan) bagi orang-orang yang memikirkan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 70), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Allah menciptakan kamu, kemudian mewafatkan kamu; dan di antara kamu ada yang dikembalikan kepada umur yang paling lemah (pikun), supaya dia tidak mengetahui lagi sesuatupun yang pernah diketahuinya. Sesungguhnya Allah Maha Mengetahui lagi Maha Kuasa.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 71), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Allah melebihkan sebahagian kamu dari sebagian yang lain dalam hal rezeki, tetapi orang-orang yang dilebihkan (rezekinya itu) tidak mau memberikan rezeki mereka kepada budak-budak yang mereka miliki, agar mereka sama (merasakan) rezeki itu. Maka mengapa mereka mengingkari nikmat Allah?.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 72), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Allah menjadikan bagi kamu isteri-isteri dari jenis kamu sendiri dan menjadikan bagimu dari isteri-isteri kamu itu, anak-anak dan cucu-cucu, dan memberimu rezeki dari yang baik-baik. Maka mengapakah mereka beriman kepada yang bathil dan mengingkari nikmat Allah?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 73), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan mereka menyembah selain Allah, sesuatu yang tidak dapat memberikan rezeki kepada mereka sedikitpun dari langit dan bumi, dan tidak berkuasa (sedikit juapun).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 74), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka janganlah kamu mengadakan sekutu-sekutu bagi Allah. Sesungguhnya Allah mengetahui, sedang kamu tidak mengetahui.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 75), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Allah membuat perumpamaan dengan seorang hamba sahaya yang dimiliki yang tidak dapat bertindak terhadap sesuatupun dan seorang yang Kami beri rezeki yang baik dari Kami, lalu dia menafkahkan sebagian dari rezeki itu secara sembunyi dan secara terang-terangan, adakah mereka itu sama? Segala puji hanya bagi Allah, tetapi kebanyakan mereka tiada mengetahui.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 76), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Allah membuat (pula) perumpamaan: dua orang lelaki yang seorang bisu, tidak dapat berbuat sesuatupun dan dia menjadi beban atas penanggungnya, ke mana saja dia disuruh oleh penanggungnya itu, dia tidak dapat mendatangkan suatu kebajikanpun. Samakah orang itu dengan orang yang menyuruh berbuat keadilan, dan dia berada pula di atas jalan yang lurus?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 77), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan kepunyaan Allah-lah segala apa yang tersembunyi di langit dan di bumi. Tidak adalah kejadian kiamat itu, melainkan seperti sekejap mata atau lebih cepat (lagi). Sesungguhnya Allah Maha Kuasa atas segala sesuatu.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 78), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Allah mengeluarkan kamu dari perut ibumu dalam keadaan tidak mengetahui sesuatupun, dan Dia memberi kamu pendengaran, penglihatan dan hati, agar kamu bersyukur.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 79), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Tidakkah mereka memperhatikan burung-burung yang dimudahkan terbang diangkasa bebas. Tidak ada yang menahannya selain daripada Allah. Sesungguhnya pada yang demikian itu benar-benar terdapat tanda-tanda (kebesaran Tuhan) bagi orang-orang yang beriman.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 80), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Allah menjadikan bagimu rumah-rumahmu sebagai tempat tinggal dan Dia menjadikan bagi kamu rumah-rumah (kemah-kemah) dari kulit binatang ternak yang kamu merasa ringan (membawa)nya di waktu kamu berjalan dan waktu kamu bermukim dan (dijadikan-Nya pula) dari bulu domba, bulu unta dan bulu kambing, alat-alat rumah tangga dan perhiasan (yang kamu pakai) sampai waktu (tertentu).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 81), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Allah menjadikan bagimu tempat bernaung dari apa yang telah Dia ciptakan, dan Dia jadikan bagimu tempat-tempat tinggal di gunung-gunung, dan Dia jadikan bagimu pakaian yang memeliharamu dari panas dan pakaian (baju besi) yang memelihara kamu dalam peperangan. Demikianlah Allah menyempurnakan nikmat-Nya atasmu agar kamu berserah diri (kepada-Nya).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 82), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Jika mereka tetap berpaling, maka sesungguhnya kewajiban yang dibebankan atasmu (Muhammad) hanyalah menyampaikan (amanat Allah) dengan terang.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 83), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mereka mengetahui nikmat Allah, kemudian mereka mengingkarinya dan kebanyakan mereka adalah orang-orang yang kafir.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 84), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan (ingatlah) akan hari (ketika) Kami bangkitkan dari tiap-tiap umat seorang saksi (rasul), kemudian tidak diizinkan kepada orang-orang yang kafir (untuk membela diri) dan tidak (pula) mereka dibolehkan meminta maaf.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 85), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan apabila orang-orang zalim telah menyaksikan azab, maka tidaklah diringankan azab bagi mereka dan tidak puIa mereka diberi tangguh.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 86), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan apabila orang-orang yang mempersekutukan (Allah) melihat sekutu-sekutu mereka, mereka berkata: "Ya Tuhan kami mereka inilah sekutu-sekutu kami yang dahulu kami sembah selain dari Engkau". Lalu sekutu-sekutu mereka mengatakan kepada mereka: "Sesungguhnya kamu benar-benar orang-orang yang dusta".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 87), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan mereka menyatakan ketundukannya kepada Allah pada hari itu dan hilanglah dari mereka apa yang selalu mereka ada-adakan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 88), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Orang-orang yang kafir dan menghalangi (manusia) dari jalan Allah, Kami tambahkan kepada mereka siksaan di atas siksaan disebabkan mereka selalu berbuat kerusakan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 89), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '(Dan ingatlah) akan hari (ketika) Kami bangkitkan pada tiap-tiap umat seorang saksi atas mereka dari mereka sendiri dan Kami datangkan kamu (Muhammad) menjadi saksi atas seluruh umat manusia. Dan Kami turunkan kepadamu Al Kitab (Al Quran) untuk menjelaskan segala sesuatu dan petunjuk serta rahmat dan kabar gembira bagi orang-orang yang berserah diri.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 90), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya Allah menyuruh (kamu) berlaku adil dan berbuat kebajikan, memberi kepada kaum kerabat, dan Allah melarang dari perbuatan keji, kemungkaran dan permusuhan. Dia memberi pengajaran kepadamu agar kamu dapat mengambil pelajaran.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 91), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan tepatilah perjanjian dengan Allah apabila kamu berjanji dan janganlah kamu membatalkan sumpah-sumpah(mu) itu, sesudah meneguhkannya, sedang kamu telah menjadikan Allah sebagai saksimu (terhadap sumpah-sumpahmu itu). Sesungguhnya Allah mengetahui apa yang kamu perbuat.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 92), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan janganlah kamu seperti seorang perempuan yang menguraikan benangnya yang sudah dipintal dengan kuat, menjadi cerai berai kembali, kamu menjadikan sumpah (perjanjian)mu sebagai alat penipu di antaramu, disebabkan adanya satu golongan yang lebih banyak jumlahnya dari golongan yang lain. Sesungguhnya Allah hanya menguji kamu dengan hal itu. Dan sesungguhnya di hari kiamat akan dijelaskan-Nya kepadamu apa yang dahulu kamu perselisihkan itu.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 93), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan kalau Allah menghendaki, niscaya Dia menjadikan kamu satu umat (saja), tetapi Allah menyesatkan siapa yang dikehendaki-Nya dan memberi petunjuk kepada siapa yang dikehendaki-Nya. Dan sesungguhnya kamu akan ditanya tentang apa yang telah kamu kerjakan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 94), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan janganlah kamu jadikan sumpah-sumpahmu sebagai alat penipu di antaramu, yang menyebabkan tergelincir kaki(mu) sesudah kokoh tegaknya, dan kamu rasakan kemelaratan (di dunia) karena kamu menghalangi (manusia) dari jalan Allah; dan bagimu azab yang besar.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 95), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan janganlah kamu tukar perjanjianmu dengan Allah dengan harga yang sedikit (murah), sesungguhnya apa yang ada di sisi Allah, itulah yang lebih baik bagimu jika kamu mengetahui.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 96), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Apa yang di sisimu akan lenyap, dan apa yang ada di sisi Allah adalah kekal. Dan sesungguhnya Kami akan memberi balasan kepada orang-orang yang sabar dengan pahala yang lebih baik dari apa yang telah mereka kerjakan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 97), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Barangsiapa yang mengerjakan amal saleh, baik laki-laki maupun perempuan dalam keadaan beriman, maka sesungguhnya akan Kami berikan kepadanya kehidupan yang baik dan sesungguhnya akan Kami beri balasan kepada mereka dengan pahala yang lebih baik dari apa yang telah mereka kerjakan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 98), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Apabila kamu membaca Al Quran hendaklah kamu meminta perlindungan kepada Allah dari syaitan yang terkutuk.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 99), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya syaitan itu tidak ada kekuasaannya atas orang-orang yang beriman dan bertawakkal kepada Tuhannya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 100), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya kekuasaannya (syaitan) hanyalah atas orang-orang yang mengambilnya jadi pemimpin dan atas orang-orang yang mempersekutukannya dengan Allah.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 101), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan apabila Kami letakkan suatu ayat di tempat ayat yang lain sebagai penggantinya padahal Allah lebih mengetahui apa yang diturunkan-Nya, mereka berkata: "Sesungguhnya kamu adalah orang yang mengada-adakan saja". Bahkan kebanyakan mereka tiada mengetahui.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 102), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Katakanlah: "Ruhul Qudus (Jibril) menurunkan Al Quran itu dari Tuhanmu dengan benar, untuk meneguhkan (hati) orang-orang yang telah beriman, dan menjadi petunjuk serta kabar gembira bagi orang-orang yang berserah diri (kepada Allah)".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 103), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan sesungguhnya Kami mengetahui bahwa mereka berkata: "Sesungguhnya Al Quran itu diajarkan oleh seorang manusia kepadanya (Muhammad)". Padahal bahasa orang yang mereka tuduhkan (bahwa) Muhammad belajar kepadanya bahasa ''Ajam, sedang Al Quran adalah dalam bahasa Arab yang terang.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 104), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya orang-orang yang tidak beriman kepada ayat-ayat Allah (Al Quran), Allah tidak akan memberi petunjuk kepada mereka dan bagi mereka azab yang pedih.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 105), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya yang mengada-adakan kebohongan, hanyalah orang-orang yang tidak beriman kepada ayat-ayat Allah, dan mereka itulah orang-orang pendusta.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 106), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Barangsiapa yang kafir kepada Allah sesudah dia beriman (dia mendapat kemurkaan Allah), kecuali orang yang dipaksa kafir padahal hatinya tetap tenang dalam beriman (dia tidak berdosa), akan tetapi orang yang melapangkan dadanya untuk kekafiran, maka kemurkaan Allah menimpanya dan baginya azab yang besar.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 107), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Yang demikian itu disebabkan karena sesungguhnya mereka mencintai kehidupan di dunia lebih dari akhirat, dan bahwasanya Allah tiada memberi petunjuk kepada kaum yang kafir.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 108), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mereka itulah orang-orang yang hati, pendengaran dan penglihatannya telah dikunci mati oleh Allah, dan mereka itulah orang-orang yang lalai.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 109), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Pastilah bahwa mereka di akhirat nanti adalah orang-orang yang merugi.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 110), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan sesungguhnya Tuhanmu (pelindung) bagi orang-orang yang berhijrah sesudah menderita cobaan, kemudian mereka berjihad dan sabar; sesungguhnya Tuhanmu sesudah itu benar-benar Maha Pengampun lagi Maha Penyayang.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 111), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '(Ingatlah) suatu hari (ketika) tiap-tiap diri datang untuk membela dirinya sendiri dan bagi tiap-tiap diri disempurnakan (balasan) apa yang telah dikerjakannya, sedangkan mereka tidak dianiaya (dirugikan).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 112), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Allah telah membuat suatu perumpamaan (dengan) sebuah negeri yang dahulunya aman lagi tenteram, rezekinya datang kepadanya melimpah ruah dari segenap tempat, tetapi (penduduk)nya mengingkari nikmat-nikmat Allah; karena itu Allah merasakan kepada mereka pakaian kelaparan dan ketakutan, disebabkan apa yang selalu mereka perbuat.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 113), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan sesungguhnya telah datang kepada mereka seorang rasul dari mereka sendiri, tetapi mereka mendustakannya; karena itu mereka dimusnahkan azab dan mereka adalah orang-orang yang zalim.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 114), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka makanlah yang halal lagi baik dari rezeki yang telah diberikan Allah kepadamu; dan syukurilah nikmat Allah, jika kamu hanya kepada-Nya saja menyembah.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 115), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya Allah hanya mengharamkan atasmu (memakan) bangkai, darah, daging babi dan apa yang disembelih dengan menyebut nama selain Allah; tetapi barangsiapa yang terpaksa memakannya dengan tidak menganiaya dan tidak pula melampaui batas, maka sesungguhnya Allah Maha Pengampun lagi Maha Penyayang.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 116), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan janganlah kamu mengatakan terhadap apa yang disebut-sebut oleh lidahmu secara dusta "ini halal dan ini haram", untuk mengada-adakan kebohongan terhadap Allah. Sesungguhnya orang-orang yang mengada-adakan kebohongan terhadap Allah tiadalah beruntung.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 117), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '(Itu adalah) kesenangan yang sedikit, dan bagi mereka azab yang pedih.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 118), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan terhadap orang-orang Yahudi, Kami haramkan apa yang telah Kami ceritakan dahulu kepadamu; dan Kami tiada menganiaya mereka, akan tetapi merekalah yang menganiaya diri mereka sendiri.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 119), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Kemudian, sesungguhnya Tuhanmu (mengampuni) bagi orang-orang yang mengerjakan kesalahan karena kebodohannya, kemudian mereka bertaubat sesudah itu dan memperbaiki (dirinya), sesungguhnya Tuhanmu sesudah itu benar-benar Maha Pengampun lagi Maha Penyayang.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 120), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya Ibrahim adalah seorang imam yang dapat dijadikan teladan lagi patuh kepada Allah dan hanif. Dan sekali-kali bukanlah dia termasuk orang-orang yang mempersekutukan (Tuhan),', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 121), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '(lagi) yang mensyukuri nikmat-nikmat Allah. Allah telah memilihnya dan menunjukinya kepada jalan yang lurus.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 122), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Kami berikan kepadanya kebaikan di dunia. Dan sesungguhnya dia di akhirat benar-benar termasuk orang-orang yang saleh.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 123), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Kemudian Kami wahyukan kepadamu (Muhammad): "Ikutilah agama Ibrahim seorang yang hanif" dan bukanlah dia termasuk orang-orang yang mempersekutukan Tuhan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 124), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya diwajibkan (menghormati) hari Sabtu atas orang-orang (Yahudi) yang berselisih padanya. Dan sesungguhnya Tuhanmu benar-benar akan memberi putusan di antara mereka di hari kiamat terhadap apa yang telah mereka perselisihkan itu.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 125), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Serulah (manusia) kepada jalan Tuhan-mu dengan hikmah dan pelajaran yang baik dan bantahlah mereka dengan cara yang baik. Sesungguhnya Tuhanmu Dialah yang lebih mengetahui tentang siapa yang tersesat dari jalan-Nya dan Dialah yang lebih mengetahui orang-orang yang mendapat petunjuk.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 126), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan jika kamu memberikan balasan, maka balaslah dengan balasan yang sama dengan siksaan yang ditimpakan kepadamu. Akan tetapi jika kamu bersabar, sesungguhnya itulah yang lebih baik bagi orang-orang yang sabar.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 127), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Bersabarlah (hai Muhammad) dan tiadalah kesabaranmu itu melainkan dengan pertolongan Allah dan janganlah kamu bersedih hati terhadap (kekafiran) mereka dan janganlah kamu bersempit dada terhadap apa yang mereka tipu dayakan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 128), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya Allah beserta orang-orang yang bertakwa dan orang-orang yang berbuat kebaikan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maha Suci Allah, yang telah memperjalankan hamba-Nya pada suatu malam dari Al Masjidil Haram ke Al Masjidil Aqsha yang telah Kami berkahi sekelilingnya agar Kami perlihatkan kepadanya sebagian dari tanda-tanda (kebesaran) Kami. Sesungguhnya Dia adalah Maha Mendengar lagi Maha Mengetahui.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Kami berikan kepada Musa kitab (Taurat) dan Kami jadikan kitab Taurat itu petunjuk bagi Bani Israil (dengan firman): "Janganlah kamu mengambil penolong selain Aku,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '(yaitu) anak cucu dari orang-orang yang Kami bawa bersama-sama Nuh. Sesungguhnya dia adalah hamba (Allah) yang banyak bersyukur.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan telah Kami tetapkan terhadap Bani Israil dalam Kitab itu: "Sesungguhnya kamu akan membuat kerusakan di muka bumi ini dua kali dan pasti kamu akan menyombongkan diri dengan kesombongan yang besar".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka apabila datang saat hukuman bagi (kejahatan) pertama dari kedua (kejahatan) itu, Kami datangkan kepadamu hamba-hamba Kami yang mempunyai kekuatan yang besar, lalu mereka merajalela di kampung-kampung, dan itulah ketetapan yang pasti terlaksana.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Kemudian Kami berikan kepadamu giliran untuk mengalahkan mereka kembali dan Kami membantumu dengan harta kekayaan dan anak-anak dan Kami jadikan kamu kelompok yang lebih besar.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Jika kamu berbuat baik (berarti) kamu berbuat baik bagi dirimu sendiri dan jika kamu berbuat jahat, maka (kejahatan) itu bagi dirimu sendiri, dan apabila datang saat hukuman bagi (kejahatan) yang kedua, (Kami datangkan orang-orang lain) untuk menyuramkan muka-muka kamu dan mereka masuk ke dalam mesjid, sebagaimana musuh-musuhmu memasukinya pada kali pertama dan untuk membinasakan sehabis-habisnya apa saja yang mereka kuasai.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mudah-mudahan Tuhanmu akan melimpahkan rahmat(Nya) kepadamu; dan sekiranya kamu kembali kepada (kedurhakaan) niscaya Kami kembali (mengazabmu) dan Kami jadikan neraka Jahannam penjara bagi orang-orang yang tidak beriman.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya Al Quran ini memberikan petunjuk kepada (jalan) yang lebih lurus dan memberi khabar gembira kepada orang-orang Mu''min yang mengerjakan amal saleh bahwa bagi mereka ada pahala yang besar,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'dan sesungguhnya orang-orang yang tidak beriman kepada kehidupan akhirat, Kami sediakan bagi mereka azab yang pedih.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan manusia mendoa untuk kejahatan sebagaimana ia mendoa untuk kebaikan. Dan adalah manusia bersifat tergesa-gesa.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 12), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Kami jadikan malam dan siang sebagai dua tanda, lalu Kami hapuskan tanda malam dan Kami jadikan tanda siang itu terang, agar kamu mencari kurnia dari Tuhanmu, dan supaya kamu mengetahui bilangan tahun-tahun dan perhitungan. Dan segala sesuatu telah Kami terangkan dengan jelas.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 13), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan tiap-tiap manusia itu telah Kami tetapkan amal perbuatannya (sebagaimana tetapnya kalung) pada lehernya. Dan Kami keluarkan baginya pada hari kiamat sebuah kitab yang dijumpainya terbuka.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 14), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '"Bacalah kitabmu, cukuplah dirimu sendiri pada waktu ini sebagai penghisab terhadapmu".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 15), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Barangsiapa yang berbuat sesuai dengan hidayah (Allah), maka sesungguhnya dia berbuat itu untuk (keselamatan) dirinya sendiri; dan barangsiapa yang sesat maka sesungguhnya dia tersesat bagi (kerugian) dirinya sendiri. Dan seorang yang berdosa tidak dapat memikul dosa orang lain, dan Kami tidak akan mengazab sebelum Kami mengutus seorang rasul.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 16), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan jika Kami hendak membinasakan suatu negeri, maka Kami perintahkan kepada orang-orang yang hidup mewah di negeri itu (supaya mentaati Allah) tetapi mereka melakukan kedurhakaan dalam negeri itu, maka sudah sepantasnya berlaku terhadapnya perkataan (ketentuan Kami), kemudian Kami hancurkan negeri itu sehancur-hancurnya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 17), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan berapa banyaknya kaum sesudah Nuh telah Kami binasakan. Dan cukuplah Tuhanmu Maha Mengetahui lagi Maha Melihat dosa hamba-hamba-Nya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 18), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Barangsiapa menghendaki kehidupan sekarang (duniawi), maka Kami segerakan baginya di dunia itu apa yang kami kehendaki bagi orang yang kami kehendaki dan Kami tentukan baginya neraka jahannam; ia akan memasukinya dalam keadaan tercela dan terusir.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 19), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan barangsiapa yang menghendaki kehidupan akhirat dan berusaha ke arah itu dengan sungguh-sungguh sedang ia adalah mukmin, maka mereka itu adalah orang-orang yang usahanya dibalasi dengan baik.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 20), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Kepada masing-masing golongan baik golongan ini maupun golongan itu Kami berikan bantuan dari kemurahan Tuhanmu. Dan kemurahan Tuhanmu tidak dapat dihalangi.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 21), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Perhatikanlah bagaimana Kami lebihkan sebagian dari mereka atas sebagian (yang lain). Dan pasti kehidupan akhirat lebih tinggi tingkatnya dan lebih besar keutamaannya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 22), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Janganlah kamu adakan tuhan yang lain di samping Allah, agar kamu tidak menjadi tercela dan tidak ditinggalkan (Allah).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 23), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Tuhanmu telah memerintahkan supaya kamu jangan menyembah selain Dia dan hendaklah kamu berbuat baik pada ibu bapakmu dengan sebaik-baiknya. Jika salah seorang di antara keduanya atau kedua-duanya sampai berumur lanjut dalam pemeliharaanmu, maka sekali-kali janganlah kamu mengatakan kepada keduanya perkataan "ah" dan janganlah kamu membentak mereka dan ucapkanlah kepada mereka perkataan yang mulia.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 24), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan rendahkanlah dirimu terhadap mereka berdua dengan penuh kesayangan dan ucapkanlah: "Wahai Tuhanku, kasihilah mereka keduanya, sebagaimana mereka berdua telah mendidik aku waktu kecil".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 25), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Tuhanmu lebih mengetahui apa yang ada dalam hatimu; jika kamu orang-orang yang baik, maka sesungguhnya Dia Maha Pengampun bagi orang-orang yang bertaubat.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 26), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan berikanlah kepada keluarga-keluarga yang dekat akan haknya, kepada orang miskin dan orang yang dalam perjalanan dan janganlah kamu menghambur-hamburkan (hartamu) secara boros.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 27), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya pemboros-pemboros itu adalah saudara-saudara syaitan dan syaitan itu adalah sangat ingkar kepada Tuhannya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 28), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan jika kamu berpaling dari mereka untuk memperoleh rahmat dari Tuhanmu yang kamu harapkan, maka katakanlah kepada mereka ucapan yang pantas.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 29), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan janganlah kamu jadikan tanganmu terbelenggu pada lehermu dan janganlah kamu terlalu mengulurkannya karena itu kamu menjadi tercela dan menyesal.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 30), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya Tuhanmu melapangkan rezeki kepada siapa yang Dia kehendaki dan menyempitkannya; sesungguhnya Dia Maha Mengetahui lagi Maha Melihat akan hamba-hamba-Nya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 31), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan janganlah kamu membunuh anak-anakmu karena takut kemiskinan. Kamilah yang akan memberi rezeki kepada mereka dan juga kepadamu. Sesungguhnya membunuh mereka adalah suatu dosa yang besar.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 32), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan janganlah kamu mendekati zina; sesungguhnya zina itu adalah suatu perbuatan yang keji. Dan suatu jalan yang buruk.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 33), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan janganlah kamu membunuh jiwa yang diharamkan Allah (membunuhnya), melainkan dengan suatu (alasan) yang benar. Dan barangsiapa dibunuh secara zalim, maka sesungguhnya Kami telah memberi kekuasaan kepada ahli warisnya, tetapi janganlah ahli waris itu melampaui batas dalam membunuh. Sesungguhnya ia adalah orang yang mendapat pertolongan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 34), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan janganlah kamu mendekati harta anak yatim, kecuali dengan cara yang lebih baik (bermanfaat) sampai ia dewasa dan penuhilah janji; sesungguhnya janji itu pasti diminta pertanggungan jawabnya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 35), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan sempurnakanlah takaran apabila kamu menakar, dan timbanglah dengan neraca yang benar. Itulah yang lebih utama (bagimu) dan lebih baik akibatnya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 36), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan janganlah kamu mengikuti apa yang kamu tidak mempunyai pengetahuan tentangnya. Sesungguhnya pendengaran, penglihatan dan hati, semuanya itu akan diminta pertanggungan jawabnya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 37), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan janganlah kamu berjalan di muka bumi ini dengan sombong, karena sesungguhnya kamu sekali-kali tidak dapat menembus bumi dan sekali-kali kamu tidak akan sampai setinggi gunung.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 38), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Semua itu kejahatannya amat dibenci di sisi Tuhanmu.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 39), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Itulah sebagian hikmah yang diwahyukan Tuhanmu kepadamu. Dan janganlah kamu mengadakan tuhan yang lain di samping Allah, yang menyebabkan kamu dilemparkan ke dalam neraka dalam keadaan tercela lagi dijauhkan (dari rahmat Allah).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 40), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka apakah patut Tuhan memilihkan bagimu anak-anak laki-laki sedang Dia sendiri mengambil anak-anak perempuan di antara para malaikat? Sesungguhnya kamu benar-benar mengucapkan kata-kata yang besar (dosanya).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 41), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan sesungguhnya dalam Al Quran ini Kami telah ulang-ulangi (peringatan-peringatan), agar mereka selalu ingat. Dan ulangan peringatan itu tidak lain hanyalah menambah mereka lari (dari kebenaran).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 42), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Katakanlah: "Jikalau ada tuhan-tuhan di samping-Nya, sebagaimana yang mereka katakan, niscaya tuhan-tuhan itu mencari jalan kepada Tuhan yang mempunyai ''Arsy".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 43), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maha Suci dan Maha Tinggi Dia dari apa yang mereka katakan dengan ketinggian yang sebesar-besarnya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 44), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Langit yang tujuh, bumi dan semua yang ada di dalamnya bertasbih kepada Allah. Dan tak ada suatupun melainkan bertasbih dengan memuji-Nya, tetapi kamu sekalian tidak mengerti tasbih mereka. Sesungguhnya Dia adalah Maha Penyantun lagi Maha Pengampun.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 45), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan apabila kamu membaca Al Quran niscaya Kami adakan antara kamu dan orang-orang yang tidak beriman kepada kehidupan akhirat, suatu dinding yang tertutup,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 46), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'dan Kami adakan tutupan di atas hati mereka dan sumbatan di telinga mereka, agar mereka tidak dapat memahaminya. Dan apabila kamu menyebut Tuhanmu saja dalam Al Quran, niscaya mereka berpaling ke belakang karena bencinya,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 47), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Kami lebih mengetahui dalam keadaan bagaimana mereka mendengarkan sewaktu mereka mendengarkan kamu, dan sewaktu mereka berbisik-bisik (yaitu) ketika orang-orang zalim itu berkata: "Kamu tidak lain hanyalah mengikuti seorang laki-laki yang kena sihir".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 48), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Lihatlah bagaimana mereka membuat perumpamaan-perumpamaan terhadapmu; karena itu mereka menjadi sesat dan tidak dapat lagi menemukan jalan (yang benar).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 49), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan mereka berkata: "Apakah bila kami telah menjadi tulang belulang dan benda-benda yang hancur, apa benar-benarkah kami akan dibangkitkan kembali sebagai makhluk yang baru?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 50), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Katakanlah: "Jadilah kamu sekalian batu atau besi,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 51), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'atau suatu makhluk dari makhluk yang tidak mungkin (hidup) menurut pikiranmu". Maka mereka akan bertanya: "Siapa yang akan menghidupkan kami kembali?" Katakanlah: "Yang telah menciptakan kamu pada kali yang pertama". Lalu mereka akan menggeleng-gelengkan kepala mereka kepadamu dan berkata: "Kapan itu (akan terjadi)?" Katakanlah: "Mudah-mudahan waktu berbangkit itu dekat",', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 52), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'yaitu pada hari Dia memanggil kamu, lalu kamu mematuhi-Nya sambil memuji-Nya dan kamu mengira, bahwa kamu tidak berdiam (di dalam kubur) kecuali sebentar saja.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 53), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan katakanlah kepada hamha-hamba-Ku: "Hendaklah mereka mengucapkan perkataan yang lebih baik (benar). Sesungguhnya syaitan itu menimbulkan perselisihan di antara mereka. Sesungguhnya syaitan itu adalah musuh yang nyata bagi manusia.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 54), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Tuhanmu lebih mengetahui tentang kamu. Dia akan memberi rahmat kepadamu jika Dia menghendaki dan Dia akan mengazabmu, jika Dia menghendaki. Dan, Kami tidaklah mengutusmu untuk menjadi penjaga bagi mereka.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 55), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Tuhan-mu lebih mengetahui siapa yang (ada) di langit dan di bumi. Dan sesungguhnya telah Kami lebihkan sebagian nabi-nabi itu atas sebagian (yang lain), dan Kami berikan Zabur kepada Daud.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 56), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Katakanlah: "Panggillah mereka yang kamu anggap (tuhan) selain Allah, maka mereka tidak akan mempunyai kekuasaan untuk menghilangkan bahaya daripadamu dan tidak pula memindahkannya".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 57), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Orang-orang yang mereka seru itu, mereka sendiri mencari jalan kepada Tuhan mereka siapa di antara mereka yang lebih dekat (kepada Allah) dan mengharapkan rahmat-Nya dan takut akan azab-Nya; sesungguhnya azab Tuhanmu adalah suatu yang (harus) ditakuti.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 58), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Tak ada suatu negeripun (yang durhaka penduduknya), melainkan Kami membinasakannya sebelum hari kiamat atau Kami azab (penduduknya) dengan azab yang sangat keras. Yang demikian itu telah tertulis di dalam kitab (Lauh Mahfuzh).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 59), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan sekali-kali tidak ada yang menghalangi Kami untuk mengirimkan (kepadamu) tanda-tanda (kekuasan Kami), melainkan karena tanda-tanda itu telah didustakan oleh orang-orang dahulu. Dan telah Kami berikan kepada Tsamud unta betina itu (sebagai mukjizat) yang dapat dilihat, tetapi mereka menganiaya unta betina itu. Dan Kami tidak memberi tanda-tanda itu melainkan untuk menakuti.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 60), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan (ingatlah), ketika Kami wahyukan kepadamu: "Sesungguhnya (ilmu) Tuhanmu meliputi segala manusia". Dan Kami tidak menjadikan mimpi yang telah Kami perlihatkan kepadamu, melainkan sebagai ujian bagi manusia dan (begitu pula) pohon kayu yang terkutuk dalam Al Quran. Dan Kami menakut-nakuti mereka, tetapi yang demikian itu hanyalah menambah besar kedurhakaan mereka.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 61), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan (ingatlah), tatkala Kami berfirman kepada para malaikat: "Sujudlah kamu semua kepada Adam", lalu mereka sujud kecuali iblis. Dia berkata: "Apakah aku akan sujud kepada orang yang Engkau ciptakan dari tanah?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 62), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dia (iblis) berkata: "Terangkanlah kepadaku inikah orangnya yang Engkau muliakan atas diriku? Sesungguhnya jika Engkau memberi tangguh kepadaku sampai hari kiamat, niscaya benar-benar akan aku sesatkan keturunannya, kecuali sebahagian kecil".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 63), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Tuhan berfirman: "Pergilah, barangsiapa di antara mereka yang mengikuti kamu, maka sesungguhnya neraka Jahannam adalah balasanmu semua, sebagai suatu pembalasan yang cukup.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 64), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan hasunglah siapa yang kamu sanggupi di antara mereka dengan ajakanmu, dan kerahkanlah terhadap mereka pasukan berkuda dan pasukanmu yang berjalan kaki dan berserikatlah dengan mereka pada harta dan anak-anak dan beri janjilah mereka. Dan tidak ada yang dijanjikan oleh syaitan kepada mereka melainkan tipuan belaka.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 65), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya hamba-hamba-Ku, kamu tidak dapat berkuasa atas mereka. Dan cukuplah Tuhan-mu sebagai Penjaga".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 66), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Tuhan-mu adalah yang melayarkan kapal-kapal di lautan untukmu, agar kamu mencari sebahagian dari karunia-Nya. Sesungguhnya Dia adalah Maha Penyayang terhadapmu.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 67), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan apabila kamu ditimpa bahaya di lautan, niscaya hilanglah siapa yang kamu seru kecuali Dia, Maka tatkala Dia menyelamatkan kamu ke daratan, kamu berpaling. Dan manusia itu adalah selalu tidak berterima kasih.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 68), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka apakah kamu merasa aman (dari hukuman Tuhan) yang menjungkir balikkan sebagian daratan bersama kamu atau Dia meniupkan (angin keras yang membawa) batu-batu kecil? dan kamu tidak akan mendapat seorang pelindungpun bagi kamu,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 69), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'atau apakah kamu merasa aman dari dikembalikan-Nya kamu ke laut sekali lagi, lalu Dia meniupkan atas kamu angin taupan dan ditenggelamkan-Nya kamu disebabkan kekafiranmu. Dan kamu tidak akan mendapat seorang penolongpun dalam hal ini terhadap (siksaan) Kami.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 70), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan sesungguhnya telah Kami muliakan anak-anak Adam, Kami angkut mereka di daratan dan di lautan, Kami beri mereka rezeki dari yang baik-baik dan Kami lebihkan mereka dengan kelebihan yang sempurna atas kebanyakan makhluk yang telah Kami ciptakan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 71), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '(Ingatlah) suatu hari (yang di hari itu) Kami panggil tiap umat dengan pemimpinnya; dan barangsiapa yang diberikan kitab amalannya di tangan kanannya maka mereka ini akan membaca kitabnya itu, dan mereka tidak dianiaya sedikitpun.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 72), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan barangsiapa yang buta (hatinya) di dunia ini, niscaya di akhirat (nanti) ia akan lebih buta (pula) dan lebih tersesat dari jalan (yang benar).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 73), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan sesungguhnya mereka hampir memalingkan kamu dari apa yang telah Kami wahyukan kepadamu, agar kamu membuat yang lain secara bohong terhadap Kami; dan kalau sudah begitu tentulah mereka mengambil kamu jadi sahabat yang setia.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 74), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan kalau Kami tidak memperkuat (hati)mu, niscaya kamu hampir-hampir condong sedikit kepada mereka,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 75), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'kalau terjadi demikian, benar-benarlah Kami akan rasakan kepadamu (siksaan) berlipat ganda di dunia ini dan begitu (pula siksaan) berlipat ganda sesudah mati, dan kamu tidak akan mendapat seorang penolongpun terhadap Kami.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 76), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan sesungguhnya benar-benar mereka hampir membuatmu gelisah di negeri (Mekah) untuk mengusirmu daripadanya dan kalau terjadi demikian, niscaya sepeninggalmu mereka tidak tinggal, melainkan sebentar saja.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 77), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '(Kami menetapkan yang demikian) sebagai suatu ketetapan terhadap rasul-rasul Kami yang Kami utus sebelum kamu dan tidak akan kamu dapati perubahan bagi ketetapan Kami itu.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 78), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dirikanlah shalat dari sesudah matahari tergelincir sampai gelap malam dan (dirikanlah pula shalat) subuh. Sesungguhnya shalat subuh itu disaksikan (oleh malaikat).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 79), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan pada sebahagian malam hari bersembahyang tahajudlah kamu sebagai suatu ibadah tambahan bagimu; mudah-mudahan Tuhan-mu mengangkat kamu ke tempat yang terpuji.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 80), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan katakanlah: "Ya Tuhan-ku, masukkanlah aku secara masuk yang benar dan keluarkanlah (pula) aku secara keluar yang benar dan berikanlah kepadaku dari sisi Engkau kekuasaan yang menolong.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 81), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan katakanlah: "Yang benar telah datang dan yang batil telah lenyap". Sesungguhnya yang batil itu adalah sesuatu yang pasti lenyap.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 82), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Kami turunkan dari Al Quran suatu yang menjadi penawar dan rahmat bagi orang-orang yang beriman dan Al Quran itu tidaklah menambah kepada orang-orang yang zalim selain kerugian.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 83), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan apabila Kami berikan kesenangan kepada manusia niscaya berpalinglah dia; dan membelakang dengan sikap yang sombong; dan apabila dia ditimpa kesusahan niscaya dia berputus asa.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 84), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Katakanlah: "Tiap-tiap orang berbuat menurut keadaannya masing-masing". Maka Tuhanmu lebih mengetahui siapa yang lebih benar jalannya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 85), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan mereka bertanya kepadamu tentang roh. Katakanlah: "Roh itu termasuk urusan Tuhan-ku, dan tidaklah kamu diberi pengetahuan melainkan sedikit".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 86), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan sesungguhnya jika Kami menghendaki, niscaya Kami lenyapkan apa yang telah Kami wahyukan kepadamu, dan dengan pelenyapan itu, kamu tidak akan mendapatkan seorang pembelapun terhadap Kami,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 87), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'kecuali karena rahmat dari Tuhanmu. Sesungguhnya karunia-Nya atasmu adalah besar.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 88), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Katakanlah: "Sesungguhnya jika manusia dan jin berkumpul untuk membuat yang serupa Al Quran ini, niscaya mereka tidak akan dapat membuat yang serupa dengan dia, sekalipun sebagian mereka menjadi pembantu bagi sebagian yang lain".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 89), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan sesungguhnya Kami telah mengulang-ulang kepada manusia dalam Al Quran ini tiap-tiap macam perumpamaan, tapi kebanyakan manusia tidak menyukai kecuali mengingkari(nya).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 90), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan mereka berkata: "Kami sekali-kali tidak percaya kepadamu hingga kamu memancarkan mata air dan bumi untuk kami,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 91), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'atau kamu mempunyai sebuah kebun korma dan anggur, lalu kamu alirkan sungai-sungai di celah kebun yang deras alirannya,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 92), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'atau kamu jatuhkan langit berkeping-keping atas kami, sebagaimana kamu katakan atau kamu datangkan Allah dan malaikat-malaikat berhadapan muka dengan kami.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 93), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Atau kamu mempunyai sebuah rumah dari emas, atau kamu naik ke langit. Dan kami sekali-kali tidak akan mempercayai kenaikanmu itu hingga kamu turunkan atas kami sebuah kitab yang kami baca". Katakanlah: "Maha Suci Tuhanku, bukankah aku ini hanya seorang manusia yang menjadi rasul?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 94), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan tidak ada sesuatu yang menghalangi manusia untuk beriman tatkala datang petunjuk kepadanya, kecuali perkataan mereka: "Adakah Allah mengutus seorang manusia menjadi rasuI?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 95), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Katakanlah: "Kalau seandainya ada malaikat-malaikat yang berjalan-jalan sebagai penghuni di bumi, niscaya Kami turunkan dari langit kepada mereka seorang malaikat menjadi rasul".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 96), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Katakanlah: "Cukuplah Allah menjadi saksi antara aku dan kamu sekalian. Sesungguhnya Dia adalah Maha Mengetahui lagi Maha Melihat akan hamba-hamba-Nya".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 97), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan barangsiapa yang ditunjuki Allah, dialah yang mendapat petunjuk dan barangsiapa yang Dia sesatkan maka sekali-kali kamu tidak akan mendapat penolong-penolong bagi mereka selain dari Dia. Dan Kami akan mengumpulkan mereka pada hari kiamat (diseret) atas muka mereka dalam keadaan buta, bisu dan pekak. Tempat kediaman mereka adalah neraka jahannam. Tiap-tiap kali nyala api Jahannam itu akan padam, Kami tambah lagi bagi mereka nyalanya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 98), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Itulah balasan bagi mereka, karena sesungguhnya mereka kafir kepada ayat-ayat Kami dan (karena mereka) berkata: "Apakah bila kami telah menjadi tulang belulang dan benda-benda yang hancur, apakah kami benar-benar akan dibangkitkan kembali sebagai makhluk baru?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 99), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan apakah mereka tidak memperhatikan bahwasanya Allah yang menciptakan langit dan bumi adalah kuasa (pula) menciptakan yang serupa dengan mereka, dan telah menetapkan waktu yang tertentu bagi mereka yang tidak ada keraguan padanya? Maka orang-orang zalim itu tidak menghendaki kecuali kekafiran.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 100), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Katakanlah: "Kalau seandainya kamu menguasai perbendaharaan-perbendaharaan rahmat Tuhanku, niscaya perbendaharaan itu kamu tahan, karena takut membelanjakannya". Dan adalah manusia itu sangat kikir.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 101), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan sesungguhnya Kami telah memberikan kepada Musa sembilan buah mukjizat yang nyata, maka tanyakanlah kepada Bani Israil, tatkala Musa datang kepada mereka lalu Fir''aun berkata kepadanya: "Sesungguhnya aku sangka kamu, hai Musa, seorang yang kena sihir".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 102), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Musa menjawab: "Sesungguhnya kamu telah mengetahui, bahwa tiada yang menurunkan mukjizat-mukjizat itu kecuali Tuhan Yang memelihara langit dan bumi sebagai bukti-bukti yang nyata; dan sesungguhnya aku mengira kamu, hai Fir''aun, seorang yang akan binasa".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 103), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Kemudian (Fir''aun) hendak mengusir mereka (Musa dan pengikut-pengikutnya) dari bumi (Mesir) itu, maka Kami tenggelamkan dia (Fir''aun) serta orang-orang yang bersama-sama dia seluruhnya,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 104), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'dan Kami berfirman sesudah itu kepada Bani Israil: "Diamlah di negeri ini, maka apabila datang masa berbangkit, niscaya Kami datangkan kamu dalam keadaan bercampur baur (dengan musuhmu)".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 105), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Kami turunkan (Al Quran) itu dengan sebenar-benarnya dan Al Quran itu telah turun dengan (membawa) kebenaran. Dan Kami tidak mengutus kamu, melainkan sebagai pembawa berita gembira dan pemberi peringatan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 106), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Al Quran itu telah Kami turunkan dengan berangsur-angsur agar kamu membacakannya perlahan-lahan kepada manusia dan Kami menurunkannya bagian demi bagian.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 107), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Katakanlah: "Berimanlah kamu kepadanya atau tidak usah beriman (sama saja bagi Allah). Sesungguhnya orang-orang yang diberi pengetahuan sebelumnya apabila Al Quran dibacakan kepada mereka, mereka menyungkur atas muka mereka sambil bersujud,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 108), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'dan mereka berkata: "Maha Suci Tuhan kami, sesungguhnya janji Tuhan kami pasti dipenuhi".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 109), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan mereka menyungkur atas muka mereka sambil menangis dan mereka bertambah khusyu''.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 110), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Katakanlah: "Serulah Allah atau serulah Ar-Rahman. Dengan nama yang mana saja kamu seru, Dia mempunyai al asmaaul husna (nama-nama yang terbaik) dan janganlah kamu mengeraskan suaramu dalam shalatmu dan janganlah pula merendahkannya dan carilah jalan tengah di antara kedua itu".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 111), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan katakanlah: "Segala puji bagi Allah Yang tidak mempunyai anak dan tidak mempunyai sekutu dalam kerajaan-Nya dan Dia bukan pula hina yang memerlukan penolong dan agungkanlah Dia dengan pengagungan yang sebesar-besarnya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Segala puji bagi Allah yang telah menurunkan kepada hamba-Nya Al Kitab (Al-Quran) dan Dia tidak mengadakan kebengkokan di dalamnya;', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'sebagai bimbingan yang lurus, untuk memperingatkan siksaan yang sangat pedih dari sisi Allah dan memberi berita gembira kepada orang-orang yang beriman, yang mengerjakan amal saleh, bahwa mereka akan mendapat pembalasan yang baik,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'mereka kekal di dalamnya untuk selama-lamanya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan untuk memperingatkan kepada orang-orang yang berkata: "Allah mengambil seorang anak".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mereka sekali-kali tidak mempunyai pengetahuan tentang hal itu, begitu pula nenek moyang mereka. Alangkah buruknya kata-kata yang keluar dari mulut mereka; mereka tidak mengatakan (sesuatu) kecuali dusta.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka (apakah) barangkali kamu akan membunuh dirimu karena bersedih hati setelah mereka berpaling, sekiranya mereka tidak beriman kepada keterangan ini (Al-Quran).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya Kami telah menjadikan apa yang di bumi sebagai perhiasan baginya, agar Kami menguji mereka siapakah di antara mereka yang terbaik perbuatannya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan sesungguhnya Kami benar-benar akan menjadikan (pula) apa yang di atasnya menjadi tanah rata lagi tandus.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Atau kamu mengira bahwa orang-orang yang mendiami gua dan (yang mempunyai) raqim itu, mereka termasuk tanda-tanda kekuasaan Kami yang mengherankan?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '(Ingatlah) tatkala para pemuda itu mencari tempat berlindung ke dalam gua, lalu mereka berdoa: "Wahai Tuhan kami, berikanlah rahmat kepada kami dari sisi-Mu dan sempurnakanlah bagi kami petunjuk yang lurus dalam urusan kami (ini)".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka Kami tutup telinga mereka beberapa tahun dalam gua itu,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 12), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Kemudian Kami bangunkan mereka, agar Kami mengetahui manakah di antara kedua golongan itu] yang lebih tepat dalam menghitung berapa lama mereka tinggal (dalam gua itu).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 13), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Kami kisahkan kepadamu (Muhammad) cerita ini dengan benar. Sesungguhnya mereka adalah pemuda-pemuda yang beriman kepada Tuhan mereka, dan Kami tambah pula untuk mereka petunjuk.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 14), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Kami meneguhkan hati mereka diwaktu mereka berdiri, lalu mereka pun berkata, "Tuhan kami adalah Tuhan seluruh langit dan bumi; kami sekali-kali tidak menyeru Tuhan selain Dia, sesungguhnya kami kalau demikian telah mengucapkan perkataan yang amat jauh dari kebenaran".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 15), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Kaum kami ini telah menjadikan selain Dia sebagai tuhan-tuhan (untuk disembah). Mengapa mereka tidak mengemukakan alasan yang terang (tentang kepercayaan mereka)? Siapakah yang lebih zalim daripada orang-orang yang mengada-adakan kebohongan terhadap Allah?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 16), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan apabila kamu meninggalkan mereka dan apa yang mereka sembah selain Allah, maka carilah tempat berlindung ke dalam gua itu, niscaya Tuhanmu akan melimpahkan sebagian rahmat-Nya kepadamu dan menyediakan sesuatu yang berguna bagimu dalam urusan kamu.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 17), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan kamu akan melihat matahari ketika terbit, condong dari gua mereka ke sebelah kanan, dan bila matahari terbenam menjauhi mereka ke sebelah kiri sedang mereka berada dalam tempat yang luas dalam gua itu. Itu adalah sebagian dari tanda-tanda (kebesaran) Allah. Barangsiapa yang diberi petunjuk oleh Allah, maka dialah yang mendapat petunjuk; dan barangsiapa yang disesatkan-Nya, maka kamu tidak akan mendapatkan seorang pemimpinpun yang dapat memberi petunjuk kepadanya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 18), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan kamu mengira mereka itu bangun, padahal mereka tidur; Dan kami balik-balikkan mereka ke kanan dan ke kiri, sedang anjing mereka mengunjurkan kedua lengannya di muka pintu gua. Dan jika kamu menyaksikan mereka tentulah kamu akan berpaling dari mereka dengan melarikan diri dan tentulah (hati) kamu akan dipenuhi oleh ketakutan terhadap mereka.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 19), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan demikianlah Kami bangunkan mereka agar mereka saling bertanya di antara mereka sendiri. Berkatalah salah seorang di antara mereka: Sudah berapa lamakah kamu berada (disini?)". Mereka menjawab: "Kita berada (disini) sehari atau setengah hari". Berkata (yang lain lagi): "Tuhan kamu lebih mengetahui berapa lamanya kamu berada (di sini). Maka suruhlah salah seorang di antara kamu untuk pergi ke kota dengan membawa uang perakmu ini, dan hendaklah dia lihat manakah makanan yang lebih baik, maka hendaklah ia membawa makanan itu untukmu, dan hendaklah ia berlaku lemah-lembut dan janganlah sekali-kali menceritakan halmu kepada seorangpun.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 20), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya jika mereka dapat mengetahui tempatmu, niscaya mereka akan melempar kamu dengan batu, atau memaksamu kembali kepada agama mereka, dan jika demikian niscaya kamu tidak akan beruntung selama lamanya".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 21), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan demikian (pula) Kami mempertemukan (manusia) dengan mereka, agar manusia itu mengetahui, bahwa janji Allah itu benar, dan bahwa kedatangan hari kiamat tidak ada keraguan padanya. Ketika orang-orang itu berselisih tentang urusan mereka, orang-orang itu berkata: "Dirikan sebuah bangunan di atas (gua) mereka, Tuhan mereka lebih mengetahui tentang mereka". Orang-orang yang berkuasa atas urusan mereka berkata: "Sesungguhnya kami akan mendirikan sebuah rumah peribadatan di atasnya".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 22), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Nanti (ada orang yang akan) mengatakan (jumlah mereka) adalah tiga orang yang keempat adalah anjingnya, dan (yang lain) mengatakan: "(jumlah mereka) adalah lima orang yang keenam adalah anjing nya", sebagai terkaan terhadap barang yang gaib; dan (yang lain lagi) mengatakan: "(jumlah mereka) tujuh orang, yang ke delapan adalah anjingnya". Katakanlah: "Tuhanku lebih mengetahui jumlah mereka; tidak ada orang yang mengetahui (bilangan) mereka kecuali sedikit". Karena itu janganlah kamu (Muhammad) bertengkar tentang hal mereka, kecuali pertengkaran lahir saja dan jangan kamu menanyakan tentang mereka (pemuda-pemuda itu) kepada seorangpun di antara mereka.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 23), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan jangan sekali-kali kamu mengatakan tentang sesuatu: "Sesungguhnya aku akan mengerjakan ini besok pagi,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 24), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'kecuali (dengan menyebut): "Insya Allah". Dan ingatlah kepada Tuhanmu jika kamu lupa dan katakanlah: "Mudah-mudahan Tuhanku akan memberiku petunjuk kepada yang lebih dekat kebenarannya dari pada ini".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 25), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan mereka tinggal dalam gua mereka tiga ratus tahun dan ditambah sembilan tahun (lagi).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 26), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Katakanlah: "Allah lebih mengetahui berapa lamanya mereka tinggal (di gua); kepunyaan-Nya-lah semua yang tersembunyi di langit dan di bumi. Alangkah terang penglihatan-Nya dan alangkah tajam pendengaran-Nya; tak ada seorang pelindungpun bagi mereka selain dari pada-Nya; dan Dia tidak mengambil seorangpun menjadi sekutu-Nya dalam menetapkan keputusan".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 27), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan bacakanlah apa yang diwahyukan kepadamu, yaitu kitab Tuhanmu (Al Quran). Tidak ada (seorangpun) yang dapat merubah kalimat-kalimat-Nya. Dan kamu tidak akan dapat menemukan tempat berlindung selain dari pada-Nya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 28), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan bersabarlah kamu bersama-sama dengan orang-orang yang menyeru Tuhannya di pagi dan senja hari dengan mengharap keridhaan-Nya; dan janganlah kedua matamu berpaling dari mereka (karena) mengharapkan perhiasan dunia ini; dan janganlah kamu mengikuti orang yang hatinya telah Kami lalaikan dari mengingati Kami, serta menuruti hawa nafsunya dan adalah keadaannya itu melewati batas.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 29), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan katakanlah: "Kebenaran itu datangnya dari Tuhanmu; maka barangsiapa yang ingin (beriman) hendaklah ia beriman, dan barangsiapa yang ingin (kafir) biarlah ia kafir". Sesungguhnya Kami telah sediakan bagi orang orang zalim itu neraka, yang gejolaknya mengepung mereka. Dan jika mereka meminta minum, niscaya mereka akan diberi minum dengan air seperti besi yang mendidih yang menghanguskan muka. Itulah minuman yang paling buruk dan tempat istirahat yang paling jelek.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 30), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesunggunya mereka yang beriman dan beramal saleh, tentulah Kami tidak akan menyia-nyiakan pahala orang-orang yang mengerjakan amalan(nya) dengan yang baik.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 31), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mereka itulah (orang-orang yang) bagi mereka surga ''Adn, mengalir sungai-sungai di bawahnya; dalam surga itu mereka dihiasi dengan gelang mas dan mereka memakai pakaian hijau dari sutera halus dan sutera tebal, sedang mereka duduk sambil bersandar di atas dipan-dipan yang indah. Itulah pahala yang sebaik-baiknya, dan tempat istirahat yang indah;', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 32), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan berikanlah kepada mereka sebuah perumpamaan dua orang laki-laki, Kami jadikan bagi seorang di antara keduanya (yang kafir) dua buah kebun anggur dan kami kelilingi kedua kebun itu dengan pohon-pohon korma dan di antara kedua kebun itu Kami buatkan ladang.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 33), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Kedua buah kebun itu menghasilkan buahnya, dan kebun itu tiada kurang buahnya sedikitpun, dan Kami alirkan sungai di celah-celah kedua kebun itu,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 34), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'dan dia mempunyai kekayaan besar, maka ia berkata kepada kawannya (yang mukmin) ketika bercakap-cakap dengan dia: "Hartaku lebih banyak dari pada hartamu dan pengikut-pengikutku lebih kuat"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 35), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan dia memasuki kebunnya sedang dia zalim terhadap dirinya sendiri; ia berkata: "Aku kira kebun ini tidak akan binasa selama-lamanya,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 36), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'dan aku tidak mengira hari kiamat itu akan datang, dan jika sekiranya aku kembalikan kepada Tuhanku, pasti aku akan mendapat tempat kembali yang lebih baik dari pada kebun-kebun itu".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 37), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Kawannya (yang mukmin) berkata kepadanya -- sedang dia bercakap-cakap dengannya: "Apakah kamu kafir kepada (Tuhan) yang menciptakan kamu dari tanah, kemudian dari setetes air mani, lalu Dia menjadikan kamu seorang laki-laki yang sempurna?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 38), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Tetapi aku (percaya bahwa): Dialah Allah, Tuhanku, dan aku tidak mempersekutukan seorangpun dengan Tuhanku.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 39), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan mengapa kamu tidak mengatakan waktu kamu memasuki kebunmu "maasyaallaah, laa quwwata illaa billaah (sungguh atas kehendak Allah semua ini terwujud, tiada kekuatan kecuali dengan pertolongan Allah). Sekiranya kamu anggap aku lebih sedikit darimu dalam hal harta dan keturunan,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 40), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'maka mudah-mudahan Tuhanku, akan memberi kepadaku (kebun) yang lebih baik dari pada kebunmu (ini); dan mudah-mudahan Dia mengirimkan ketentuan (petir) dari langit kepada kebunmu; hingga (kebun itu) menjadi tanah yang licin;', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 41), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'atau airnya menjadi surut ke dalam tanah, maka sekali-kali kamu tidak dapat menemukannya lagi".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 42), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan harta kekayaannya dibinasakan; lalu ia membulak-balikkan kedua tangannya (tanda menyesal) terhadap apa yang ia telah belanjakan untuk itu, sedang pohon anggur itu roboh bersama para-paranya dan dia berkata: "Aduhai kiranya dulu aku tidak mempersekutukan seorangpun dengan Tuhanku".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 43), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan tidak ada bagi dia segolonganpun yang akan menolongnya selain Allah; dan sekali-kali ia tidak dapat membela dirinya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 44), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Di sana pertolongan itu hanya dari Allah Yang Hak. Dia adalah sebaik-baik Pemberi pahala dan sebaik-baik Pemberi balasan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 45), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan berilah perumpamaan kepada mereka (manusia), kehidupan dunia sebagai air hujan yang Kami turunkan dari langit, maka menjadi subur karenanya tumbuh-tumbuhan di muka bumi, kemudian tumbuh-tumbuhan itu menjadi kering yang diterbangkan oleh angin. Dan adalah Allah, Maha Kuasa atas segala sesuatu.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 46), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Harta dan anak-anak adalah perhiasan kehidupan dunia tetapi amalan-amalan yang kekal lagi saleh adalah lebih baik pahalanya di sisi Tuhanmu serta lebih baik untuk menjadi harapan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 47), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan (ingatlah) akan hari (yang ketika itu) Kami perjalankan gunung-gunung dan kamu akan dapat melihat bumi itu datar dan Kami kumpulkan seluruh manusia, dan tidak kami tinggalkan seorangpun dari mereka.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 48), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan mereka akan dibawa ke hadapan Tuhanmu dengan berbaris. Sesungguhnya kamu datang kepada Kami, sebagaimana Kami menciptakan kamu pada kali yang pertama; bahkan kamu mengatakan bahwa Kami sekali-kali tidak akan menetapkan bagi kamu waktu (memenuhi) perjanjian.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 49), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan diletakkanlah kitab, lalu kamu akan melihat orang-orang bersalah ketakutan terhadap apa yang (tertulis) di dalamnya, dan mereka berkata: "Aduhai celaka kami, kitab apakah ini yang tidak meninggalkan yang kecil dan tidak (pula) yang besar, melainkan ia mencatat semuanya; dan mereka dapati apa yang telah mereka kerjakan ada (tertulis). Dan Tuhanmu tidak menganiaya seorang juapun".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 50), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan (ingatlah) ketika Kami berfirman kepada para malaikat: "Sujudlah kamu kepada Adam, maka sujudlah mereka kecuali Iblis. Dia adalah dari golongan jin, maka ia mendurhakai perintah Tuhannya. Patutkah kamu mengambil dia dan turanan-turunannya sebagai pemimpin selain daripada-Ku, sedang mereka adalah musuhmu? Amat buruklah iblis itu sebagai pengganti (dari Allah) bagi orang-orang yang zalim.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 51), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Aku tidak menghadirkan mereka (iblis dan anak cucunya) untuk menyaksikan penciptaan langit dan bumi dan tidak (pula) penciptaan diri mereka sendiri; dan tidaklah Aku mengambil orang-orang yang menyesatkan itu sebagai penolong.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 52), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan (ingatlah) akan hari (yang ketika itu) Dia berfirman: "Serulah olehmu sekalian sekutu-sekutu-Ku yang kamu katakan itu". Mereka lalu memanggilnya tetapi sekutu-sekutu itu tidak membalas seruan mereka dan Kami adakan untuk mereka tempat kebinasaan (neraka).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 53), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan orang-orang yang berdosa melihat neraka, maka mereka meyakini, bahwa mereka akan jatuh ke dalamnya dan mereka tidak menemukan tempat berpaling dari padanya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 54), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan sesungguhnya Kami telah mengulang-ulangi bagi manusia dalam Al Quran ini bermacam-macam perumpamaan. Dan manusia adalah makhluk yang paling banyak membantah.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 55), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dam tidak ada sesuatupun yang menghalangi manusia dari beriman, ketika petunjuk telah datang kepada mereka, dan dari memohon ampun kepada Tuhannya, kecuali (keinginan menanti) datangnya hukum (Allah yang telah berlalu pada) umat-umat yang dahulu atau datangnya azab atas mereka dengan nyata.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 56), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan tidaklah Kami mengutus rasul-rasul hanyalah sebagai pembawa berita gembira dan sebagai pemberi peringatan; tetapi orang-orang yang kafir membantah dengan yang batil agar dengan demikian mereka dapat melenyap kan yang hak, dan mereka menganggap ayat-ayat kami dan peringatan-peringatan terhadap mereka sebagai olok-olokan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 57), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan siapakah yang lebih zalim dari pada orang yang telah diperingatkan dengan ayat-ayat Tuhannya lalu dia berpaling dari padanya dan melupakan apa yang telah dikerjakan oleh kedua tangannya? Sesungguhnya Kami telah meletakkan tutupan di atas hati mereka, (sehingga mereka tidak) memahaminya, dan (Kami letakkan pula) sumbatan di telinga mereka; dan kendatipun kamu menyeru mereka kepada petunjuk, niscaya mereka tidak akan mendapat petunjuk selama-lamanya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 58), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Tuhanmulah yang Maha Pengampun, lagi mempunyai rahmat. Jika Dia mengazab mereka karena perbuatan mereka, tentu Dia akan menyegerakan azab bagi mereka. Tetapi bagi mereka ada waktu yang tertentu (untuk mendapat azab) yang mereka sekali-kali tidak akan menemukan tempat berlindung dari padanya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 59), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan (penduduk) negeri telah Kami binasakan ketika mereka berbuat zalim, dan telah Kami tetapkan waktu tertentu bagi kebinasaan mereka.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 60), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan (ingatlah) ketika Musa berkata kepada muridnya: "Aku tidak akan berhenti (berjalan) sebelum sampai ke pertemuan dua buah lautan; atau aku akan berjalan sampai bertahun-tahun".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 61), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka tatkala mereka sampai ke pertemuan dua buah laut itu, mereka lalai akan ikannya, lalu ikan itu melompat mengambil jalannya ke laut itu.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 62), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka tatkala mereka berjalan lebih jauh, berkatalah Musa kepada muridnya: "Bawalah kemari makanan kita; sesungguhnya kita telah merasa letih karena perjalanan kita ini".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 63), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Muridnya menjawab: "Tahukah kamu tatkala kita mencari tempat berlindung di batu tadi, maka sesungguhnya aku lupa (menceritakan tentang) ikan itu dan tidak adalah yang melupakan aku untuk menceritakannya kecuali syaitan dan ikan itu mengambil jalannya ke laut dengan cara yang aneh sekali".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 64), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Musa berkata: "Itulah (tempat) yang kita cari". Lalu keduanya kembali, mengikuti jejak mereka semula.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 65), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Lalu mereka bertemu dengan seorang hamba di antara hamba-hamba Kami, yang telah Kami berikan kepadanya rahmat dari sisi Kami, dan yang telah Kami ajarkan kepadanya ilmu dari sisi Kami.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 66), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Musa berkata kepada Khidhr: "Bolehkah aku mengikutimu supaya kamu mengajarkan kepadaku ilmu yang benar di antara ilmu-ilmu yang telah diajarkan kepadamu?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 67), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dia menjawab: "Sesungguhnya kamu sekali-kali tidak akan sanggup sabar bersama aku.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 68), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan bagaimana kamu dapat sabar atas sesuatu, yang kamu belum mempunyai pengetahuan yang cukup tentang hal itu?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 69), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Musa berkata: "Insya Allah kamu akan mendapati aku sebagai orang yang sabar, dan aku tidak akan menentangmu dalam sesuatu urusanpun".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 70), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dia berkata: "Jika kamu mengikutiku, maka janganlah kamu menanyakan kepadaku tentang sesuatu apapun, sampai aku sendiri menerangkannya kepadamu".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 71), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka berjalanlah keduanya, hingga tatkala keduanya menaiki perahu lalu Khidhr melobanginya. Musa berkata: "Mengapa kamu melobangi perahu itu akibatnya kamu menenggelamkan penumpangnya?" Sesungguhnya kamu telah berbuat sesuatu kesalahan yang besar.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 72), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dia (Khidhr) berkata: "Bukankah aku telah berkata: "Sesungguhnya kamu sekali-kali tidak akan sabar bersama dengan aku".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 73), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Musa berkata: "Janganlah kamu menghukum aku karena kelupaanku dan janganlah kamu membebani aku dengan sesuatu kesulitan dalam urusanku".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 74), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka berjalanlah keduanya; hingga tatkala keduanya berjumpa dengan seorang anak, maka Khidhr membunuhnya. Musa berkata: "Mengapa kamu membunuh jiwa yang bersih, bukan karena dia membunuh orang lain? Sesungguhnya kamu telah melakukan suatu yang mungkar".', NOW(), NOW());
